import React, { useState, useMemo, useEffect } from 'react';
import { User, UserStatus } from '../types';
import { UserDatabase } from '../services/db';
import { 
  Search, 
  UserPlus, 
  Check, 
  X, 
  Users, 
  Loader2, 
  ShieldCheck, 
  Clock,
  MessageCircle,
  UserCheck,
  UserMinus,
  SearchX,
  Compass,
  Star,
  Zap,
  Circle,
  ZapOff,
  SlidersHorizontal,
  ArrowUpDown,
  Calendar,
  Filter,
  ChevronDown,
  Trophy
} from 'lucide-react';
import { useNavigate } from 'react-router-dom';

const StatusMarker: React.FC<{ status: UserStatus; size?: number }> = ({ status, size = 12 }) => {
  const colors = {
    [UserStatus.ONLINE]: 'text-emerald-500 fill-emerald-500 shadow-[0_0_12px_rgba(16,185,129,0.6)]',
    [UserStatus.BUSY]: 'text-rose-500 fill-rose-500 shadow-[0_0_12px_rgba(244,63,94,0.6)]',
    [UserStatus.AWAY]: 'text-amber-400 fill-amber-400 shadow-[0_0_12px_rgba(251,191,36,0.6)]',
    [UserStatus.INVISIBLE]: 'text-zinc-400 fill-zinc-400',
    [UserStatus.OFFLINE]: 'text-zinc-800 fill-zinc-800',
  };
  return <Circle size={size} className={`${colors[status]} transition-all duration-500`} />;
};

interface FriendsViewProps {
  currentUser: User;
}

const FriendsView: React.FC<FriendsViewProps> = ({ currentUser }) => {
  const navigate = useNavigate();
  const [searchTerm, setSearchTerm] = useState('');
  const [searchResults, setSearchResults] = useState<User[]>([]);
  const [isSearching, setIsSearching] = useState(false);
  const [discoverableUsers, setDiscoverableUsers] = useState<User[]>([]);
  const [refreshKey, setRefreshKey] = useState(0);

  // Estados dos Filtros
  const [showFilters, setShowFilters] = useState(false);
  const [minLevel, setMinLevel] = useState(0);
  const [minReputation, setMinReputation] = useState(0);
  const [sortOrder, setSortOrder] = useState<'newest' | 'oldest' | 'reputation'>('newest');

  // Forçar atualização da UI
  const triggerRefresh = () => setRefreshKey(prev => prev + 1);

  useEffect(() => {
    const users = UserDatabase.getDiscoverableUsers(currentUser.id);
    // Filtrar quem já é amigo ou tem pedido pendente
    const filtered = users.filter(u => 
      !currentUser.friends.includes(u.id) && 
      !UserDatabase.hasSentRequest(currentUser.id, u.id) &&
      !currentUser.friendRequests.some(r => r.fromId === u.id)
    );
    setDiscoverableUsers(filtered);
  }, [currentUser.friends, currentUser.id, refreshKey]);

  useEffect(() => {
    // Busca e Filtros Combinados
    const applyFilters = (users: User[]) => {
      let filtered = users.filter(u => u.level >= minLevel && (u.reputation || 0) >= minReputation);

      filtered.sort((a, b) => {
        if (sortOrder === 'newest') {
          return new Date(b.createdAt || 0).getTime() - new Date(a.createdAt || 0).getTime();
        } else if (sortOrder === 'oldest') {
          return new Date(a.createdAt || 0).getTime() - new Date(b.createdAt || 0).getTime();
        } else if (sortOrder === 'reputation') {
          return (b.reputation || 0) - (a.reputation || 0);
        }
        return 0;
      });

      return filtered;
    };

    if (searchTerm.length > 1 || minLevel > 0 || minReputation > 0) {
      setIsSearching(true);
      const timer = setTimeout(() => {
        const baseResults = searchTerm.length > 1 
          ? UserDatabase.searchUsers(searchTerm, currentUser.id)
          : UserDatabase.getDiscoverableUsers(currentUser.id);

        setSearchResults(applyFilters(baseResults));
        setIsSearching(false);
      }, 300);
      return () => clearTimeout(timer);
    } else {
      setSearchResults([]);
      setIsSearching(false);
    }
  }, [searchTerm, minLevel, minReputation, sortOrder, currentUser.id, refreshKey]);

  const sendRequest = (targetId: string) => {
    if (UserDatabase.sendFriendRequest(currentUser.id, targetId)) {
      if (navigator.vibrate) navigator.vibrate(10);
      triggerRefresh();
    }
  };

  const acceptRequest = (fromId: string) => {
    UserDatabase.acceptFriendRequest(currentUser.id, fromId);
    if (navigator.vibrate) navigator.vibrate([20, 50, 20]);
    triggerRefresh();
  };

  const rejectRequest = (fromId: string) => {
    const users = UserDatabase.getUsers();
    const user = users.find(u => u.id === currentUser.id);
    if (user) {
      user.friendRequests = user.friendRequests.filter(r => r.fromId !== fromId);
      UserDatabase.updateUser(user);
      triggerRefresh();
    }
  };

  const handleRemoveFriend = (targetId: string) => {
    if (window.confirm("Deseja remover esta conexão da sua Tribo?")) {
      UserDatabase.removeFriend(currentUser.id, targetId);
      triggerRefresh();
    }
  };

  const incomingRequests = useMemo(() => {
    return currentUser.friendRequests
      .map(req => ({ ...req, sender: UserDatabase.findById(req.fromId) }))
      .filter(r => r.sender);
  }, [currentUser.friendRequests, refreshKey]);

  const friendsList = useMemo(() => {
    return currentUser.friends
      .map(id => UserDatabase.findById(id))
      .filter(f => f) as User[];
  }, [currentUser.friends, refreshKey]);

  const resetFilters = () => {
    setMinLevel(0);
    setMinReputation(0);
    setSortOrder('newest');
    setSearchTerm('');
  };

  return (
    <div className="max-w-6xl mx-auto space-y-16 animate-in fade-in duration-700 pb-24 px-4">

      {/* Header Dinâmico */}
      <section className="space-y-10">
        <div className="flex flex-col md:flex-row md:items-end justify-between gap-6 px-4">
          <div>
            <div className="flex items-center gap-3 mb-2">
              <div className="w-12 h-1 bg-emerald-500 rounded-full"></div>
              <span className="text-[10px] font-black uppercase tracking-[0.5em] text-emerald-500">Conexões Reais</span>
            </div>
            <h2 className="text-6xl font-black tracking-tighter text-[var(--msn-text)]">MINHA <span className="text-emerald-500 italic">TRIBO</span></h2>
            <p className="text-zinc-500 font-bold text-xl mt-3">Sua rede privada, segura e sem algoritmos.</p>
          </div>

          <div className="flex gap-4">
            <div className="flex items-center gap-4 bg-[var(--msn-sidebar)] backdrop-blur-md border border-[var(--msn-border)] px-8 py-5 rounded-[2.5rem] shadow-xl">
              <div className="w-12 h-12 bg-emerald-500/10 rounded-2xl flex items-center justify-center text-emerald-500 border border-emerald-500/20">
                <Users size={24} />
              </div>
              <div>
                <span className="text-3xl font-black text-[var(--msn-text)] leading-none">{friendsList.length}</span>
                <p className="text-[9px] font-black text-zinc-600 uppercase tracking-widest mt-1">Aliados</p>
              </div>
            </div>
          </div>
        </div>

        {/* Busca Inteligente com Filtros */}
        <div className="space-y-6 max-w-4xl mx-auto">
          <div className="relative group">
            <div className="absolute inset-0 bg-emerald-500/5 blur-[80px] opacity-0 group-focus-within:opacity-100 transition-opacity rounded-full"></div>
            <Search className="absolute left-8 top-1/2 -translate-y-1/2 text-zinc-700 group-focus-within:text-emerald-500 transition-all duration-300" size={32} />
            <input 
              type="text"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              placeholder="Buscar novo membro por @username..."
              className="w-full bg-[var(--msn-sidebar)] border border-[var(--msn-border)] rounded-[3.5rem] py-10 pl-24 pr-16 text-2xl font-medium focus:outline-none focus:border-emerald-500/40 transition-all shadow-2xl placeholder:text-zinc-800 text-[var(--msn-text)] relative z-10"
            />

            <div className="absolute right-6 top-1/2 -translate-y-1/2 z-20 flex items-center gap-3">
              {isSearching && <Loader2 className="animate-spin text-emerald-500" size={24} />}
              <button 
                onClick={() => setShowFilters(!showFilters)}
                className={`p-4 rounded-2xl transition-all border ${showFilters ? 'bg-emerald-500 text-black border-emerald-500 shadow-lg' : 'bg-black/20 text-zinc-500 border-white/5 hover:text-white'}`}
                title="Filtros Avançados"
              >
                <SlidersHorizontal size={24} />
              </button>
            </div>
          </div>

          {/* Painel de Filtros */}
          {showFilters && (
            <div className="bg-[var(--msn-sidebar)] border border-[var(--msn-border)] rounded-[3rem] p-10 animate-in slide-in-from-top-4 duration-300 shadow-2xl space-y-10 relative z-20">
              <div className="grid grid-cols-1 md:grid-cols-3 gap-10">

                {/* Filtro de Nível */}
                <div className="space-y-4">
                  <div className="flex items-center justify-between px-2">
                    <label className="text-[10px] font-black uppercase text-zinc-500 tracking-widest flex items-center gap-2">
                      <Zap size={14} className="text-emerald-500" /> Nível Mínimo
                    </label>
                    <span className="text-xl font-black text-emerald-500">{minLevel}</span>
                  </div>
                  <input 
                    type="range" min="0" max="99" value={minLevel} 
                    onChange={(e) => setMinLevel(parseInt(e.target.value))}
                    className="w-full accent-emerald-500 h-2 bg-black/40 rounded-full appearance-none cursor-pointer"
                  />
                </div>

                {/* Filtro de Reputação */}
                <div className="space-y-4">
                  <div className="flex items-center justify-between px-2">
                    <label className="text-[10px] font-black uppercase text-zinc-500 tracking-widest flex items-center gap-2">
                      <Trophy size={14} className="text-amber-500" /> Reputação Mínima
                    </label>
                    <span className="text-xl font-black text-amber-500">{minReputation}</span>
                  </div>
                  <input 
                    type="range" min="0" max="5000" step="50" value={minReputation} 
                    onChange={(e) => setMinReputation(parseInt(e.target.value))}
                    className="w-full accent-amber-500 h-2 bg-black/40 rounded-full appearance-none cursor-pointer"
                  />
                </div>

                {/* Ordenação */}
                <div className="space-y-4">
                  <label className="text-[10px] font-black uppercase text-zinc-500 tracking-widest flex items-center gap-2 px-2">
                    <ArrowUpDown size={14} className="text-blue-500" /> Ordenar Por
                  </label>
                  <div className="flex bg-black/40 p-1 rounded-2xl border border-[var(--msn-border)]">
                    <button 
                      onClick={() => setSortOrder('newest')}
                      className={`flex-1 py-3 rounded-xl text-[9px] font-black uppercase tracking-tighter transition-all ${sortOrder === 'newest' ? 'bg-zinc-800 text-white shadow-lg' : 'text-zinc-600'}`}
                    >
                      Recentes
                    </button>
                    <button 
                      onClick={() => setSortOrder('reputation')}
                      className={`flex-1 py-3 rounded-xl text-[9px] font-black uppercase tracking-tighter transition-all ${sortOrder === 'reputation' ? 'bg-zinc-800 text-white shadow-lg' : 'text-zinc-600'}`}
                    >
                      Reputação
                    </button>
                    <button 
                      onClick={() => setSortOrder('oldest')}
                      className={`flex-1 py-3 rounded-xl text-[9px] font-black uppercase tracking-tighter transition-all ${sortOrder === 'oldest' ? 'bg-zinc-800 text-white shadow-lg' : 'text-zinc-600'}`}
                    >
                      Antigos
                    </button>
                  </div>
                </div>
              </div>

              <div className="flex justify-between items-center pt-6 border-t border-white/5">
                <p className="text-[9px] font-black text-zinc-700 uppercase tracking-widest">Ajuste os parâmetros para filtrar a Tribo</p>
                <button 
                  onClick={resetFilters}
                  className="text-rose-500 font-black uppercase text-[10px] tracking-widest flex items-center gap-2 hover:opacity-70 transition-opacity"
                >
                  <ZapOff size={14} /> Resetar Filtros
                </button>
              </div>
            </div>
          )}
        </div>

        {(searchTerm.length > 1 || minLevel > 0 || minReputation > 0) && (
          <div className="space-y-6 animate-in slide-in-from-top-6 duration-500">
            <div className="flex items-center justify-between px-10">
              <h4 className="text-[11px] font-black uppercase tracking-[0.4em] text-zinc-600">
                Resultados Refinados ({searchResults.length})
              </h4>
            </div>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              {searchResults.length > 0 ? (
                searchResults.map(user => (
                  <MemberCard key={user.id} user={user} currentUser={currentUser} onSendRequest={sendRequest} />
                ))
              ) : !isSearching && (
                <div className="col-span-full py-20 text-center bg-zinc-900/10 border-2 border-dashed border-[var(--msn-border)] rounded-[4rem] flex flex-col items-center gap-6">
                  <SearchX size={48} className="text-zinc-800" />
                  <div>
                    <p className="text-zinc-500 font-black uppercase text-xs tracking-widest">Nenhum membro atende aos filtros</p>
                    <button onClick={resetFilters} className="mt-4 text-emerald-500 font-black text-[10px] uppercase tracking-widest underline decoration-2 underline-offset-4">Limpar tudo</button>
                  </div>
                </div>
              )}
            </div>
          </div>
        )}
      </section>

      {/* Pedidos Pendentes - Atenção Redobrada */}
      {incomingRequests.length > 0 && (
        <section className="space-y-8 animate-in slide-in-from-right-10 duration-700">
          <div className="flex items-center gap-4 px-6">
            <div className="p-4 bg-amber-500/10 rounded-2xl border border-amber-500/20 text-amber-500 animate-pulse">
              <Clock size={24} />
            </div>
            <div>
              <h3 className="text-2xl font-black text-[var(--msn-text)] tracking-tight">Novos Convites</h3>
              <p className="text-[10px] font-black text-zinc-500 uppercase tracking-[0.2em]">Pessoas querendo entrar na sua Tribo</p>
            </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            {incomingRequests.map((req, idx) => (
              <div key={idx} className="bg-[var(--msn-sidebar)] border border-[var(--msn-border)] rounded-[3rem] p-8 flex items-center justify-between group hover:border-amber-500/30 transition-all shadow-xl">
                <div className="flex items-center gap-6">
                  <div className="relative">
                    <img src={req.sender?.avatar} className="w-16 h-16 rounded-[1.8rem] object-cover border-2 border-zinc-800" />
                    <div className="absolute -bottom-1 -right-1 p-1 bg-white dark:bg-zinc-950 rounded-full border border-[var(--msn-border)]">
                      <StatusMarker status={req.sender?.status || UserStatus.OFFLINE} size={10} />
                    </div>
                  </div>
                  <div>
                    <p className="font-black text-xl text-[var(--msn-text)] tracking-tight">{req.sender?.name}</p>
                    <p className="text-[10px] text-zinc-500 font-black uppercase tracking-widest mt-0.5">@{req.sender?.username}</p>
                  </div>
                </div>
                <div className="flex gap-3">
                  <button onClick={() => rejectRequest(req.fromId)} className="w-14 h-14 bg-black/5 text-zinc-500 hover:text-rose-500 hover:bg-rose-500/10 rounded-2xl transition-all border border-[var(--msn-border)] flex items-center justify-center"><X size={24} /></button>
                  <button onClick={() => acceptRequest(req.fromId)} className="w-14 h-14 bg-emerald-500 text-black rounded-2xl hover:bg-emerald-400 transition-all flex items-center justify-center shadow-lg"><Check size={28} strokeWidth={3} /></button>
                </div>
              </div>
            ))}
          </div>
        </section>
      )}

      {/* Dashboard da Tribo (Amigos Pessoais) */}
      <section className="space-y-10">
        <div className="flex items-center justify-between px-6">
          <div className="flex items-center gap-4">
            <div className="p-4 bg-emerald-500/10 rounded-2xl border border-emerald-500/20 text-emerald-500">
              <UserCheck size={24} />
            </div>
            <div>
              <h3 className="text-3xl font-black text-[var(--msn-text)] tracking-tight">Conexões Ativas</h3>
              <p className="text-[10px] font-black text-zinc-500 uppercase tracking-widest">Sincronizado com seu Papo</p>
            </div>
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-2 gap-8">
          {friendsList.length > 0 ? (
            friendsList.map(friend => (
              <div key={friend.id} className="bg-[var(--msn-sidebar)] border border-[var(--msn-border)] rounded-[3.5rem] p-10 flex items-center justify-between group hover:border-emerald-500/40 hover:-translate-y-2 transition-all duration-500 shadow-2xl relative overflow-hidden">
                <div className="absolute inset-0 bg-gradient-to-br from-emerald-500/[0.02] to-transparent opacity-0 group-hover:opacity-100 transition-opacity"></div>

                <div className="flex items-center gap-8 relative z-10">
                  <div className="relative">
                    <div className={`w-24 h-24 rounded-[2.2rem] bg-zinc-800 overflow-hidden border-4 border-[var(--msn-bg)] shadow-2xl group-hover:scale-105 transition-transform duration-500 ${friend.animatedAvatar ? 'avatar-animated' : ''}`}>
                      <img src={friend.avatar} alt={friend.name} className="w-full h-full object-cover" />
                    </div>
                    <div className="absolute -bottom-1 -right-1 p-1.5 bg-white dark:bg-zinc-950 rounded-full border-2 border-[var(--msn-border)] shadow-xl">
                      <StatusMarker status={friend.status} size={14} />
                    </div>
                  </div>
                  <div className="min-w-0">
                    <div className="flex items-center gap-2">
                      <p className="font-black text-2xl text-[var(--msn-text)] tracking-tighter truncate max-w-[150px]">{friend.name}</p>
                      {friend.verified && <ShieldCheck size={18} className="text-emerald-500" />}
                    </div>
                    <p className="text-[10px] text-zinc-500 font-black uppercase tracking-[0.3em] mt-1.5">@{friend.username}</p>
                    <div className="flex items-center gap-2 mt-3">
                      <span className={`text-[8px] font-black uppercase px-2 py-0.5 rounded border ${
                        friend.status === UserStatus.ONLINE ? 'bg-emerald-500/10 text-emerald-500 border-emerald-500/20' :
                        friend.status === UserStatus.BUSY ? 'bg-rose-500/10 text-rose-500 border-rose-500/20' :
                        'bg-zinc-500/10 text-zinc-500 border-zinc-500/20'
                      }`}>
                        {friend.status.toLowerCase()}
                      </span>
                      {friend.currentMusic && (
                         <div className="flex items-center gap-1 text-blue-500 animate-pulse">
                           <Zap size={8} fill="currentColor" />
                           <span className="text-[7px] font-black uppercase tracking-tighter truncate max-w-[80px]">{friend.currentMusic}</span>
                         </div>
                      )}
                    </div>
                  </div>
                </div>

                <div className="flex gap-3 relative z-10">
                  <button 
                    onClick={() => navigate('/chat')}
                    className="w-16 h-16 bg-emerald-500 text-black rounded-[1.8rem] hover:bg-emerald-400 transition-all flex items-center justify-center shadow-xl shadow-emerald-500/20 active:scale-90"
                    title="Iniciar Papo"
                  >
                    <MessageCircle size={28} fill="currentColor" />
                  </button>
                  <button 
                    onClick={() => handleRemoveFriend(friend.id)}
                    className="w-16 h-16 bg-black/5 text-zinc-500 hover:text-rose-500 hover:bg-rose-500/10 rounded-[1.8rem] border border-[var(--msn-border)] transition-all flex items-center justify-center active:scale-90"
                    title="Remover Conexão"
                  >
                    <UserMinus size={24} />
                  </button>
                </div>
              </div>
            ))
          ) : (
            <div className="col-span-full bg-black/5 border-2 border-dashed border-[var(--msn-border)] rounded-[5rem] p-24 text-center flex flex-col items-center gap-6 group">
              <Users size={64} className="text-zinc-800 group-hover:text-emerald-500 transition-colors" />
              <div>
                <p className="text-2xl font-black text-zinc-600 tracking-tight">Sua Tribo está vazia</p>
                <p className="text-zinc-700 text-sm font-bold mt-2">Busque por amigos ou explore as sugestões abaixo para expandir sua rede.</p>
              </div>
            </div>
          )}
        </div>
      </section>

      {/* Descoberta de Novos Aliados */}
      {!searchTerm && minLevel === 0 && minReputation === 0 && discoverableUsers.length > 0 && (
        <section className="space-y-10 pt-16 border-t border-[var(--msn-border)]">
          <div className="flex items-center gap-4 px-6">
            <div className="p-4 bg-blue-500/10 rounded-2xl border border-blue-500/20 text-blue-400">
               <Compass size={24} />
            </div>
            <div>
              <h3 className="text-3xl font-black text-[var(--msn-text)] tracking-tight">Sugeridos para Você</h3>
              <p className="text-[10px] font-black text-zinc-500 uppercase tracking-widest">Pessoas com reputação positiva na TRIBO</p>
            </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
            {discoverableUsers.slice(0, 6).map(user => (
              <div key={user.id} className="bg-[var(--msn-sidebar)] border border-[var(--msn-border)] p-10 rounded-[4rem] group hover:border-emerald-500/30 transition-all duration-700 shadow-xl flex flex-col items-center text-center relative overflow-hidden">
                <div className="absolute top-0 right-0 p-6 opacity-10 group-hover:opacity-30 transition-opacity">
                   <Compass size={80} className="text-emerald-500 rotate-12" />
                </div>

                <div className="relative mb-8">
                  <div className={`w-32 h-32 rounded-[3rem] bg-zinc-800 overflow-hidden border-[6px] border-[var(--msn-bg)] shadow-2xl group-hover:border-emerald-500/20 transition-all duration-700 ${user.animatedAvatar ? 'avatar-animated' : ''}`}>
                    <img src={user.avatar} className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-1000" />
                  </div>
                  <div className="absolute -bottom-2 -right-2 bg-emerald-500 text-black px-4 py-1.5 rounded-full text-[10px] font-black uppercase tracking-tighter border-4 border-[var(--msn-bg)]">
                    Nv. {user.level}
                  </div>
                </div>

                <div className="flex items-center gap-2 mb-1">
                  <p className="text-2xl font-black text-[var(--msn-text)] group-hover:text-emerald-400 transition-colors tracking-tighter">{user.name}</p>
                  {user.verified && <ShieldCheck size={18} className="text-emerald-500" />}
                </div>
                <p className="text-[10px] text-zinc-600 font-black uppercase tracking-[0.2em] mb-10">@{user.username}</p>

                <div className="grid grid-cols-2 gap-4 w-full mb-10">
                  <div className="p-4 bg-black/10 rounded-[1.8rem] border border-[var(--msn-border)] flex flex-col items-center">
                    <span className="text-[8px] font-black text-zinc-600 uppercase tracking-tighter mb-1">Reputação</span>
                    <span className="text-sm font-black text-emerald-500 flex items-center gap-1"><Star size={12} fill="currentColor" /> {user.reputation}</span>
                  </div>
                  <div className="p-4 bg-black/10 rounded-[1.8rem] border border-[var(--msn-border)] flex flex-col items-center">
                    <span className="text-[8px] font-black text-zinc-600 uppercase tracking-tighter mb-1">Status</span>
                    <StatusMarker status={user.status} size={10} />
                  </div>
                </div>

                <button 
                  onClick={() => sendRequest(user.id)}
                  className="w-full bg-emerald-500 hover:bg-emerald-400 text-black font-black py-6 rounded-[2.5rem] transition-all shadow-xl shadow-emerald-500/10 text-xs uppercase tracking-[0.3em] flex items-center justify-center gap-3 active:scale-95"
                >
                  <UserPlus size={20} /> Conectar
                </button>
              </div>
            ))}
          </div>
        </section>
      )}
    </div>
  );
};

const MemberCard: React.FC<{ user: User; currentUser: User; onSendRequest: (id: string) => void }> = ({ user, currentUser, onSendRequest }) => {
  const isFriend = currentUser.friends.includes(user.id);
  const hasSentReq = UserDatabase.hasSentRequest(currentUser.id, user.id);

  return (
    <div className="bg-[var(--msn-sidebar)] border border-[var(--msn-border)] rounded-[3rem] p-8 flex items-center justify-between group shadow-xl transition-all duration-500 hover:border-emerald-500/30 relative overflow-hidden">
      <div className="flex items-center gap-6 relative z-10">
        <div className="w-20 h-20 rounded-[1.8rem] bg-zinc-800 overflow-hidden border-2 border-zinc-800 group-hover:border-emerald-500/30 transition-all duration-500">
          <img src={user.avatar} className="w-full h-full object-cover" />
        </div>
        <div>
          <div className="flex items-center gap-2">
            <p className="font-black text-2xl text-[var(--msn-text)] group-hover:text-emerald-400 transition-colors tracking-tighter">{user.name}</p>
            {user.verified && <ShieldCheck size={18} className="text-emerald-500" />}
          </div>
          <p className="text-[10px] text-zinc-500 font-black uppercase tracking-widest mt-1">@{user.username}</p>
          <div className="flex items-center gap-3 mt-1.5">
            <span className="text-[8px] font-black text-emerald-500 uppercase flex items-center gap-1">
              <Zap size={8} fill="currentColor" /> Nv. {user.level}
            </span>
            <span className="text-[8px] font-black text-amber-500 uppercase flex items-center gap-1">
              <Star size={8} fill="currentColor" /> Rep. {user.reputation}
            </span>
            <span className="text-[8px] font-black text-zinc-600 uppercase flex items-center gap-1">
              <Calendar size={8} /> {user.createdAt ? new Date(user.createdAt).toLocaleDateString('pt-BR', { year: '2-digit', month: '2-digit' }) : '--/--'}
            </span>
          </div>
        </div>
      </div>

      <div className="relative z-10">
        {isFriend ? (
          <div className="bg-emerald-500/10 text-emerald-400 px-6 py-3 rounded-2xl border border-emerald-500/20 text-[9px] font-black uppercase tracking-widest flex items-center gap-2">
            <UserCheck size={16} /> Aliado
          </div>
        ) : hasSentReq ? (
          <div className="bg-amber-400/5 text-amber-400 px-6 py-3 rounded-2xl border border-amber-400/20 text-[9px] font-black uppercase tracking-widest flex items-center gap-2">
            <Clock size={16} /> Enviado
          </div>
        ) : (
          <button 
            onClick={() => onSendRequest(user.id)} 
            className="bg-emerald-500 hover:bg-emerald-400 text-black p-5 rounded-2xl shadow-xl shadow-emerald-500/20 transition-all active:scale-95"
          >
            <UserPlus size={26} />
          </button>
        )}
      </div>
    </div>
  );
};

export default FriendsView;

import React, { useState, useEffect, useMemo } from 'react';
import { 
  ChevronLeft, Plus, X, Tractor, Coins, Lock, TrendingUp, TrendingDown,
  Sprout, Factory, Package, Beef, Milk, Trophy, Loader2, Zap,
  ShoppingBag, Users, ShieldCheck, BarChart3, Star, ArrowUpRight,
  Droplets, Waves, Leaf, Box, Bug, ThermometerSun, AlertTriangle, Skull,
  ArrowRight, Flame, Wallet, History
} from 'lucide-react';
import { User, AgroCrop, AgroGameState, AgroPlot, PlotStatus, AgroAnimal, AgroPen, MarketPrice, AgroMachine, UserStatus } from '../types';
import { UserDatabase } from '../services/db';

const CROPS: AgroCrop[] = [
  { id: 'milho', name: 'Milho Híbrido', emoji: '🌽', growthTime: 15, cost: 50, baseYield: 120, xp: 30, minLevel: 1, riskFactor: 0.02 },
  { id: 'soja', name: 'Soja Exportação', emoji: '🌱', growthTime: 45, cost: 300, baseYield: 600, xp: 150, minLevel: 2, riskFactor: 0.05 },
  { id: 'pimenta', name: 'Pimenta Malagueta', emoji: '🌶️', growthTime: 30, cost: 150, baseYield: 400, xp: 100, minLevel: 3, riskFactor: 0.03 },
  { id: 'cana', name: 'Cana Caiana', emoji: '🎋', growthTime: 90, cost: 1200, baseYield: 3000, xp: 900, minLevel: 4, riskFactor: 0.08 },
  { id: 'erva-mate', name: 'Erva-Mate Premium', emoji: '🧉', growthTime: 60, cost: 800, baseYield: 2000, xp: 600, minLevel: 5, riskFactor: 0.04 },
  { id: 'laranja', name: 'Laranja Citros', emoji: '🍊', growthTime: 120, cost: 2500, baseYield: 8000, xp: 2000, minLevel: 7, riskFactor: 0.06 },
  { id: 'cafe', name: 'Café Especial', emoji: '☕', growthTime: 180, cost: 5000, baseYield: 15000, xp: 4000, minLevel: 10, riskFactor: 0.12 },
];

const ANIMALS: AgroAnimal[] = [
  { id: 'galinha', name: 'Galinha Caipira', emoji: '🐔', productionTime: 30, cost: 800, baseYield: 20, xp: 150, products: ['ovos'], minLevel: 2 },
  { id: 'porco', name: 'Suinocultura', emoji: '🐷', productionTime: 120, cost: 4500, baseYield: 80, xp: 900, products: ['carne'], minLevel: 5 },
  { id: 'vaca', name: 'Nelore Elite', emoji: '🐄', productionTime: 400, cost: 15000, baseYield: 250, xp: 3500, products: ['leite', 'carne'], minLevel: 10 },
];

const INDUSTRY_RECIPES = [
  { id: 'etanol', name: 'Etanol Bio', input: 'cana', inputQty: 1000, outputQty: 50, time: 20, xp: 500, emoji: '⛽' },
  { id: 'queijo', name: 'Queijo Artesanal', input: 'leite', inputQty: 50, outputQty: 5, time: 15, xp: 300, emoji: '🧀' },
  { id: 'oleo', name: 'Óleo de Soja', input: 'soja', inputQty: 200, outputQty: 20, time: 25, xp: 400, emoji: '🛢️' },
  { id: 'suco', name: 'Suco de Laranja', input: 'laranja', inputQty: 500, outputQty: 100, time: 10, xp: 200, emoji: '🧃' },
];

const AgroBrazil: React.FC<{ currentUser: User }> = ({ currentUser }) => {
  const [isLobby, setIsLobby] = useState(true);
  const [activeTab, setActiveTab] = useState<'fazenda' | 'pecuaria' | 'industria' | 'cooperativa' | 'ranking'>('fazenda');
  const [selectedPlot, setSelectedPlot] = useState<number | null>(null);
  const [selectedPen, setSelectedPen] = useState<number | null>(null);
  const [isProcessing, setIsProcessing] = useState<string | null>(null);
  const [processingProgress, setProcessingProgress] = useState(0);

  const [gameState, setGameState] = useState<AgroGameState>(() => 
    UserDatabase.getAgroState(currentUser.id)
  );

  useEffect(() => {
    const interval = setInterval(() => {
      const now = Date.now();
      setGameState(prev => {
        const nextPlots = prev.plots.map(p => {
          if (!p.cropId || !p.plantedAt) return p;
          const crop = CROPS.find(c => c.id === p.cropId);
          if (!crop) return p;

          const elapsed = (now - p.plantedAt) / 1000;
          const progress = elapsed / crop.growthTime;

          if (p.status === 'planted' || p.status === 'growing') {
            if (Math.random() < crop.riskFactor / 100) {
              const lossType = Math.random() > 0.4 ? 'partial_loss' : 'total_loss';
              return { ...p, status: lossType as PlotStatus, quality: lossType === 'partial_loss' ? 0.4 : 0 };
            }
            if (progress >= 1.0) return { ...p, status: 'ready' as PlotStatus };
            if (p.status === 'planted' && progress > 0.1) return { ...p, status: 'growing' as PlotStatus };
          }
          if (p.status === 'ready' && elapsed > crop.growthTime * 4) return { ...p, status: 'total_loss' as PlotStatus, quality: 0 };
          return p;
        });

        const nextPens = prev.pens.map(pen => {
          if (pen.status === 'active' && pen.startedAt && pen.animalId) {
            const animal = ANIMALS.find(a => a.id === pen.animalId);
            if (animal && (now - pen.startedAt) / 1000 >= animal.productionTime) {
              return { ...pen, status: 'ready' as const };
            }
          }
          return pen;
        });

        const newState = { ...prev, plots: nextPlots, pens: nextPens, lastCheck: now };
        UserDatabase.saveAgroState(currentUser.id, newState);
        return newState;
      });
    }, 1000);
    return () => clearInterval(interval);
  }, [currentUser.id]);

  const syncReputation = (xp: number) => {
    const freshUser = UserDatabase.findById(currentUser.id);
    if (freshUser) {
      freshUser.reputation += Math.floor(xp / 10);
      freshUser.xp += xp;
      if (freshUser.xp >= freshUser.level * 2000) {
        freshUser.level++;
        freshUser.xp = 0;
      }
      UserDatabase.updateUser(freshUser);
    }
  };

  const handlePlant = (plotId: number, cropId: string) => {
    const crop = CROPS.find(c => c.id === cropId);
    if (!crop || gameState.credits < crop.cost) return;
    setGameState(prev => ({
      ...prev,
      credits: prev.credits - crop.cost,
      plots: prev.plots.map(p => p.id === plotId ? { ...p, cropId, plantedAt: Date.now(), status: 'planted', quality: 1.0, riskTriggered: false } : p)
    }));
    setSelectedPlot(null);
    if (navigator.vibrate) navigator.vibrate(20);
  };

  const handleHarvest = (plotId: number) => {
    const plot = gameState.plots.find(p => p.id === plotId);
    if (!plot || !plot.cropId) return;
    if (plot.status !== 'ready' && plot.status !== 'partial_loss' && plot.status !== 'total_loss') return;

    const crop = CROPS.find(c => c.id === plot.cropId);
    if (!crop) return;

    const yieldAmount = Math.floor(crop.baseYield * plot.quality);
    const xpReward = Math.floor(crop.xp * plot.quality);

    setGameState(prev => {
      const inv = { ...prev.inventory };
      if (yieldAmount > 0) inv[crop.id] = (inv[crop.id] || 0) + yieldAmount;
      syncReputation(xpReward);
      return {
        ...prev,
        xp: prev.xp + xpReward,
        inventory: inv,
        plots: prev.plots.map(p => p.id === plotId ? { ...p, cropId: null, plantedAt: null, status: 'empty', quality: 1.0 } : p)
      };
    });
    if (navigator.vibrate) navigator.vibrate([10, 30]);
  };

  const handleProcessIndustry = async (recipeId: string) => {
    const recipe = INDUSTRY_RECIPES.find(r => r.id === recipeId);
    if (!recipe || (gameState.inventory[recipe.input] || 0) < recipe.inputQty || isProcessing) return;

    setIsProcessing(recipeId);
    setProcessingProgress(0);

    const duration = recipe.time * 1000;
    const start = Date.now();

    const timer = setInterval(() => {
      const elapsed = Date.now() - start;
      const progress = (elapsed / duration) * 100;
      if (progress >= 100) {
        clearInterval(timer);
        setGameState(prev => {
          const inv = { ...prev.inventory };
          inv[recipe.input] -= recipe.inputQty;
          inv[recipe.id] = (inv[recipe.id] || 0) + recipe.outputQty;
          syncReputation(recipe.xp);
          return { ...prev, inventory: inv, xp: prev.xp + recipe.xp };
        });
        setIsProcessing(null);
        setProcessingProgress(0);
        if (navigator.vibrate) navigator.vibrate([50, 20, 50]);
      } else {
        setProcessingProgress(progress);
      }
    }, 100);
  };

  const handleSellItem = (itemId: string, qty: number) => {
    const priceData = gameState.marketPrices.find(p => p.cropId === itemId);
    const currentQty = gameState.inventory[itemId] || 0;
    if (!priceData || currentQty < qty) return;

    const totalEarning = priceData.price * qty;
    setGameState(prev => {
      const inv = { ...prev.inventory };
      inv[itemId] -= qty;
      return { ...prev, credits: prev.credits + totalEarning, inventory: inv };
    });
    if (navigator.vibrate) navigator.vibrate(10);
  };

  const handleBuyAnimal = (penId: number, animalId: string) => {
    const animal = ANIMALS.find(a => a.id === animalId);
    if (!animal || gameState.credits < animal.cost) return;
    setGameState(prev => ({
      ...prev,
      credits: prev.credits - animal.cost,
      pens: prev.pens.map(p => p.id === penId ? { ...p, animalId, startedAt: Date.now(), status: 'active', hunger: 0, health: 1.0 } : p)
    }));
    setSelectedPen(null);
  };

  return (
    <div className="h-[calc(100vh-180px)] bg-[#010502] rounded-[4rem] border border-white/5 flex flex-col overflow-hidden shadow-2xl relative">

      {/* Background Decor */}
      <div className="absolute top-0 left-0 w-full h-full pointer-events-none opacity-5">
        <div className="absolute top-[-10%] left-[-10%] w-[60%] h-[60%] bg-emerald-500 blur-[150px] rounded-full"></div>
        <div className="absolute bottom-[-10%] right-[-10%] w-[60%] h-[60%] bg-amber-500 blur-[150px] rounded-full"></div>
      </div>

      <header className="p-8 border-b border-white/5 bg-black/40 flex items-center justify-between relative z-10">
        <div className="flex items-center gap-6">
          <button onClick={() => isLobby ? null : setIsLobby(true)} className="p-4 bg-zinc-900 text-zinc-500 rounded-2xl hover:text-white transition-all"><ChevronLeft size={24}/></button>
          <div>
            <h2 className="text-2xl font-black text-white italic tracking-tighter uppercase">ESTÂNCIA <span className="text-emerald-500">TRIBO</span></h2>
            <div className="flex items-center gap-4 mt-1">
              <div className="flex items-center gap-2">
                <Wallet size={16} className="text-emerald-500"/>
                <span className="text-xl font-black text-emerald-500 tracking-tighter">R$ {gameState.credits.toLocaleString('pt-BR')}</span>
              </div>
              <div className="w-1 h-1 rounded-full bg-zinc-800"></div>
              <span className="text-[10px] font-black text-zinc-600 uppercase tracking-widest">NÍVEL {gameState.level} • XP {gameState.xp}</span>
            </div>
          </div>
        </div>

        {isLobby ? null : (
          <div className="hidden md:flex gap-3">
             <div className="flex flex-col items-end">
               <span className="text-[8px] font-black text-zinc-600 uppercase">Eficiência Geral</span>
               <div className="w-32 h-1.5 bg-zinc-900 rounded-full mt-1 overflow-hidden">
                 <div className="h-full bg-emerald-500" style={{ width: '75%' }}></div>
               </div>
             </div>
          </div>
        )}
      </header>

      {isLobby ? (
        <div className="flex-1 flex flex-col items-center justify-center p-10 text-center space-y-12 relative z-10">
          <div className="relative">
            <div className="w-48 h-48 bg-emerald-500/10 rounded-[4rem] border-2 border-emerald-500/30 flex items-center justify-center animate-pulse">
               <Tractor size={100} className="text-emerald-500" />
            </div>
            <div className="absolute -bottom-4 -right-4 bg-amber-500 text-black p-4 rounded-3xl shadow-2xl rotate-12">
               <Star size={24} fill="currentColor" />
            </div>
          </div>
          <div className="space-y-4">
             <h1 className="text-7xl font-black italic text-white tracking-tighter leading-none">AGRO<br/><span className="text-emerald-500">BRAZIL</span></h1>
             <p className="text-zinc-500 font-bold uppercase tracking-[0.3em] text-[11px]">Gerencie sua soberania alimentar e industrial</p>
          </div>
          <button onClick={() => setIsLobby(false)} className="w-full max-w-sm bg-emerald-500 hover:bg-emerald-400 text-black font-black py-8 rounded-[2.5rem] uppercase tracking-widest text-sm shadow-2xl shadow-emerald-500/20 active:scale-95 transition-all">
             Acessar Fazenda
          </button>
        </div>
      ) : (
        <>
          <nav className="flex bg-zinc-950/80 p-2 border-b border-white/5 overflow-x-auto scrollbar-hide relative z-10">
            {[
              { id: 'fazenda', icon: Sprout, label: 'Lavoura' },
              { id: 'pecuaria', icon: Beef, label: 'Pecuária' },
              { id: 'industria', icon: Factory, label: 'Indústria' },
              { id: 'cooperativa', icon: ShoppingBag, label: 'Mercado' },
              { id: 'ranking', icon: Trophy, label: 'Ranking' }
            ].map(t => (
              <button key={t.id} onClick={() => setActiveTab(t.id as any)} className={`flex-1 min-w-[110px] py-5 rounded-3xl text-[10px] font-black uppercase tracking-widest flex items-center justify-center gap-2 transition-all ${activeTab === t.id ? 'bg-emerald-500 text-black shadow-xl' : 'text-zinc-600 hover:text-zinc-400'}`}>
                <t.icon size={18}/> {t.label}
              </button>
            ))}
          </nav>

          <main className="flex-1 overflow-y-auto p-8 scrollbar-hide relative z-10">
            {activeTab === 'fazenda' && (
              <div className="grid grid-cols-2 md:grid-cols-4 gap-6">
                {gameState.plots.map(plot => {
                  const crop = plot.cropId ? CROPS.find(c => c.id === plot.cropId) : null;
                  const isLocked = plot.status === 'locked';
                  const isReady = plot.status === 'ready';
                  const isGrowing = plot.status === 'growing' || plot.status === 'planted';

                  return (
                    <div key={plot.id} 
                      onClick={() => !isLocked && (!crop ? setSelectedPlot(plot.id) : (isReady || plot.status.includes('loss')) && handleHarvest(plot.id))}
                      className={`aspect-square rounded-[3rem] border-4 flex flex-col items-center justify-center relative transition-all group cursor-pointer shadow-xl
                        ${isLocked ? 'bg-black border-zinc-900 opacity-20' : 
                          isReady ? 'bg-emerald-500/10 border-emerald-500 animate-pulse' : 
                          plot.status.includes('loss') ? 'bg-rose-500/10 border-rose-500' :
                          'bg-zinc-900/60 border-white/5 hover:border-emerald-500/40'}
                      `}
                    >
                      {isLocked ? <Lock className="text-zinc-800"/> : crop ? (
                        <div className="flex flex-col items-center gap-2">
                          <span className={`text-6xl drop-shadow-2xl transition-transform group-hover:scale-110 ${plot.status === 'total_loss' ? 'grayscale opacity-50' : ''}`}>{crop.emoji}</span>
                          {isGrowing && <div className="absolute inset-x-8 bottom-8 h-1.5 bg-black/40 rounded-full overflow-hidden"><div className="h-full bg-emerald-500 animate-pulse" style={{ width: '40%' }} /></div>}
                          {isReady && <span className="bg-emerald-500 text-black px-4 py-1.5 rounded-full text-[8px] font-black uppercase tracking-widest shadow-lg">Colher</span>}
                        </div>
                      ) : <Plus size={32} className="text-zinc-800 group-hover:text-emerald-500 transition-colors"/>}
                    </div>
                  );
                })}
              </div>
            )}

            {activeTab === 'industria' && (
              <div className="space-y-8 animate-in fade-in duration-500">
                <div className="bg-emerald-500/5 p-8 rounded-[3rem] border border-emerald-500/20 flex items-center justify-between">
                   <div className="flex items-center gap-6">
                      <div className="w-16 h-16 bg-emerald-500 rounded-3xl flex items-center justify-center text-black">
                         <Factory size={32} />
                      </div>
                      <div>
                         <h3 className="text-2xl font-black text-white italic tracking-tighter">PARQUE INDUSTRIAL</h3>
                         <p className="text-[10px] font-black text-zinc-500 uppercase tracking-widest">Transforme matéria-prima em lucro</p>
                      </div>
                   </div>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                   {INDUSTRY_RECIPES.map(recipe => {
                      const hasItems = (gameState.inventory[recipe.input] || 0) >= recipe.inputQty;
                      const active = isProcessing === recipe.id;

                      return (
                        <div key={recipe.id} className={`p-8 rounded-[3rem] border-2 flex flex-col gap-6 transition-all ${active ? 'border-emerald-500 bg-emerald-500/5' : 'border-white/5 bg-zinc-900/60'}`}>
                           <div className="flex justify-between items-start">
                              <div className="flex items-center gap-5">
                                 <span className="text-5xl">{recipe.emoji}</span>
                                 <div>
                                    <h4 className="text-xl font-black text-white tracking-tighter uppercase">{recipe.name}</h4>
                                    <p className="text-[9px] font-black text-zinc-500 uppercase tracking-widest mt-1">Gera +{recipe.xp} XP • {recipe.time}s</p>
                                 </div>
                              </div>
                              <div className="text-right">
                                 <span className="text-[8px] font-black text-zinc-600 uppercase">Input Necessário</span>
                                 <p className={`text-sm font-black ${hasItems ? 'text-emerald-500' : 'text-rose-500'}`}>{recipe.inputQty} {recipe.input}</p>
                              </div>
                           </div>

                           {active ? (
                             <div className="space-y-3">
                                <div className="flex justify-between text-[10px] font-black uppercase text-emerald-500"><span>Processando...</span><span>{Math.floor(processingProgress)}%</span></div>
                                <div className="w-full h-3 bg-black rounded-full overflow-hidden border border-emerald-500/20">
                                   <div className="h-full bg-emerald-500 transition-all duration-100" style={{ width: `${processingProgress}%` }}></div>
                                </div>
                             </div>
                           ) : (
                             <button 
                               onClick={() => handleProcessIndustry(recipe.id)}
                               disabled={!hasItems || !!isProcessing}
                               className={`w-full py-5 rounded-2xl font-black uppercase tracking-widest text-[10px] transition-all ${hasItems && !isProcessing ? 'bg-emerald-500 text-black shadow-xl active:scale-95' : 'bg-zinc-800 text-zinc-600 cursor-not-allowed'}`}
                             >
                               {isProcessing ? 'Indústria Ocupada' : hasItems ? 'Iniciar Produção' : 'Faltam Recursos'}
                             </button>
                           )}
                        </div>
                      );
                   })}
                </div>
              </div>
            )}

            {activeTab === 'cooperativa' && (
              <div className="space-y-8 animate-in slide-in-from-bottom-6 duration-500">
                <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                  {gameState.marketPrices.map(price => {
                    const stock = gameState.inventory[price.cropId] || 0;
                    return (
                      <div key={price.cropId} className="bg-zinc-900/80 border border-white/5 p-8 rounded-[3rem] flex flex-col gap-6 shadow-2xl group hover:border-emerald-500/20 transition-all">
                        <div className="flex justify-between items-center">
                          <span className="text-4xl">
                            {price.cropId === 'etanol' ? '⛽' : price.cropId === 'queijo' ? '🧀' : price.cropId === 'milho' ? '🌽' : price.cropId === 'soja' ? '🌱' : price.cropId === 'cana' ? '🎋' : '📦'}
                          </span>
                          <div className={`flex items-center gap-1 px-3 py-1 rounded-full text-[8px] font-black uppercase ${price.trend === 'up' ? 'bg-emerald-500/20 text-emerald-500' : 'bg-rose-500/20 text-rose-500'}`}>
                            {price.trend === 'up' ? <TrendingUp size={12}/> : <TrendingDown size={12}/>} {price.trend}
                          </div>
                        </div>
                        <div>
                          <h4 className="text-[10px] font-black uppercase text-zinc-500 tracking-widest mb-1">{price.cropId}</h4>
                          <p className="text-2xl font-black text-white tracking-tighter">R$ {price.price} <span className="text-zinc-700 text-sm">/ unidade</span></p>
                        </div>
                        <div className="flex items-center justify-between p-4 bg-black/40 rounded-2xl border border-white/5">
                           <span className="text-[9px] font-black text-zinc-500 uppercase tracking-widest">Estoque</span>
                           <span className="text-xl font-black text-emerald-500">{stock}</span>
                        </div>
                        <div className="grid grid-cols-2 gap-3">
                           <button onClick={() => handleSellItem(price.cropId, 10)} disabled={stock < 10} className="py-4 bg-zinc-800 hover:bg-emerald-500 hover:text-black rounded-xl text-[9px] font-black uppercase tracking-widest transition-all disabled:opacity-20">Vender 10</button>
