      setGameState(prev => {
        const nextPlots = prev.plots.map(p => {
          if (!p.cropId || !p.plantedAt) return p;
          const crop = CROPS.find(c => c.id === p.cropId);
          if (!crop) return p;

          const elapsed = (now - p.plantedAt) / 1000;
          const progress = elapsed / crop.growthTime;

          if (p.status === 'planted' || p.status === 'growing') {
            if (Math.random() < crop.riskFactor / 1000) { // Baixo risco contínuo
              const lossType = Math.random() > 0.4 ? 'partial_loss' : 'total_loss';
              return { ...p, status: lossType as PlotStatus, quality: lossType === 'partial_loss' ? 0.4 : 0 };
            }
            if (progress >= 1.0) return { ...p, status: 'ready' as PlotStatus };
            if (p.status === 'planted' && progress > 0.1) return { ...p, status: 'growing' as PlotStatus };
          }
          // Lógica de apodrecimento
          if (p.status === 'ready' && elapsed > crop.growthTime * 4) return { ...p, status: 'total_loss' as PlotStatus, quality: 0 };
          return p;
        });

        const nextPens = prev.pens.map(pen => {
          if (pen.status === 'active' && pen.startedAt && pen.animalId) {
            const animal = ANIMALS.find(a => a.id === pen.animalId);
            if (animal && (now - pen.startedAt) / 1000 >= animal.productionTime) {
              return { ...pen, status: 'ready' as const };
            }
          }
          return pen;
        });

        const newState = { ...prev, plots: nextPlots, pens: nextPens, lastCheck: now };
        UserDatabase.saveAgroState(currentUser.id, newState);
        return newState;
      });
    }, 1000);
    return () => clearInterval(interval);
  }, [currentUser.id]);

  const syncReputation = (xp: number) => {
    const freshUser = UserDatabase.findById(currentUser.id);
    if (freshUser) {
      freshUser.reputation += Math.floor(xp / 15);
      freshUser.xp += xp;
      if (freshUser.xp >= freshUser.level * 2500) {
        freshUser.level++;
        freshUser.xp = 0;
      }
      UserDatabase.updateUser(freshUser);
    }
  };

  const handlePlant = (plotId: number, cropId: string) => {
    const crop = CROPS.find(c => c.id === cropId);
    if (!crop || gameState.credits < crop.cost) return;
    setGameState(prev => ({
      ...prev,
      credits: prev.credits - crop.cost,
      plots: prev.plots.map(p => p.id === plotId ? { ...p, cropId, plantedAt: Date.now(), status: 'planted', quality: 1.0, riskTriggered: false } : p)
    }));
    setSelectedPlot(null);
    if (navigator.vibrate) navigator.vibrate(20);
  };

  const handleHarvest = (plotId: number) => {
    const plot = gameState.plots.find(p => p.id === plotId);
    if (!plot || !plot.cropId) return;
    if (plot.status !== 'ready' && plot.status !== 'partial_loss' && plot.status !== 'total_loss') return;

    const crop = CROPS.find(c => c.id === plot.cropId);
    if (!crop) return;

    const yieldAmount = Math.floor(crop.baseYield * plot.quality);
    const xpReward = Math.floor(crop.xp * plot.quality);

    setGameState(prev => {
      const inv = { ...prev.inventory };
      if (yieldAmount > 0) inv[crop.id] = (inv[crop.id] || 0) + yieldAmount;
      syncReputation(xpReward);
      return {
        ...prev,
        xp: prev.xp + xpReward,
        inventory: inv,
        plots: prev.plots.map(p => p.id === plotId ? { ...p, cropId: null, plantedAt: null, status: 'empty', quality: 1.0 } : p)
      };
    });
    if (navigator.vibrate) navigator.vibrate([10, 30]);
  };

  const handleBuyAnimal = (penId: number, animalId: string) => {
    const animal = ANIMALS.find(a => a.id === animalId);
    if (!animal || gameState.credits < animal.cost) return;
    setGameState(prev => ({
      ...prev,
      credits: prev.credits - animal.cost,
      pens: prev.pens.map(p => p.id === penId ? { 
        ...p, 
        animalId, 
        startedAt: Date.now(), 
        status: 'active', 
        hunger: 0, 
        health: 1.0 
      } : p)
    }));
    setSelectedPen(null);
    if (navigator.vibrate) navigator.vibrate(50);
  };

  const handleCollectProduction = (penId: number) => {
    const pen = gameState.pens.find(p => p.id === penId);
    if (!pen || !pen.animalId || pen.status !== 'ready') return;

    const animal = ANIMALS.find(a => a.id === pen.animalId);
    if (!animal) return;

    setGameState(prev => {
      const inv = { ...prev.inventory };
      animal.products.forEach(prod => {
        inv[prod] = (inv[prod] || 0) + animal.baseYield;
      });
      syncReputation(animal.xp);
      return {
        ...prev,
        inventory: inv,
        xp: prev.xp + animal.xp,
        pens: prev.pens.map(p => p.id === penId ? { ...p, startedAt: Date.now(), status: 'active' } : p)
      };
    });
    if (navigator.vibrate) navigator.vibrate([20, 40]);
  };

  const handleProcessIndustry = async (recipeId: string) => {
    const recipe = INDUSTRY_RECIPES.find(r => r.id === recipeId);
    if (!recipe || (gameState.inventory[recipe.input] || 0) < recipe.inputQty || isProcessing) return;

    setIsProcessing(recipeId);
    setProcessingProgress(0);

    const duration = recipe.time * 1000;
    const start = Date.now();

    const timer = setInterval(() => {
      const elapsed = Date.now() - start;
      const progress = (elapsed / duration) * 100;
      if (progress >= 100) {
        clearInterval(timer);
        setGameState(prev => {
          const inv = { ...prev.inventory };
          inv[recipe.input] -= recipe.inputQty;
          inv[recipe.id] = (inv[recipe.id] || 0) + recipe.outputQty;
          syncReputation(recipe.xp);
          return { ...prev, inventory: inv, xp: prev.xp + recipe.xp };
        });
        setIsProcessing(null);
        setProcessingProgress(0);
        if (navigator.vibrate) navigator.vibrate([50, 20, 50]);
      } else {
        setProcessingProgress(progress);
      }
    }, 100);
  };

  const handleSellItem = (itemId: string, qty: number) => {
    const priceData = gameState.marketPrices.find(p => p.cropId === itemId);
    const currentQty = gameState.inventory[itemId] || 0;
    if (!priceData || currentQty < qty) return;

    const totalEarning = priceData.price * qty;
    setGameState(prev => {
      const inv = { ...prev.inventory };
      inv[itemId] -= qty;
      return { ...prev, credits: prev.credits + totalEarning, inventory: inv };
    });
    if (navigator.vibrate) navigator.vibrate(10);
  };

  return (
    <div className="h-[calc(100vh-180px)] bg-[#010502] rounded-[4rem] border border-white/5 flex flex-col overflow-hidden shadow-2xl relative">

