                                    <h4 className="text-2xl font-black text-white tracking-tighter uppercase">{recipe.name}</h4>
                                    <div className="flex items-center gap-3 mt-2">
                                       <span className="text-[9px] font-black text-emerald-500 uppercase flex items-center gap-1"><Zap size={10} fill="currentColor"/> +{recipe.xp} XP</span>
                                       <span className="text-[9px] font-black text-zinc-500 uppercase flex items-center gap-1"><History size={10}/> {recipe.time}s</span>
                                    </div>
                                 </div>
                              </div>
                              <div className="text-right">
                                 <span className="text-[9px] font-black text-zinc-600 uppercase tracking-widest">Requisito</span>
