                           {active ? (
                             <div className="space-y-4 relative z-10">
                                <div className="flex justify-between text-[11px] font-black uppercase text-emerald-500 tracking-[0.2em]"><span>Industrializando...</span><span>{Math.floor(processingProgress)}%</span></div>
                                <div className="w-full h-4 bg-black rounded-full overflow-hidden border border-emerald-500/20 shadow-inner">
                                   <div className="h-full bg-emerald-500 shadow-[0_0_15px_rgba(16,185,129,0.5)] transition-all duration-100" style={{ width: `${processingProgress}%` }}></div>
                                </div>
                             </div>
                           ) : (
                             <button 
                               onClick={() => handleProcessIndustry(recipe.id)}
                               disabled={!hasItems || !!isProcessing}
                               className={`w-full py-6 rounded-3xl font-black uppercase tracking-[0.2em] text-xs transition-all relative z-10 ${hasItems && !isProcessing ? 'bg-emerald-500 text-black shadow-2xl active:scale-95' : 'bg-zinc-800 text-zinc-600 cursor-not-allowed opacity-40'}`}
