                           <div className="absolute bottom-[-10%] right-[-5%] opacity-5 pointer-events-none">
                              <Factory size={150} />
                           </div>
                        </div>
                      );
                   })}
                </div>
              </div>
            )}

            {activeTab === 'cooperativa' && (
              <div className="space-y-10 animate-in slide-in-from-bottom-10 duration-500">
                <div className="bg-zinc-900 border border-white/5 rounded-[4rem] p-10 flex flex-col md:flex-row items-center justify-between gap-10">
                   <div className="flex items-center gap-8">
                      <div className="p-6 bg-emerald-500/10 rounded-[2.5rem] border border-emerald-500/20 text-emerald-500">
                         <ShoppingBag size={48} />
                      </div>
                      <div>
                         <h3 className="text-4xl font-black italic text-white tracking-tighter uppercase">BALCÃO DA <span className="text-emerald-500">COOPERATIVA</span></h3>
