              <div className="p-12 grid grid-cols-1 md:grid-cols-2 gap-6 max-h-[60vh] overflow-y-auto scrollbar-hide">
                 {CROPS.map(c => (
                   <button 
                    key={c.id} 
                    disabled={gameState.level < c.minLevel || gameState.credits < c.cost}
                    onClick={() => handlePlant(selectedPlot, c.id)}
                    className={`p-8 rounded-[3.5rem] border-2 flex items-center justify-between transition-all ${gameState.level < c.minLevel ? 'opacity-20 bg-black cursor-not-allowed border-zinc-900' : 'bg-zinc-900/60 border-white/5 hover:border-emerald-500/40'}`}
                   >
                     <div className="flex items-center gap-5 text-left">
                        <span className="text-6xl drop-shadow-xl">{c.emoji}</span>
                        <div>
                           <p className="font-black text-xl text-white tracking-tighter">{c.name}</p>
                           <p className="text-sm font-black text-emerald-500 tracking-tighter">R$ {c.cost.toLocaleString()}</p>
                           <p className="text-[9px] font-black text-zinc-600 uppercase mt-1">Colheita: {c.growthTime}s</p>
                        </div>
                     </div>
                     {gameState.level < c.minLevel && <Lock size={20} className="text-zinc-700"/>}
                   </button>
                 ))}
              </div>
           </div>
        </div>
      )}

      {/* Animais */}
      {selectedPen !== null && (
        <div className="fixed inset-0 z-[300] bg-black/98 backdrop-blur-3xl flex items-center justify-center p-6 animate-in fade-in duration-300">
           <div className="w-full max-w-2xl bg-[#0a0a0a] border border-white/10 rounded-[5rem] overflow-hidden shadow-2xl animate-in zoom-in-95 duration-500">
              <div className="p-12 border-b border-white/5 flex justify-between items-center bg-zinc-950/20">
                 <div>
                    <h3 className="text-4xl font-black italic tracking-tighter uppercase">MATRIZES <span className="text-blue-500">ANIMAIS</span></h3>
                    <p className="text-[10px] font-black text-zinc-600 uppercase tracking-[0.4em] mt-2">Invista na pecuária de elite</p>
                 </div>
                 <button onClick={() => setSelectedPen(null)} className="p-5 bg-zinc-900 rounded-3xl text-zinc-500 hover:text-white transition-colors"><X size={32}/></button>
              </div>
              <div className="p-12 grid grid-cols-1 md:grid-cols-2 gap-6 max-h-[60vh] overflow-y-auto scrollbar-hide">
                 {ANIMALS.map(a => (
                   <button 
                    key={a.id} 
                    disabled={gameState.level < a.minLevel || gameState.credits < a.cost}
                    onClick={() => handleBuyAnimal(selectedPen, a.id)}
                    className={`p-8 rounded-[3.5rem] border-2 flex items-center justify-between transition-all ${gameState.level < a.minLevel ? 'opacity-20 bg-black cursor-not-allowed border-zinc-900' : 'bg-zinc-900/60 border-white/5 hover:border-blue-500/40'}`}
                   >
                     <div className="flex items-center gap-5 text-left">
                        <span className="text-6xl drop-shadow-xl">{a.emoji}</span>
                        <div>
                           <p className="font-black text-xl text-white tracking-tighter">{a.name}</p>
                           <p className="text-sm font-black text-blue-500 tracking-tighter">R$ {a.cost.toLocaleString()}</p>
                           <p className="text-[9px] font-black text-zinc-600 uppercase mt-1">Prod: {a.productionTime}s</p>
                        </div>
                     </div>
                     {gameState.level < a.minLevel && <Lock size={20} className="text-zinc-700"/>}
                   </button>
                 ))}
              </div>
           </div>
        </div>
      )}

    </div>
  );
};

export default AgroBrazil;

import React, { useState, useEffect, useMemo } from 'react';
