  { id: 'galinha', name: 'Galinha Caipira', emoji: '🐔', productionTime: 30, cost: 800, baseYield: 20, xp: 150, products: ['ovos'], minLevel: 1 },
  { id: 'porco', name: 'Suinocultura', emoji: '🐷', productionTime: 120, cost: 4500, baseYield: 80, xp: 900, products: ['carne'], minLevel: 4 },
