          <button onClick={() => setIsLobby(false)} className="w-full max-w-sm bg-emerald-500 hover:bg-emerald-400 text-black font-black py-8 rounded-[2.5rem] uppercase tracking-widest text-sm shadow-2xl shadow-emerald-500/20 active:scale-95 transition-all flex items-center justify-center gap-4">
             Administrar Território <ArrowRight size={20} />
