                          isReady ? 'bg-amber-500/10 border-amber-500' : 
                          'bg-zinc-900/60 border-white/5 hover:border-blue-500/40'}
                      `}
                    >
                      {isLocked ? <Lock className="text-zinc-800"/> : animal ? (
                        <div className="flex flex-col items-center gap-4 relative z-10 text-center">
                           <span className="text-7xl group-hover:scale-110 transition-transform">{animal.emoji}</span>
                           <div>
                              <p className="text-[11px] font-black uppercase text-zinc-400 tracking-widest">{animal.name}</p>
                              {isActive && <p className="text-[9px] font-black text-blue-500 uppercase mt-1 animate-pulse flex items-center gap-1 justify-center"><Droplets size={10} /> Produzindo...</p>}
                              {isReady && <button className="mt-4 bg-amber-500 text-black px-8 py-2.5 rounded-full text-[10px] font-black uppercase tracking-widest shadow-xl">Coletar {animal.products[0]}</button>}
                           </div>
                        </div>
                      ) : (
                        <div className="flex flex-col items-center gap-3">
                           <div className="w-16 h-16 bg-black/20 rounded-3xl flex items-center justify-center text-zinc-800 group-hover:text-blue-500 transition-colors">
                              <Plus size={32} />
                           </div>
                           <p className="text-[10px] font-black uppercase text-zinc-800 tracking-widest">Novo Cercado</p>
                        </div>
                      )}
                    </div>
                  );
                })}
              </div>
            )}

            {activeTab === 'industria' && (
              <div className="space-y-8 animate-in fade-in duration-500">
                <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                   {INDUSTRY_RECIPES.map(recipe => {
                      const hasItems = (gameState.inventory[recipe.input] || 0) >= recipe.inputQty;
                      const active = isProcessing === recipe.id;

                      return (
                        <div key={recipe.id} className={`p-10 rounded-[3.5rem] border-4 flex flex-col gap-8 transition-all relative overflow-hidden ${active ? 'border-emerald-500 bg-emerald-500/5' : 'border-white/5 bg-zinc-900/60'}`}>
                           <div className="flex justify-between items-start relative z-10">
                              <div className="flex items-center gap-6">
                                 <div className="w-16 h-16 bg-zinc-950 rounded-3xl flex items-center justify-center text-5xl shadow-2xl">
                                    {recipe.emoji}
                                 </div>
                                 <div>
                                    <h4 className="text-2xl font-black text-white tracking-tighter uppercase">{recipe.name}</h4>
                                    <div className="flex items-center gap-3 mt-2">
                                       <span className="text-[9px] font-black text-emerald-500 uppercase flex items-center gap-1"><Zap size={10} fill="currentColor"/> +{recipe.xp} XP</span>
                                       <span className="text-[9px] font-black text-zinc-500 uppercase flex items-center gap-1"><History size={10}/> {recipe.time}s</span>
                                    </div>
                                 </div>
                              </div>
                              <div className="text-right">
                                 <span className="text-[9px] font-black text-zinc-600 uppercase tracking-widest">Requisito</span>
                                 <p className={`text-lg font-black ${hasItems ? 'text-emerald-500' : 'text-rose-500'}`}>{recipe.inputQty} {recipe.input}</p>
                              </div>
                           </div>

                           {active ? (
                             <div className="space-y-4 relative z-10">
                                <div className="flex justify-between text-[11px] font-black uppercase text-emerald-500 tracking-[0.2em]"><span>Processando...</span><span>{Math.floor(processingProgress)}%</span></div>
                                <div className="w-full h-4 bg-black rounded-full overflow-hidden border border-emerald-500/20 shadow-inner">
                                   <div className="h-full bg-emerald-500 shadow-[0_0_15px_rgba(16,185,129,0.5)] transition-all duration-100" style={{ width: `${processingProgress}%` }}></div>
                                </div>
                             </div>
                           ) : (
                             <button 
                               onClick={() => handleProcessIndustry(recipe.id)}
                               disabled={!hasItems || !!isProcessing}
                               className={`w-full py-6 rounded-3xl font-black uppercase tracking-[0.2em] text-xs transition-all relative z-10 ${hasItems && !isProcessing ? 'bg-emerald-500 text-black shadow-2xl active:scale-95' : 'bg-zinc-800 text-zinc-600 cursor-not-allowed opacity-40'}`}
                             >
                               {isProcessing ? 'Indústria Ocupada' : hasItems ? 'Iniciar Produção' : 'Recursos Insuficientes'}
                             </button>
                           )}
