                      );
                   })}
                </div>
              </div>
            )}

            {activeTab === 'cooperativa' && (
              <div className="space-y-10 animate-in slide-in-from-bottom-10 duration-500">
                <div className="bg-zinc-900 border border-white/5 rounded-[4rem] p-10 flex flex-col md:flex-row items-center justify-between gap-10">
                   <div className="flex items-center gap-8">
                      <div className="p-6 bg-emerald-500/10 rounded-[2.5rem] border border-emerald-500/20 text-emerald-500">
                         <ShoppingBag size={48} />
                      </div>
                      <div>
                         <h3 className="text-4xl font-black italic text-white tracking-tighter uppercase">BALCÃO DA <span className="text-emerald-500">COOPERATIVA</span></h3>
                         <p className="text-[10px] font-black text-zinc-500 uppercase tracking-widest mt-2">Converta sua produção em créditos TRIBO</p>
                      </div>
                   </div>
                   <div className="px-10 py-5 bg-black rounded-[2rem] border border-white/5 text-center">
                      <span className="text-[8px] font-black text-zinc-600 uppercase block mb-1">Total em Estoque</span>
                      <span className="text-2xl font-black text-white">{(Object.values(gameState.inventory) as number[]).reduce((a, b) => a + b, 0)}</span>
                   </div>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
                  {gameState.marketPrices.map(price => {
                    const stock = gameState.inventory[price.cropId] || 0;
                    return (
                      <div key={price.cropId} className="bg-zinc-900/60 border border-white/5 p-8 rounded-[3rem] flex flex-col gap-6 group hover:border-emerald-500/20 transition-all shadow-2xl">
                        <div className="flex justify-between items-center">
                          <div className="w-16 h-16 bg-zinc-950 rounded-3xl flex items-center justify-center text-4xl shadow-xl">
