                          </div>
                          <div className={`flex items-center gap-2 px-4 py-2 rounded-full text-[10px] font-black uppercase ${price.trend === 'up' ? 'bg-emerald-500/10 text-emerald-500' : 'bg-rose-500/10 text-rose-500'}`}>
