const TITLES = [
  { minLevel: 1, title: 'Pequeno Produtor', color: 'text-zinc-400' },
  { minLevel: 5, title: 'Produtor Familiar', color: 'text-emerald-400' },
  { minLevel: 10, title: 'Fazendeiro Regional', color: 'text-blue-400' },
