const AgroBrazil: React.FC<{ currentUser: User }> = ({ currentUser }) => {
  const [isLobby, setIsLobby] = useState(true);
  const [activeTab, setActiveTab] = useState<'fazenda' | 'pecuaria' | 'industria' | 'exportacao' | 'ranking'>('fazenda');
  const [selectedPlot, setSelectedPlot] = useState<number | null>(null);
  const [selectedPen, setSelectedPen] = useState<number | null>(null);
  const [isProcessing, setIsProcessing] = useState<string | null>(null);
  const [processingProgress, setProcessingProgress] = useState(0);

  const [gameState, setGameState] = useState<AgroGameState>(() => 
    UserDatabase.getAgroState(currentUser.id)
  );

  const currentTitle = useMemo(() => {
    return [...TITLES].reverse().find(t => gameState.level >= t.minLevel) || TITLES[0];
  }, [gameState.level]);

  // Gameloop principal
  useEffect(() => {
    const interval = setInterval(() => {
      const now = Date.now();
      setGameState(prev => {
        const nextPlots = prev.plots.map(p => {
          if (!p.cropId || !p.plantedAt) return p;
          const crop = CROPS.find(c => c.id === p.cropId);
          if (!crop) return p;

          const elapsed = (now - p.plantedAt) / 1000;
          const progress = elapsed / crop.growthTime;

          if (p.status === 'planted' || p.status === 'growing') {
            // Risco de praga ou seca
            if (Math.random() < crop.riskFactor / 1000) { 
              const lossType = Math.random() > 0.4 ? 'partial_loss' : 'total_loss';
              return { ...p, status: lossType as PlotStatus, quality: lossType === 'partial_loss' ? 0.4 : 0 };
            }
            if (progress >= 1.0) return { ...p, status: 'ready' as PlotStatus };
            if (p.status === 'planted' && progress > 0.1) return { ...p, status: 'growing' as PlotStatus };
          }
          return p;
        });

        const nextPens = prev.pens.map(pen => {
          if (pen.status === 'active' && pen.startedAt && pen.animalId) {
            const animal = ANIMALS.find(a => a.id === pen.animalId);
            if (animal && (now - pen.startedAt) / 1000 >= animal.productionTime) {
              return { ...pen, status: 'ready' as const };
            }
          }
          return pen;
        });

        // Contratos de Exportação expiram
        const nextContracts = (prev.exportContracts || []).filter(c => c.expiresAt > now);
        // Gera novo contrato se houver poucos
        if (nextContracts.length < 3 && Math.random() > 0.99) {
           const randomCrop = CROPS[Math.floor(Math.random() * CROPS.length)];
           nextContracts.push({
             id: Math.random().toString(36).substr(2, 5).toUpperCase(),
             targetItem: randomCrop.id,
             quantity: Math.floor(Math.random() * 5000) + 1000,
             reward: Math.floor(randomCrop.cost * 15),
             expiresAt: now + (1000 * 60 * 30), // 30 min
             bonusXp: randomCrop.xp * 5,
             destination: ['China', 'EUA', 'Europa', 'Oriente Médio'][Math.floor(Math.random() * 4)]
           });
        }

        const newState = { 
          ...prev, 
          plots: nextPlots, 
          pens: nextPens, 
          exportContracts: nextContracts,
          lastCheck: now 
        };
        UserDatabase.saveAgroState(currentUser.id, newState);
        return newState;
      });
    }, 1000);
    return () => clearInterval(interval);
  }, [currentUser.id]);

  const syncReputation = (xp: number) => {
    const freshUser = UserDatabase.findById(currentUser.id);
    if (freshUser) {
      freshUser.reputation += Math.floor(xp / 10);
      freshUser.xp += xp;
      if (freshUser.xp >= freshUser.level * 2500) {
        freshUser.level++;
        freshUser.xp = 0;
      }
      UserDatabase.updateUser(freshUser);
    }
  };

  const handlePlant = (plotId: number, cropId: string) => {
    const crop = CROPS.find(c => c.id === cropId);
    if (!crop || gameState.credits < crop.cost) return;
    setGameState(prev => ({
      ...prev,
      credits: prev.credits - crop.cost,
      plots: prev.plots.map(p => p.id === plotId ? { ...p, cropId, plantedAt: Date.now(), status: 'planted', quality: 1.0, riskTriggered: false } : p)
    }));
    setSelectedPlot(null);
  };

  const handleHarvest = (plotId: number) => {
    const plot = gameState.plots.find(p => p.id === plotId);
    if (!plot || !plot.cropId || plot.status !== 'ready') return;
    const crop = CROPS.find(c => c.id === plot.cropId);
    if (!crop) return;
    const yieldAmount = Math.floor(crop.baseYield * plot.quality);
    setGameState(prev => {
      const inv = { ...prev.inventory };
      inv[crop.id] = (inv[crop.id] || 0) + yieldAmount;
      syncReputation(crop.xp);
      return {
        ...prev,
        xp: prev.xp + crop.xp,
        inventory: inv,
        plots: prev.plots.map(p => p.id === plotId ? { ...p, cropId: null, plantedAt: null, status: 'empty', quality: 1.0 } : p)
      };
    });
  };

  const handleCompleteExport = (contract: ExportContract) => {
    const currentQty = gameState.inventory[contract.targetItem] || 0;
    if (currentQty < contract.quantity) return;

    setGameState(prev => {
      const inv = { ...prev.inventory };
      inv[contract.targetItem] -= contract.quantity;
      syncReputation(contract.bonusXp);
      return {
        ...prev,
        credits: prev.credits + contract.reward,
        xp: prev.xp + contract.bonusXp,
        inventory: inv,
        exportContracts: prev.exportContracts.filter(c => c.id !== contract.id)
      };
    });
    if (navigator.vibrate) navigator.vibrate([30, 10, 30]);
  };

  return (
    <div className="h-full bg-[#050805] rounded-[3.5rem] border border-white/5 flex flex-col overflow-hidden shadow-2xl relative">

      {/* HUD Superior Especial */}
      <header className="p-8 border-b border-white/5 bg-zinc-950/60 backdrop-blur-xl flex items-center justify-between relative z-10 shrink-0">
        <div className="flex items-center gap-6">
          <button onClick={() => isLobby ? null : setIsLobby(true)} className="p-4 bg-zinc-900 text-zinc-500 rounded-2xl hover:text-white transition-all">
            <ChevronLeft size={24}/>
          </button>
          <div className="flex items-center gap-4">
             <div className="relative">
                <img src={currentUser.avatar} className="w-14 h-14 rounded-2xl object-cover border-2 border-emerald-500/20" />
                <div className="absolute -bottom-1 -right-1 bg-emerald-500 text-black p-0.5 rounded-lg"><BadgeCheck size={12}/></div>
             </div>
             <div>
                <h2 className="text-xl font-black text-white italic tracking-tighter uppercase leading-none">AGRO <span className="text-emerald-500">BRASIL</span></h2>
                <p className={`text-[10px] font-black uppercase tracking-widest mt-1 ${currentTitle.color}`}>{currentTitle.title}</p>
             </div>
          </div>
        </div>

        <div className="flex items-center gap-6">
           <div className="text-right hidden sm:block">
              <span className="text-[8px] font-black text-zinc-600 uppercase">Capital Líquido</span>
              <p className="text-xl font-black text-emerald-500 tracking-tighter">R$ {gameState.credits.toLocaleString('pt-BR')}</p>
           </div>
           <div className="w-12 h-12 bg-emerald-500/10 rounded-2xl flex items-center justify-center text-emerald-500 border border-emerald-500/20">
              <Landmark size={24} />
           </div>
        </div>
      </header>

      {isLobby ? (
        <div className="flex-1 flex flex-col items-center justify-center p-12 text-center space-y-12 relative z-10 overflow-y-auto scrollbar-hide">
           <div className="relative group">
              <div className="absolute inset-0 bg-emerald-500 blur-[80px] opacity-10 animate-pulse"></div>
              <Tractor size={120} className="text-emerald-500 relative z-10 drop-shadow-[0_0_30px_rgba(16,185,129,0.3)]" />
           </div>
           <div className="space-y-4">
              <h1 className="text-7xl md:text-9xl font-black italic text-white tracking-tighter leading-none">AGRO<br/><span className="text-emerald-500">BRASIL</span></h1>
              <p className="text-zinc-500 font-bold uppercase tracking-[0.5em] text-[10px] max-w-sm mx-auto">Soberania alimentar e riqueza nacional na TRIBO</p>
           </div>

           <div className="grid grid-cols-3 gap-4 w-full max-w-lg">
              <div className="bg-zinc-900/40 p-6 rounded-[2.5rem] border border-white/5">
                 <Package size={20} className="text-emerald-500 mx-auto mb-2" />
                 <p className="text-lg font-black text-white">{Object.values(gameState.inventory).reduce((a, b) => a + b, 0)}</p>
                 <p className="text-[7px] font-black text-zinc-600 uppercase tracking-widest">Estoque</p>
              </div>
              <div className="bg-zinc-900/40 p-6 rounded-[2.5rem] border border-white/5">
                 <Ship size={20} className="text-blue-500 mx-auto mb-2" />
                 <p className="text-lg font-black text-white">{gameState.exportContracts?.length || 0}</p>
                 <p className="text-[7px] font-black text-zinc-600 uppercase tracking-widest">Contratos</p>
              </div>
              <div className="bg-zinc-900/40 p-6 rounded-[2.5rem] border border-white/5">
                 <Trophy size={20} className="text-amber-500 mx-auto mb-2" />
                 <p className="text-lg font-black text-white">#{gameState.level}</p>
                 <p className="text-[7px] font-black text-zinc-600 uppercase tracking-widest">Patente</p>
              </div>
           </div>

           <button onClick={() => setIsLobby(false)} className="w-full max-w-sm bg-emerald-500 hover:bg-emerald-400 text-black font-black py-8 rounded-[2.5rem] uppercase tracking-widest text-sm shadow-2xl shadow-emerald-500/20 active:scale-95 transition-all flex items-center justify-center gap-4">
              Iniciar Gestão <ArrowRight size={20} />
           </button>
        </div>
      ) : (
        <>
          <nav className="flex bg-zinc-950/80 p-2 border-b border-white/5 overflow-x-auto scrollbar-hide relative z-10 shrink-0">
            {[
              { id: 'fazenda', icon: Sprout, label: 'Lavouras' },
              { id: 'pecuaria', icon: Beef, label: 'Pecuária' },
              { id: 'industria', icon: Factory, label: 'Indústria' },
              { id: 'exportacao', icon: Ship, label: 'Exportar' },
              { id: 'ranking', icon: Trophy, label: 'Soberanos' }
            ].map(t => (
              <button 
                key={t.id} 
                onClick={() => setActiveTab(t.id as any)} 
                className={`flex-1 min-w-[100px] py-4 rounded-3xl text-[9px] font-black uppercase tracking-widest flex items-center justify-center gap-2 transition-all ${activeTab === t.id ? 'bg-emerald-500 text-black shadow-xl' : 'text-zinc-600 hover:text-zinc-400'}`}
              >
                <t.icon size={16}/> {t.label}
              </button>
            ))}
          </nav>

