                       <div key={p.id} className={`p-8 rounded-[3.5rem] border-2 flex items-center justify-between transition-all ${p.id === currentUser.id ? 'bg-emerald-500 text-black border-emerald-500 shadow-2xl scale-[1.02]' : 'bg-zinc-900/40 border-white/5 text-white hover:border-white/20'}`}>
