                       { id: currentUser.id, name: currentUser.name, level: gameState.level, credits: gameState.credits, avatar: currentUser.avatar, title: currentTitle.title },
                       { id: '3', name: 'Tribo Farmer', level: 12, credits: 85000, avatar: 'https://picsum.photos/seed/farmer/100', title: 'Barão do Café' },
                       { id: '4', name: 'Agro King', level: 8, credits: 42000, avatar: 'https://picsum.photos/seed/king/100', title: 'Fazendeiro Regional' }
                     ].sort((a,b) => b.credits - a.credits).map((p, i) => (
                       <div key={p.id} className={`p-8 rounded-[3.5rem] border-2 flex items-center justify-between transition-all ${p.id === currentUser.id ? 'bg-emerald-500 text-black border-emerald-500 shadow-2xl scale-[1.02]' : 'bg-zinc-900/40 border-white/5 text-white hover:border-white/20'}`}>
                          <div className="flex items-center gap-8">
                             <div className="font-black italic text-3xl w-10 opacity-60">#{i+1}</div>
                             <img src={p.avatar} className="w-16 h-16 rounded-2xl border-2 border-white/10 shadow-lg object-cover" />
                             <div>
                                <p className="font-black text-2xl tracking-tighter">{p.name}</p>
                                <p className="text-[9px] font-black uppercase opacity-60 tracking-[0.2em]">{p.title}</p>
                             </div>
                          </div>
                          <div className="text-right">
                             <p className="font-black text-2xl tracking-tighter">R$ {p.credits.toLocaleString()}</p>
                             <p className="text-[9px] font-black uppercase opacity-60 tracking-widest mt-1">Nv. {p.level}</p>
                          </div>
                       </div>
                     ))}
                  </div>
               </div>
            )}
          </main>
        </>
      )}

      {/* Modal de Plantio */}
      {selectedPlot !== null && (
        <div className="fixed inset-0 z-[300] bg-black/98 backdrop-blur-3xl flex items-center justify-center p-6 animate-in fade-in duration-300">
           <div className="w-full max-w-2xl bg-[#0a0a0a] border border-white/10 rounded-[5rem] overflow-hidden shadow-2xl animate-in zoom-in-95 duration-500">
              <div className="p-12 border-b border-white/5 flex justify-between items-center bg-zinc-950/20">
                 <div>
                    <h3 className="text-4xl font-black italic tracking-tighter uppercase leading-none">SEMENTES <span className="text-emerald-500">CERTIFICADAS</span></h3>
                    <p className="text-[10px] font-black text-zinc-600 uppercase tracking-[0.4em] mt-2">Invista em tecnologia genética de ponta</p>
                 </div>
                 <button onClick={() => setSelectedPlot(null)} className="p-5 bg-zinc-900 rounded-3xl text-zinc-500 hover:text-white transition-colors"><X size={32}/></button>
              </div>
              <div className="p-12 grid grid-cols-1 md:grid-cols-2 gap-6 max-h-[60vh] overflow-y-auto scrollbar-hide">
                 {CROPS.map(c => (
                   <button 
                    key={c.id} 
                    disabled={gameState.level < c.minLevel || gameState.credits < c.cost}
                    onClick={() => handlePlant(selectedPlot, c.id)}
                    className={`p-8 rounded-[3.5rem] border-2 flex items-center justify-between transition-all ${gameState.level < c.minLevel ? 'opacity-20 bg-black cursor-not-allowed border-zinc-900' : 'bg-zinc-900/60 border-white/5 hover:border-emerald-500/40'}`}
                   >
                     <div className="flex items-center gap-5 text-left">
                        <span className="text-6xl drop-shadow-xl">{c.emoji}</span>
                        <div>
                           <p className="font-black text-xl text-white tracking-tighter">{c.name}</p>
                           <p className="text-sm font-black text-emerald-500 tracking-tighter">R$ {c.cost.toLocaleString()}</p>
                           <p className="text-[9px] font-black text-zinc-600 uppercase mt-1">Nv. {c.minLevel} • {c.growthTime}s</p>
                        </div>
                     </div>
                     {gameState.level < c.minLevel && <Lock size={20} className="text-zinc-700"/>}
                   </button>
                 ))}
              </div>
           </div>
        </div>
      )}

    </div>
  );
};

