                    <p className="text-[12px] font-black text-zinc-600 uppercase tracking-[0.5em] mt-3">Investimento em genética e produtividade</p>
                 </div>
                 <button onClick={() => setSelectedPen(null)} className="p-8 bg-zinc-900 rounded-[2.5rem] text-zinc-500 hover:text-white transition-all"><X size={48}/></button>
              </div>
              <div className="p-16 grid grid-cols-1 md:grid-cols-2 gap-8 max-h-[60vh] overflow-y-auto scrollbar-hide">
                 {ANIMALS.map(a => (
                   <button 
                    key={a.id} 
                    disabled={gameState.level < a.minLevel || gameState.credits < a.cost}
                    onClick={() => handleBuyAnimal(selectedPen, a.id)}
                    className={`p-10 rounded-[4rem] border-4 flex items-center justify-between transition-all ${gameState.level < a.minLevel ? 'opacity-20 bg-black cursor-not-allowed border-zinc-900' : 'bg-zinc-900/60 border-white/5 hover:border-blue-500/40 hover:scale-[1.02] shadow-2xl'}`}
                   >
                     <div className="flex items-center gap-8 text-left">
                        <span className="text-7xl drop-shadow-2xl">{a.emoji}</span>
                        <div>
                           <p className="font-black text-2xl text-white tracking-tighter">{a.name}</p>
                           <p className="text-xl font-black text-blue-500 tracking-tighter">R$ {a.cost.toLocaleString()}</p>
                           <div className="flex items-center gap-4 mt-2">
                             <span className="text-[10px] font-black text-zinc-600 uppercase">Nv. {a.minLevel}</span>
                             <span className="text-[10px] font-black text-zinc-600 uppercase">Ciclo: {a.productionTime}s</span>
                           </div>
                        </div>
                     </div>
                     {gameState.level < a.minLevel && <Lock size={32} className="text-zinc-700"/>}
                   </button>
                 ))}
              </div>
           </div>
        </div>
      )}

    </div>
  );
};

