  { id: 'racao', name: 'Ração Animal', input: 'milho', inputQty: 200, output: 'racao', outputQty: 50, time: 20, xp: 100, emoji: '📦' },
  { id: 'queijo', name: 'Queijo Artesanal', input: 'leite', inputQty: 100, output: 'queijo_artesanal', outputQty: 5, time: 30, xp: 450, emoji: '🧀' },
