  { id: 'haras', name: 'Haras Elite', emoji: '🐎', productionTime: 900, cost: 150000, baseYield: 1, xp: 30000, products: ['prestigio'], minLevel: 25 },
];

const INDUSTRY_RECIPES = [
  { id: 'racao', name: 'Fábrica de Ração', input: 'milho', inputQty: 200, output: 'racao', outputQty: 60, time: 20, xp: 150, emoji: '📦' },
  { id: 'queijo', name: 'Queijo Artesanal', input: 'leite', inputQty: 100, output: 'queijo_artesanal', outputQty: 12, time: 30, xp: 450, emoji: '🧀' },
  { id: 'etanol', name: 'Usina de Etanol', input: 'cana', inputQty: 1000, output: 'etanol', outputQty: 80, time: 60, xp: 1500, emoji: '⛽' },
  { id: 'carne_premium', name: 'Corte Premium', input: 'carne', inputQty: 500, output: 'carne_premium', outputQty: 30, time: 90, xp: 4000, emoji: '🥩' },
];

const GLOBAL_EVENTS: Omit<AgroEvent, 'id' | 'expiresAt'>[] = [
  { title: 'Seca no Centro-Oeste', description: 'O Milho e a Soja estão escassos. Preços dispararam!', effect: 'price_up', targetCrop: 'milho', multiplier: 2.5 },
  { title: 'Super-safra de Cana', description: 'Produção recorde derruba preços do Etanol.', effect: 'price_down', targetCrop: 'etanol', multiplier: 0.5 },
  { title: 'Boom da Carne Premium', description: 'Demanda externa aquece o mercado de carnes.', effect: 'price_up', targetCrop: 'carne_premium', multiplier: 1.8 },
  { title: 'Crise dos Citros', description: 'Praga na Laranja aumenta o risco de perda total.', effect: 'risk_up', targetCrop: 'laranja', multiplier: 3.0 },
  { title: 'Acordo com a China', description: 'Exportação de Soja gera bônus de XP massivo.', effect: 'yield_up', targetCrop: 'soja', multiplier: 1.5 },
];

const TITLES = [
  { minLevel: 1, title: 'Pequeno Produtor', color: 'text-zinc-500' },
  { minLevel: 10, title: 'Produtor Familiar', color: 'text-emerald-500' },
  { minLevel: 25, title: 'Fazendeiro Regional', color: 'text-blue-500' },
  { minLevel: 50, title: 'Magnata do Agro', color: 'text-amber-500' },
  { minLevel: 80, title: 'Barão da Soja', color: 'text-rose-500' },
  { minLevel: 100, title: 'Soberano das Terras', color: 'text-white font-black italic animate-pulse' },
];

const AgroBrazil: React.FC<{ currentUser: User }> = ({ currentUser }) => {
  const [isLobby, setIsLobby] = useState(true);
  const [activeTab, setActiveTab] = useState<'fazenda' | 'pecuaria' | 'industria' | 'mercado' | 'exportacao' | 'ranking'>('fazenda');
  const [selectedPlot, setSelectedPlot] = useState<number | null>(null);
  const [selectedPen, setSelectedPen] = useState<number | null>(null);
  const [isProcessing, setIsProcessing] = useState<string | null>(null);
  const [processingProgress, setProcessingProgress] = useState(0);

  const [gameState, setGameState] = useState<AgroGameState>(() => 
    UserDatabase.getAgroState(currentUser.id)
  );

  const currentTitle = useMemo(() => {
    return [...TITLES].reverse().find(t => gameState.level >= t.minLevel) || TITLES[0];
  }, [gameState.level]);

  // Game Loop
  useEffect(() => {
    const interval = setInterval(() => {
      const now = Date.now();
      setGameState(prev => {
        // 1. Atualizar Plantações
        const nextPlots = prev.plots.map(p => {
          if (!p.cropId || !p.plantedAt || p.status === 'locked' || p.status === 'empty' || p.status === 'ready' || p.status.includes('loss')) return p;
          const crop = CROPS.find(c => c.id === p.cropId);
          if (!crop) return p;

          const elapsed = (now - p.plantedAt) / 1000;
          const progress = elapsed / crop.growthTime;

          // Modifier from events
          const riskModifier = prev.activeEvents.filter(e => e.effect === 'risk_up' && e.targetCrop === crop.id).reduce((acc, e) => acc * e.multiplier, 1.0);

          if (progress < 1.0 && Math.random() < (crop.riskFactor * riskModifier) / 1000) {
            const isTotal = Math.random() > 0.7;
            return { ...p, status: isTotal ? 'total_loss' : 'partial_loss', quality: isTotal ? 0 : 0.4 };
          }
          if (progress >= 1.0) return { ...p, status: 'ready' as PlotStatus };
          if (progress > 0.1) return { ...p, status: 'growing' as PlotStatus };
          return p;
        });

        // 2. Mercado Dinâmico (Inflação e Oferta/Demanda)
        const nextMarket = prev.marketPrices.map(mp => {
           // Base variation
           let baseChange = (Math.random() * 0.04) - 0.02; // -2% to +2%

           // Apply events
           const activeEvent = prev.activeEvents.find(e => e.targetCrop === mp.cropId);
           if (activeEvent) {
              if (activeEvent.effect === 'price_up') baseChange += 0.05;
              if (activeEvent.effect === 'price_down') baseChange -= 0.05;
           }

           const newPrice = Math.max(10, Math.floor(mp.price * (1 + baseChange)));
           return { 
              ...mp, 
              price: newPrice, 
              trend: baseChange > 0 ? 'up' as const : 'down' as const 
           };
        });

        // 3. Eventos Aleatórios
        const nextEvents = prev.activeEvents.filter(e => e.expiresAt > now);
        if (nextEvents.length < 2 && Math.random() > 0.995) {
           const evTemplate = GLOBAL_EVENTS[Math.floor(Math.random() * GLOBAL_EVENTS.length)];
           nextEvents.push({
             ...evTemplate,
             id: Math.random().toString(36).substr(2, 5),
             expiresAt: now + (1000 * 60 * 10) // 10 min
           });
        }

        // 4. Contratos Premium
        const nextContracts = (prev.exportContracts || []).filter(c => c.expiresAt > now);
        if (nextContracts.length < 3 && Math.random() > 0.99) {
           const randomCrop = CROPS[Math.floor(Math.random() * CROPS.length)];
           nextContracts.push({
             id: `XPT-${Math.random().toString(36).substr(2, 4).toUpperCase()}`,
             targetItem: randomCrop.id,
             quantity: 2000 + Math.floor(Math.random() * 8000),
             reward: Math.floor(randomCrop.cost * 25),
             premiumReward: Math.random() > 0.8 ? 5 : 0, // Rare AgroGems
             expiresAt: now + (1000 * 60 * 30),
             bonusXp: randomCrop.xp * 12,
             destination: ['Porto de Santos', 'Singapura', 'Hamburgo', 'Los Angeles'][Math.floor(Math.random() * 4)]
           });
        }

        const newState = { 
          ...prev, 
          plots: nextPlots, 
          marketPrices: nextMarket, 
          activeEvents: nextEvents, 
          exportContracts: nextContracts, 
          lastCheck: now 
        };
        UserDatabase.saveAgroState(currentUser.id, newState);
        return newState;
      });
    }, 1000);
    return () => clearInterval(interval);
  }, [currentUser.id]);

  const syncReputation = (xp: number) => {
    const user = UserDatabase.findById(currentUser.id);
    if (user) {
      user.reputation += Math.floor(xp / 15);
      user.xp += xp;
      if (user.xp >= user.level * 2500) { user.level++; user.xp = 0; }
      UserDatabase.updateUser(user);
    }
  };

  const handlePlant = (plotId: number, cropId: string) => {
    const crop = CROPS.find(c => c.id === cropId);
    if (!crop || gameState.credits < crop.cost) return;
    setGameState(prev => ({
      ...prev,
      credits: prev.credits - crop.cost,
      plots: prev.plots.map(p => p.id === plotId ? { ...p, cropId, plantedAt: Date.now(), status: 'planted', quality: 1.0 } : p)
    }));
    setSelectedPlot(null);
  };

  const handleHarvest = (plotId: number) => {
    const plot = gameState.plots.find(p => p.id === plotId);
    if (!plot || !plot.cropId) return;
    const crop = CROPS.find(c => c.id === plot.cropId);
    if (!crop) return;

    const yieldModifier = gameState.activeEvents.filter(e => e.effect === 'yield_up' && e.targetCrop === crop.id).reduce((acc, e) => acc * e.multiplier, 1.0);
    const yieldAmt = Math.floor(crop.baseYield * plot.quality * yieldModifier);

    setGameState(prev => {
      const inv = { ...prev.inventory };
      inv[crop.id] = (inv[crop.id] || 0) + yieldAmt;
      syncReputation(crop.xp);
      return {
        ...prev,
        inventory: inv,
        xp: prev.xp + crop.xp,
        plots: prev.plots.map(p => p.id === plotId ? { ...p, cropId: null, plantedAt: null, status: 'empty', quality: 1.0 } : p)
      };
    });
  };

  const handleSell = (itemId: string, qty: number) => {
    const priceData = gameState.marketPrices.find(p => p.cropId === itemId);
    const stock = gameState.inventory[itemId] || 0;
    if (!priceData || stock < qty) return;

    const tax = 0.05; // 5% fee
    const earning = Math.floor(priceData.price * qty * (1 - tax));

    setGameState(prev => {
      const inv = { ...prev.inventory };
      inv[itemId] -= qty;

      // Dynamic Demand logic: Price drops when someone sells a lot
      const nextMarket = prev.marketPrices.map(mp => {
        if (mp.cropId === itemId) return { ...mp, price: Math.max(10, Math.floor(mp.price * 0.98)) };
        return mp;
      });

      return { ...prev, credits: prev.credits + earning, inventory: inv, marketPrices: nextMarket };
    });
  };

  const handleCompleteExport = (contract: ExportContract) => {
    const stock = gameState.inventory[contract.targetItem] || 0;
    if (stock < contract.quantity) return;

    setGameState(prev => {
      const inv = { ...prev.inventory };
      inv[contract.targetItem] -= contract.quantity;
      syncReputation(contract.bonusXp);
      return {
        ...prev,
        credits: prev.credits + contract.reward,
        premiumCredits: prev.premiumCredits + contract.premiumReward,
        xp: prev.xp + contract.bonusXp,
        inventory: inv,
        exportContracts: prev.exportContracts.filter(c => c.id !== contract.id)
      };
    });
  };

  const handleUseGem = () => {
    if (gameState.premiumCredits < 1) return;
    // Speed up first growing plot found
    setGameState(prev => {
      const target = prev.plots.find(p => p.status === 'growing' || p.status === 'planted');
      if (!target) return prev;
      return {
        ...prev,
        premiumCredits: prev.premiumCredits - 1,
        plots: prev.plots.map(p => p.id === target.id ? { ...p, status: 'ready' as PlotStatus } : p)
      };
    });
  };

  return (
    <div className="h-[calc(100vh-175px)] bg-[#010502] rounded-[4rem] border border-white/5 flex flex-col overflow-hidden shadow-2xl relative">

      {/* HUD Superior Tri-Moeda */}
      <header className="p-8 bg-zinc-950/80 backdrop-blur-3xl border-b border-white/5 flex items-center justify-between relative z-20 shrink-0">
        <div className="flex items-center gap-6">
          <button onClick={() => isLobby ? null : setIsLobby(true)} className="p-4 bg-zinc-900 text-zinc-500 rounded-2xl hover:text-white transition-all"><ChevronLeft size={24}/></button>
          <div className="flex items-center gap-4">
             <div className="w-14 h-14 bg-emerald-500/10 rounded-2xl border border-emerald-500/20 flex items-center justify-center text-emerald-500 shadow-inner">
                <Tractor size={32} />
             </div>
             <div>
                <h2 className="text-xl font-black text-white italic tracking-tighter uppercase leading-none">AGRO <span className="text-emerald-500">BRASIL</span></h2>
                <p className={`text-[10px] font-black uppercase tracking-[0.3em] mt-1.5 ${currentTitle.color}`}>{currentTitle.title}</p>
             </div>
          </div>
        </div>

        <div className="flex items-center gap-6">
           <div className="flex flex-col items-end">
              <div className="flex items-center gap-2">
                 <span className="text-[10px] font-black text-emerald-500 tracking-tighter">R$ {gameState.credits.toLocaleString()}</span>
                 <Wallet size={12} className="text-zinc-600"/>
              </div>
              <div className="flex items-center gap-2">
                 <span className="text-[10px] font-black text-amber-400 tracking-tighter">{gameState.premiumCredits}</span>
                 <Diamond size={12} className="text-amber-400 fill-amber-400/20"/>
              </div>
              <div className="flex items-center gap-2">
                 <span className="text-[10px] font-black text-zinc-500 tracking-tighter">{currentUser.reputation}</span>
                 <Star size={12} className="text-zinc-700"/>
              </div>
           </div>
           <div className="px-5 py-3 bg-zinc-900 rounded-2xl border border-white/5 text-center min-w-[90px]">
              <span className="text-[9px] font-black text-white uppercase tracking-widest block mb-1">NV. {gameState.level}</span>
              <div className="w-full h-1 bg-black rounded-full overflow-hidden">
                <div className="h-full bg-emerald-500" style={{ width: `${(gameState.xp % 2500) / 25}%` }} />
              </div>
           </div>
        </div>
      </header>

      {isLobby ? (
        <div className="flex-1 flex flex-col items-center justify-center p-12 text-center space-y-16 relative z-10 overflow-y-auto scrollbar-hide">
           <div className="relative group">
              <div className="absolute inset-0 bg-emerald-500 blur-[120px] opacity-10 animate-pulse"></div>
              <img src="https://images.unsplash.com/photo-1523348837708-15d4a09cfac2?w=800&h=400&fit=crop" className="w-full max-w-2xl h-80 object-cover rounded-[5rem] border-4 border-emerald-500/20 shadow-2xl relative z-10 group-hover:scale-[1.02] transition-transform duration-1000" />
              <div className="absolute -bottom-6 -right-6 bg-amber-500 text-black p-8 rounded-[3.5rem] shadow-2xl z-20 rotate-12 transition-all group-hover:rotate-0">
                 <Trophy size={48} fill="currentColor" />
              </div>
           </div>

           <div className="space-y-6">
              <h1 className="text-7xl md:text-9xl font-black italic text-white tracking-tighter leading-none">ECONOMIA<br/><span className="text-emerald-500">REAL</span></h1>
              <p className="text-zinc-500 font-bold uppercase tracking-[0.6em] text-[11px] max-w-lg mx-auto leading-relaxed">Gerencie sua fortuna, especule no mercado e torne-se o Soberano do Agronegócio.</p>
           </div>

           <div className="grid grid-cols-3 gap-6 w-full max-w-xl">
              {[
                { label: 'Créditos', icon: Wallet, color: 'text-emerald-500' },
                { label: 'AgroGems', icon: Diamond, color: 'text-amber-400' },
                { label: 'Reputação', icon: Star, color: 'text-zinc-500' }
              ].map((m, i) => (
                <div key={i} className="bg-zinc-900/40 p-6 rounded-[2.5rem] border border-white/5 flex flex-col items-center">
                   <m.icon className={`${m.color} mb-3`} size={24}/>
                   <span className="text-[8px] font-black uppercase text-zinc-600 tracking-widest">{m.label}</span>
                </div>
              ))}
           </div>

           <button onClick={() => setIsLobby(false)} className="w-full max-w-md bg-emerald-500 hover:bg-emerald-400 text-black font-black py-10 rounded-[3.5rem] uppercase tracking-[0.4em] text-sm shadow-2xl shadow-emerald-500/20 active:scale-95 transition-all flex items-center justify-center gap-6">
              Entrar no Mercado <ArrowRight size={24} />
           </button>
        </div>
      ) : (
        <>
          <nav className="flex bg-zinc-950/80 p-2 border-b border-white/5 overflow-x-auto scrollbar-hide relative z-20 shrink-0">
            {[
              { id: 'fazenda', icon: Sprout, label: 'Lavouras' },
              { id: 'pecuaria', icon: Beef, label: 'Pecuária' },
              { id: 'industria', icon: Factory, label: 'Indústria' },
              { id: 'mercado', icon: ShoppingBag, label: 'Bolsa' },
              { id: 'exportacao', icon: Ship, label: 'Internacional' },
              { id: 'ranking', icon: Trophy, label: 'Ranking' }
            ].map(t => (
              <button 
                key={t.id} 
                onClick={() => setActiveTab(t.id as any)} 
                className={`flex-1 min-w-[120px] py-5 rounded-[2rem] text-[9px] font-black uppercase tracking-widest flex items-center justify-center gap-2.5 transition-all ${activeTab === t.id ? 'bg-emerald-500 text-black shadow-xl' : 'text-zinc-600 hover:text-zinc-400'}`}
              >
                <t.icon size={18}/> {t.label}
              </button>
            ))}
          </nav>

          {/* Banner de Eventos Globais */}
          {gameState.activeEvents.length > 0 && (
            <div className="bg-rose-500/10 border-b border-rose-500/20 p-4 flex items-center gap-4 overflow-x-auto scrollbar-hide shrink-0 z-10">
               {gameState.activeEvents.map(ev => (
                 <div key={ev.id} className="flex-none bg-rose-500 text-white px-6 py-2 rounded-full text-[9px] font-black uppercase flex items-center gap-3 shadow-lg animate-in slide-in-from-right duration-500">
                    <AlertCircle size={14} />
                    <span>{ev.title}: {ev.description}</span>
                    <div className="w-px h-3 bg-white/20"></div>
                    <span className="opacity-70">{Math.floor((ev.expiresAt - Date.now()) / 60000)}m</span>
                 </div>
               ))}
            </div>
          )}

          <main className="flex-1 overflow-y-auto p-10 scrollbar-hide relative z-10">

            {/* Lavouras */}
            {activeTab === 'fazenda' && (
              <div className="space-y-10">
                <div className="grid grid-cols-4 gap-6 perspective-[2000px] py-10">
                  {gameState.plots.map((plot) => {
                    const crop = plot.cropId ? CROPS.find(c => c.id === plot.cropId) : null;
                    const isReady = plot.status === 'ready';
                    const isGrowing = plot.status === 'growing' || plot.status === 'planted';

                    return (
                      <div 
                        key={plot.id}
                        onClick={() => !crop ? setSelectedPlot(plot.id) : isReady && handleHarvest(plot.id)}
                        className={`
                          aspect-square rounded-[3.5rem] border-2 flex items-center justify-center relative cursor-pointer transition-all duration-700
                          transform hover:-translate-y-4 hover:shadow-2xl
                          ${plot.status === 'locked' ? 'opacity-20 bg-black border-zinc-900' : 'bg-zinc-900/40 border-white/5 hover:border-emerald-500/40 shadow-xl'}
                          ${isReady ? 'border-emerald-500 bg-emerald-500/10 shadow-[0_0_50px_rgba(16,185,129,0.1)]' : ''}
                        `}
                        style={{ transform: 'rotateX(40deg) rotateZ(-15deg)' }}
                      >
                        {plot.status === 'locked' ? <Lock className="text-zinc-800"/> : (
                          <div className="relative z-10 flex flex-col items-center gap-3">
                             {crop ? (
                                <>
                                   <span className={`text-6xl drop-shadow-2xl transition-transform duration-700 ${isReady ? 'scale-125' : ''}`}>
                                      {crop.emoji}
                                   </span>
                                   {isGrowing && (
                                     <div className="absolute inset-x-[-10px] bottom-[-20px] h-2 bg-black/40 rounded-full overflow-hidden">
                                        <div className="h-full bg-emerald-500 animate-pulse" style={{ width: '40%' }} />
                                     </div>
                                   )}
                                   {isReady && <div className="absolute -top-10 bg-emerald-500 text-black px-4 py-1.5 rounded-full text-[8px] font-black uppercase shadow-2xl animate-bounce">Colher</div>}
                                </>
                             ) : <Plus className="text-zinc-800" size={32} />}
                          </div>
                        )}
                      </div>
                    );
                  })}
                </div>

                <div className="flex justify-center">
                  <button 
                    onClick={handleUseGem}
                    disabled={gameState.premiumCredits < 1}
                    className="bg-amber-400 text-black font-black px-10 py-5 rounded-[2.5rem] flex items-center gap-4 shadow-xl hover:bg-amber-300 disabled:opacity-30 transition-all uppercase tracking-widest text-xs"
                  >
                    <Diamond size={20} fill="currentColor"/> ACELERAR COLOHEITA (1 💎)
                  </button>
                </div>
              </div>
            )}

            {/* Mercado Bolsa de Mercadorias */}
            {activeTab === 'mercado' && (
              <div className="space-y-12 animate-in fade-in duration-700 pb-10">
                <div className="bg-zinc-900 border border-white/5 rounded-[4rem] p-12 flex flex-col md:flex-row items-center justify-between gap-10 shadow-2xl relative overflow-hidden">
                   <div className="absolute top-0 right-0 p-12 opacity-5"><BarChart3 size={200} /></div>
                   <div className="flex items-center gap-10 relative z-10">
                      <div className="w-24 h-24 bg-emerald-500 rounded-[3rem] flex items-center justify-center text-black shadow-2xl">
                         <BarChart3 size={48} />
                      </div>
                      <div>
                         <h3 className="text-5xl font-black italic text-white tracking-tighter uppercase leading-none">BOLSA DE <span className="text-emerald-500">VALORES AGRO</span></h3>
                         <p className="text-[11px] font-black text-zinc-500 uppercase tracking-[0.4em] mt-3">Preços dinâmicos baseados em oferta e demanda</p>
                      </div>
                   </div>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
                  {gameState.marketPrices.map(price => {
                    const stock = gameState.inventory[price.cropId] || 0;
                    const event = gameState.activeEvents.find(e => e.targetCrop === price.cropId);

                    return (
                      <div key={price.cropId} className={`bg-zinc-900/60 border-2 p-10 rounded-[4rem] flex flex-col gap-8 group transition-all duration-500 shadow-2xl relative overflow-hidden ${event ? 'border-rose-500/40 bg-rose-500/5' : 'border-white/5 hover:border-emerald-500/20'}`}>
                        {event && <div className="absolute top-4 right-4 text-rose-500 animate-pulse"><AlertCircle size={20} /></div>}

                        <div className="flex justify-between items-center relative z-10">
                          <div className="w-20 h-20 bg-zinc-950 rounded-[2.5rem] flex items-center justify-center text-5xl shadow-xl border border-white/5">
                            {price.cropId === 'ovos' ? '🥚' : price.cropId === 'carne_premium' ? '🥩' : price.cropId === 'cafe' ? '☕' : price.cropId === 'soja' ? '🌱' : price.cropId === 'cana' ? '🎋' : price.cropId === 'etanol' ? '⛽' : '📦'}
                          </div>
                          <div className={`flex items-center gap-2 px-5 py-2.5 rounded-full text-[10px] font-black uppercase ${price.trend === 'up' ? 'bg-emerald-500/10 text-emerald-500 border border-emerald-500/20' : 'bg-rose-500/10 text-rose-500 border border-rose-500/20'}`}>
                            {price.trend === 'up' ? <TrendingUp size={16}/> : <TrendingDown size={16}/>} {price.trend === 'up' ? 'Alta' : 'Baixa'}
                          </div>
                        </div>

                        <div className="relative z-10">
                          <h4 className="text-[12px] font-black uppercase text-zinc-600 tracking-[0.4em] mb-1">{price.cropId.replace('_', ' ')}</h4>
                          <p className="text-4xl font-black text-white tracking-tighter leading-none flex items-baseline gap-2">
                             R$ {price.price}
                             <span className="text-zinc-700 text-[10px] font-black uppercase tracking-widest">Preço de Fechamento</span>
                          </p>
                        </div>

                        <div className="flex items-center justify-between p-6 bg-black/40 rounded-[2.5rem] border border-white/5 relative z-10">
                           <span className="text-[11px] font-black text-zinc-500 uppercase tracking-widest">Disponível</span>
                           <span className="text-3xl font-black text-emerald-500">{stock}</span>
                        </div>

                        <div className="grid grid-cols-2 gap-4 pt-2 relative z-10">
