const AgroBrazil: React.FC<{ currentUser: User }> = ({ currentUser }) => {
  const [isLobby, setIsLobby] = useState(true);
  const [activeTab, setActiveTab] = useState<'fazenda' | 'pecuaria' | 'industria' | 'mercado' | 'exportacao' | 'ranking'>('fazenda');
  const [selectedPlot, setSelectedPlot] = useState<number | null>(null);
  const [selectedPen, setSelectedPen] = useState<number | null>(null);
  const [isProcessing, setIsProcessing] = useState<string | null>(null);
  const [processingProgress, setProcessingProgress] = useState(0);

  const [gameState, setGameState] = useState<AgroGameState>(() => 
    UserDatabase.getAgroState(currentUser.id)
  );

  const currentTitle = useMemo(() => {
    return [...TITLES].reverse().find(t => gameState.level >= t.minLevel) || TITLES[0];
  }, [gameState.level]);

  // Game Loop
  useEffect(() => {
    const interval = setInterval(() => {
      const now = Date.now();
      setGameState(prev => {
        // 1. Atualizar Plantações
        const nextPlots = prev.plots.map(p => {
          if (!p.cropId || !p.plantedAt || p.status === 'locked' || p.status === 'empty' || p.status === 'ready' || p.status.includes('loss')) return p;
          const crop = CROPS.find(c => c.id === p.cropId);
          if (!crop) return p;

          const elapsed = (now - p.plantedAt) / 1000;
          const progress = elapsed / crop.growthTime;

          // Eventos Climáticos
          if (progress < 1.0 && Math.random() < crop.riskFactor / 1000) {
             const type = Math.random() > 0.7 ? 'total_loss' : 'partial_loss';
             return { ...p, status: type as PlotStatus, quality: type === 'total_loss' ? 0 : 0.4 };
          }

          if (progress >= 1.0) return { ...p, status: 'ready' as PlotStatus };
          if (progress > 0.1) return { ...p, status: 'growing' as PlotStatus };
          return p;
        });

        // 2. Mercado Dinâmico (Inflação e Oferta/Demanda)
        const nextMarket = prev.marketPrices.map(mp => {
           let baseChange = (Math.random() * 0.02) - 0.01; // -1% to +1%
           // Simular Inflação Controlada
           baseChange += 0.001; 

           const activeEvent = prev.activeEvents.find(e => e.targetCrop === mp.cropId);
           if (activeEvent) {
             if (activeEvent.effect === 'price_up') baseChange += 0.05;
             if (activeEvent.effect === 'price_down') baseChange -= 0.05;
           }

           const newPrice = Math.max(10, Math.floor(mp.price * (1 + baseChange)));
           return { ...mp, price: newPrice, trend: baseChange > 0 ? 'up' as const : 'down' as const };
        });

        // 3. Eventos Mundiais
        const nextEvents = prev.activeEvents.filter(e => e.expiresAt > now);
        if (nextEvents.length < 2 && Math.random() > 0.99) {
           const template = GLOBAL_EVENTS[Math.floor(Math.random() * GLOBAL_EVENTS.length)];
           nextEvents.push({
             ...template,
             id: Math.random().toString(36).substr(2, 5),
             expiresAt: now + (1000 * 60 * 10) // 10 min
           });
        }

        // 4. Exportação Internacional (Exige volume e dá Premium)
        const nextContracts = (prev.exportContracts || []).filter(c => c.expiresAt > now);
        if (nextContracts.length < 3 && Math.random() > 0.98) {
           const randomCrop = CROPS[Math.floor(Math.random() * CROPS.length)];
           nextContracts.push({
             id: `EXP-${Math.random().toString(36).substr(2, 4).toUpperCase()}`,
             targetItem: randomCrop.id,
             quantity: 500 + Math.floor(Math.random() * 2000),
             reward: Math.floor(randomCrop.cost * 15),
             premiumReward: Math.random() > 0.8 ? 5 : 0, // Rare gems
             expiresAt: now + (1000 * 60 * 20),
             bonusXp: randomCrop.xp * 10,
             destination: ['Xangai', 'Roterdã', 'Porto de Santos', 'Singapura'][Math.floor(Math.random() * 4)]
           });
        }

        const newState = { 
          ...prev, 
          plots: nextPlots, 
          marketPrices: nextMarket, 
          activeEvents: nextEvents,
          exportContracts: nextContracts,
          lastCheck: now 
        };
        UserDatabase.saveAgroState(currentUser.id, newState);
        return newState;
      });
    }, 1000);
    return () => clearInterval(interval);
  }, [currentUser.id]);

  const syncReputation = (xp: number) => {
    const user = UserDatabase.findById(currentUser.id);
    if (user) {
      user.reputation += Math.floor(xp / 20);
      user.xp += xp;
      if (user.xp >= user.level * 3000) { user.level++; user.xp = 0; }
      UserDatabase.updateUser(user);
    }
  };

  const handlePlant = (plotId: number, cropId: string) => {
    const crop = CROPS.find(c => c.id === cropId);
    if (!crop || gameState.credits < crop.cost) return;
    setGameState(prev => ({
      ...prev,
      credits: prev.credits - crop.cost,
      plots: prev.plots.map(p => p.id === plotId ? { ...p, cropId, plantedAt: Date.now(), status: 'planted', quality: 1.0 } : p)
    }));
    setSelectedPlot(null);
  };

  const handleHarvest = (plotId: number) => {
    const plot = gameState.plots.find(p => p.id === plotId);
    if (!plot || !plot.cropId) return;
    const crop = CROPS.find(c => c.id === plot.cropId);
    if (!crop) return;
    const yieldAmt = Math.floor(crop.baseYield * plot.quality);
    setGameState(prev => {
      const inv = { ...prev.inventory };
      inv[crop.id] = (inv[crop.id] || 0) + yieldAmt;
      syncReputation(crop.xp);
      return {
        ...prev,
        inventory: inv,
        xp: prev.xp + crop.xp,
        plots: prev.plots.map(p => p.id === plotId ? { ...p, cropId: null, plantedAt: null, status: 'empty', quality: 1.0 } : p)
      };
    });
  };

  const handleSell = (itemId: string, qty: number) => {
    const priceData = gameState.marketPrices.find(p => p.cropId === itemId);
    const stock = gameState.inventory[itemId] || 0;
    if (!priceData || stock < qty) return;

    const tax = 0.05; // 5% fee
    const earning = Math.floor(priceData.price * qty * (1 - tax));

    setGameState(prev => {
      const inv = { ...prev.inventory };
      inv[itemId] -= qty;
      return { ...prev, credits: prev.credits + earning, inventory: inv };
    });
  };

  const handleProcess = (recipeId: string) => {
    const recipe = INDUSTRY_RECIPES.find(r => r.id === recipeId);
    if (!recipe || (gameState.inventory[recipe.input] || 0) < recipe.inputQty || isProcessing) return;

    setIsProcessing(recipeId);
    setProcessingProgress(0);

    let prog = 0;
    const interval = setInterval(() => {
      prog += 100 / (recipe.time * 10);
      if (prog >= 100) {
        clearInterval(interval);
        setGameState(prev => {
          const inv = { ...prev.inventory };
          inv[recipe.input] -= recipe.inputQty;
          inv[recipe.output] = (inv[recipe.output] || 0) + recipe.outputQty;
          syncReputation(recipe.xp);
          return { ...prev, inventory: inv, xp: prev.xp + recipe.xp };
        });
        setIsProcessing(null);
        setProcessingProgress(0);
      } else {
        setProcessingProgress(prog);
      }
    }, 100);
  };

  return (
    <div className="h-[calc(100vh-175px)] bg-[#010502] rounded-[3.5rem] border border-white/5 flex flex-col overflow-hidden shadow-2xl relative">

      {/* Background Decor */}
      <div className="absolute top-0 left-0 w-full h-full pointer-events-none opacity-5">
        <div className="absolute top-[-10%] left-[-10%] w-[60%] h-[60%] bg-emerald-500 blur-[150px] rounded-full"></div>
        <div className="absolute bottom-[-10%] right-[-10%] w-[60%] h-[60%] bg-amber-500 blur-[150px] rounded-full"></div>
      </div>

      <header className="p-8 bg-zinc-950/60 backdrop-blur-3xl border-b border-white/5 flex items-center justify-between relative z-20 shrink-0">
        <div className="flex items-center gap-6">
          <button onClick={() => isLobby ? null : setIsLobby(true)} className="p-4 bg-zinc-900 text-zinc-500 rounded-2xl hover:text-white transition-all"><ChevronLeft size={24}/></button>
          <div className="flex items-center gap-4">
             <div className="relative">
                <div className="w-14 h-14 bg-emerald-500/10 rounded-2xl border border-emerald-500/20 flex items-center justify-center text-emerald-500">
                   <Tractor size={32} />
                </div>
                <div className="absolute -bottom-1 -right-1 bg-emerald-500 text-black p-0.5 rounded-lg border-2 border-black"><CheckCircle2 size={12}/></div>
             </div>
             <div>
                <h2 className="text-xl font-black text-white italic tracking-tighter uppercase leading-none">AGRO <span className="text-emerald-500">BRASIL</span></h2>
                <p className={`text-[9px] font-black uppercase tracking-widest mt-1.5 ${currentTitle.color}`}>{currentTitle.title}</p>
             </div>
          </div>
        </div>

        <div className="flex items-center gap-8">
           <div className="flex flex-col items-end">
              <div className="flex items-center gap-2">
                 <span className="text-[10px] font-black text-emerald-500 tracking-tighter">R$ {gameState.credits.toLocaleString()}</span>
                 <Wallet size={12} className="text-zinc-600"/>
              </div>
              <div className="flex items-center gap-2">
                 <span className="text-[10px] font-black text-amber-400 tracking-tighter">{gameState.premiumCredits}</span>
                 <Diamond size={12} className="text-amber-400 fill-amber-400/20"/>
              </div>
              <div className="flex items-center gap-2">
                 <span className="text-[10px] font-black text-zinc-500 tracking-tighter">{currentUser.reputation}</span>
                 <Star size={12} className="text-zinc-700"/>
              </div>
           </div>
           <div className="px-5 py-3 bg-zinc-900 rounded-2xl border border-white/5 text-center min-w-[90px]">
              <span className="text-[9px] font-black text-white uppercase tracking-widest block mb-1">NV. {gameState.level}</span>
              <div className="w-full h-1 bg-black rounded-full overflow-hidden">
                <div className="h-full bg-emerald-500" style={{ width: `${(gameState.xp % 3000) / 30}%` }} />
              </div>
           </div>
        </div>
      </header>

      {isLobby ? (
        <div className="flex-1 flex flex-col items-center justify-center p-12 text-center space-y-16 relative z-10 overflow-y-auto scrollbar-hide">
           <div className="relative group">
              <div className="absolute inset-0 bg-emerald-500 blur-[120px] opacity-10 animate-pulse"></div>
              <img src="https://images.unsplash.com/photo-1523348837708-15d4a09cfac2?w=800&h=400&fit=crop" className="w-full max-w-2xl h-80 object-cover rounded-[5rem] border-4 border-emerald-500/20 shadow-2xl relative z-10 group-hover:scale-[1.02] transition-transform duration-1000" />
              <div className="absolute -bottom-6 -right-6 bg-amber-500 text-black p-8 rounded-[3.5rem] shadow-2xl z-20 rotate-12 transition-all group-hover:rotate-0">
                 <Trophy size={48} fill="currentColor" />
              </div>
           </div>

           <div className="space-y-6">
              <h1 className="text-7xl md:text-9xl font-black italic text-white tracking-tighter leading-none">ECONOMIA<br/><span className="text-emerald-500">SOBERANA</span></h1>
              <p className="text-zinc-500 font-bold uppercase tracking-[0.6em] text-[11px] max-w-lg mx-auto leading-relaxed">Produza ativos reais, especule no mercado cooperativo e lidere a economia da TRIBO.</p>
           </div>

           <button onClick={() => setIsLobby(false)} className="w-full max-w-md bg-emerald-500 hover:bg-emerald-400 text-black font-black py-10 rounded-[3.5rem] uppercase tracking-[0.3em] text-sm shadow-2xl shadow-emerald-500/20 active:scale-95 transition-all flex items-center justify-center gap-6">
              Assumir Território <ArrowRight size={24} />
           </button>
        </div>
      ) : (
        <>
          <nav className="flex bg-zinc-950/80 p-2 border-b border-white/5 overflow-x-auto scrollbar-hide relative z-10 shrink-0">
            {[
              { id: 'fazenda', icon: Sprout, label: 'Lavouras' },
              { id: 'pecuaria', icon: Beef, label: 'Pecuária' },
              { id: 'industria', icon: Factory, label: 'Indústria' },
              { id: 'mercado', icon: ShoppingBag, label: 'Mercado' },
              { id: 'exportacao', icon: Ship, label: 'Internacional' },
              { id: 'ranking', icon: Trophy, label: 'Elite' }
            ].map(t => (
              <button 
                key={t.id} 
                onClick={() => setActiveTab(t.id as any)} 
                className={`flex-1 min-w-[110px] py-5 rounded-[2rem] text-[9px] font-black uppercase tracking-widest flex items-center justify-center gap-2.5 transition-all ${activeTab === t.id ? 'bg-emerald-500 text-black shadow-xl' : 'text-zinc-600 hover:text-zinc-400'}`}
              >
                <t.icon size={18}/> {t.label}
              </button>
            ))}
          </nav>

          {/* Banner de Eventos */}
          {gameState.activeEvents.length > 0 && (
            <div className="bg-rose-500/10 border-b border-rose-500/20 p-4 flex items-center gap-4 overflow-x-auto scrollbar-hide shrink-0 z-10">
               {gameState.activeEvents.map(ev => (
                 <div key={ev.id} className="flex-none bg-rose-500 text-white px-6 py-2 rounded-full text-[9px] font-black uppercase flex items-center gap-3 shadow-lg animate-in slide-in-from-right duration-500">
                    <AlertCircle size={14} />
                    <span>{ev.title}: {ev.description}</span>
                    <div className="w-px h-3 bg-white/20"></div>
                    <span className="opacity-70">{Math.floor((ev.expiresAt - Date.now()) / 60000)}m</span>
                 </div>
               ))}
            </div>
          )}

          <main className="flex-1 overflow-y-auto p-10 scrollbar-hide relative z-10">

            {/* Mercado Bolsa de Valores */}
            {activeTab === 'mercado' && (
              <div className="space-y-12 animate-in slide-in-from-bottom-10 duration-700 pb-10">
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
                  {gameState.marketPrices.map(price => {
                    const stock = gameState.inventory[price.cropId] || 0;
                    return (
                      <div key={price.cropId} className="bg-zinc-900/60 border border-white/5 p-10 rounded-[4rem] flex flex-col gap-8 group hover:border-emerald-500/20 transition-all shadow-2xl relative overflow-hidden">
                        <div className="flex justify-between items-center relative z-10">
                          <div className="w-20 h-20 bg-zinc-950 rounded-[2.5rem] flex items-center justify-center text-5xl shadow-xl">
                            {price.cropId === 'ovos' ? '🥚' : price.cropId === 'milho' ? '🌽' : price.cropId === 'soja' ? '🌱' : price.cropId === 'carne_premium' ? '🥩' : price.cropId === 'queijo_especial' ? '🧀' : '📦'}
                          </div>
                          <div className={`flex items-center gap-2 px-5 py-2.5 rounded-full text-[10px] font-black uppercase ${price.trend === 'up' ? 'bg-emerald-500/10 text-emerald-500 border border-emerald-500/20' : 'bg-rose-500/10 text-rose-500 border border-rose-500/20'}`}>
                            {price.trend === 'up' ? <TrendingUp size={16}/> : <TrendingDown size={16}/>} {price.trend === 'up' ? 'Alta' : 'Baixa'}
                          </div>
                        </div>

                        <div className="relative z-10">
                          <h4 className="text-[12px] font-black uppercase text-zinc-600 tracking-[0.4em] mb-1">{price.cropId.replace('_', ' ')}</h4>
                          <p className="text-4xl font-black text-white tracking-tighter leading-none flex items-baseline gap-2">
                             R$ {price.price}
                             <span className="text-zinc-700 text-[10px] font-black uppercase tracking-widest">Valor de Mercado</span>
                          </p>
                        </div>

                        <div className="flex items-center justify-between p-6 bg-black/40 rounded-[2.5rem] border border-white/5 relative z-10">
                           <span className="text-[11px] font-black text-zinc-500 uppercase tracking-widest">Em Depósito</span>
                           <span className="text-3xl font-black text-emerald-500">{stock}</span>
                        </div>

                        <div className="grid grid-cols-2 gap-4 pt-2 relative z-10">
                           <button onClick={() => handleSell(price.cropId, 100)} disabled={stock < 100} className="py-5 bg-zinc-800 hover:bg-emerald-500 hover:text-black rounded-[1.8rem] text-[10px] font-black uppercase tracking-widest transition-all active:scale-95 disabled:opacity-10">Liquidar 100</button>
                           <button onClick={() => handleSell(price.cropId, stock)} disabled={stock === 0} className="py-5 bg-emerald-500 text-black rounded-[1.8rem] text-[10px] font-black uppercase tracking-widest shadow-2xl hover:bg-emerald-400 transition-all active:scale-95 disabled:opacity-10">Vender Tudo</button>
                        </div>

                        <div className="mt-4 pt-4 border-t border-white/5 flex justify-between text-[9px] font-black text-zinc-700 uppercase tracking-widest">
                           <span>Taxa de Venda: 5%</span>
                           <span>Inflação Estimada: 1.2% p.m.</span>
                        </div>
                      </div>
                    );
                  })}
                </div>
              </div>
            )}

            {/* Indústria de Transformação */}
            {activeTab === 'industria' && (
              <div className="grid grid-cols-1 md:grid-cols-2 gap-10 pb-10">
                 {INDUSTRY_RECIPES.map(recipe => {
                    const stock = gameState.inventory[recipe.input] || 0;
                    const hasItems = stock >= recipe.inputQty;
                    const active = isProcessing === recipe.id;

                    return (
                      <div key={recipe.id} className={`p-12 rounded-[4.5rem] border-4 flex flex-col gap-10 transition-all relative overflow-hidden shadow-2xl ${active ? 'border-emerald-500 bg-emerald-500/5' : 'border-white/5 bg-zinc-900/60'}`}>
                         <div className="flex justify-between items-start relative z-10">
                            <div className="flex items-center gap-8">
                               <div className="w-24 h-24 bg-zinc-950 rounded-[3rem] flex items-center justify-center text-6xl shadow-inner border border-white/5">
                                  {recipe.emoji}
                               </div>
                               <div>
                                  <h4 className="text-3xl font-black text-white tracking-tighter uppercase leading-tight">{recipe.name}</h4>
                                  <div className="flex items-center gap-4 mt-2">
                                     <span className="text-[10px] font-black text-emerald-500 uppercase flex items-center gap-1.5"><Zap size={12} fill="currentColor"/> +{recipe.xp} XP</span>
                                     <span className="text-[10px] font-black text-zinc-500 uppercase flex items-center gap-1.5"><History size={12}/> {recipe.time}s</span>
                                  </div>
                               </div>
                            </div>
                            <div className="text-right">
                               <span className="text-[10px] font-black text-zinc-600 uppercase tracking-widest">Requer</span>
                               <p className={`text-2xl font-black tracking-tighter ${hasItems ? 'text-emerald-500' : 'text-rose-500'}`}>{recipe.inputQty} {recipe.input}</p>
                            </div>
                         </div>

                         {active ? (
                           <div className="space-y-5 relative z-10">
                              <div className="flex justify-between text-[11px] font-black uppercase text-emerald-500 tracking-[0.3em]"><span>Processando...</span><span>{Math.floor(processingProgress)}%</span></div>
                              <div className="w-full h-5 bg-black rounded-full overflow-hidden border border-emerald-500/20 shadow-inner">
                                 <div className="h-full bg-emerald-500 shadow-[0_0_20px_rgba(16,185,129,0.5)] transition-all duration-100" style={{ width: `${processingProgress}%` }}></div>
                              </div>
                           </div>
                         ) : (
                           <button 
                             onClick={() => handleProcess(recipe.id)}
                             disabled={!hasItems || !!isProcessing}
                             className={`w-full py-8 rounded-[2.5rem] font-black uppercase tracking-[0.3em] text-xs transition-all relative z-10 ${hasItems && !isProcessing ? 'bg-emerald-500 text-black shadow-2xl hover:bg-emerald-400 active:scale-95' : 'bg-zinc-800 text-zinc-600 cursor-not-allowed opacity-40'}`}
                           >
                             {isProcessing ? 'Linha Ocupada' : hasItems ? 'Iniciar Transformação' : `Estoque Insuficiente (${stock})`}
                           </button>
                         )}
                      </div>
                    );
                 })}
              </div>
            )}

            {/* Outras Abas (Simplificadas para o contexto) */}
            {activeTab === 'fazenda' && (
              <div className="grid grid-cols-4 gap-6 perspective-[2000px] py-10">
                {gameState.plots.map((plot) => {
                  const crop = plot.cropId ? CROPS.find(c => c.id === plot.cropId) : null;
                  const isReady = plot.status === 'ready';
                  const isGrowing = plot.status === 'growing' || plot.status === 'planted';

                  return (
                    <div 
                      key={plot.id}
                      onClick={() => !crop ? setSelectedPlot(plot.id) : isReady && handleHarvest(plot.id)}
                      className={`
                        aspect-square rounded-[3rem] border-2 flex items-center justify-center relative cursor-pointer transition-all duration-700
                        transform hover:-translate-y-4 hover:shadow-2xl
                        ${plot.status === 'locked' ? 'opacity-20 bg-black border-zinc-900 cursor-not-allowed' : 'bg-zinc-900/40 border-white/5 hover:border-emerald-500/40 shadow-xl'}
                        ${isReady ? 'border-emerald-500 bg-emerald-500/10 shadow-[0_0_40px_rgba(16,185,129,0.1)]' : ''}
                      `}
                      style={{ transform: 'rotateX(45deg) rotateZ(-15deg)' }}
                    >
                      {plot.status === 'locked' ? <Lock className="text-zinc-800"/> : (
                        <div className="relative z-10 flex flex-col items-center gap-3">
                           {crop ? (
                              <>
                                 <span className={`text-6xl drop-shadow-2xl transition-transform duration-700 ${isReady ? 'scale-125' : ''}`}>
                                    {crop.emoji}
                                 </span>
                                 {isGrowing && (
                                   <div className="absolute inset-x-[-10px] bottom-[-20px] h-2 bg-black/40 rounded-full overflow-hidden border border-white/5">
                                      <div className="h-full bg-emerald-500 animate-pulse" style={{ width: '40%' }} />
                                   </div>
                                 )}
                                 {isReady && <div className="absolute -top-10 bg-emerald-500 text-black px-4 py-1.5 rounded-full text-[8px] font-black uppercase tracking-widest shadow-2xl animate-bounce">Pronto!</div>}
                              </>
                           ) : <Plus className="text-zinc-800 group-hover:text-emerald-500" size={32} />}
                        </div>
                      )}
                    </div>
                  );
                })}
              </div>
            )}

            {/* Exportação Internacional Premium */}
            {activeTab === 'exportacao' && (
              <div className="grid grid-cols-1 md:grid-cols-2 gap-10 pb-10">
                {(gameState.exportContracts || []).map(contract => {
                   const stock = gameState.inventory[contract.targetItem] || 0;
                   const hasItems = stock >= contract.quantity;

                   return (
                     <div key={contract.id} className="bg-zinc-900 border-2 border-blue-500/20 p-12 rounded-[5rem] flex flex-col gap-10 shadow-2xl relative overflow-hidden group">
                        <div className="absolute top-0 right-0 p-12 opacity-5 group-hover:opacity-10 transition-opacity"><Ship size={150} /></div>

                        <div className="flex justify-between items-start relative z-10">
                           <div className="flex items-center gap-10">
                              <div className="w-24 h-24 bg-blue-500 rounded-[3rem] flex items-center justify-center text-6xl text-white shadow-2xl">
                                <Ship size={48} />
                              </div>
                              <div>
                                 <h4 className="text-4xl font-black text-white italic tracking-tighter uppercase">{contract.id}</h4>
                                 <p className="text-[11px] font-black text-blue-400 uppercase tracking-[0.3em] mt-2 flex items-center gap-2"><Anchor size={14}/> Porto: {contract.destination}</p>
                              </div>
                           </div>
                        </div>

                        <div className="space-y-6 relative z-10">
                           <div className="flex justify-between items-end">
                              <div className="flex flex-col">
                                 <span className="text-[10px] font-black text-zinc-600 uppercase tracking-widest mb-1">Pagamento (R$)</span>
                                 <span className="text-4xl font-black text-emerald-500 tracking-tighter">R$ {contract.reward.toLocaleString()}</span>
                                 {contract.premiumReward > 0 && <span className="text-amber-400 font-black text-sm mt-1 flex items-center gap-1">+{contract.premiumReward} <Diamond size={12} fill="currentColor"/> AgroGems</span>}
                              </div>
                              <div className="text-right">
                                 <span className="text-[10px] font-black text-zinc-600 uppercase tracking-widest">Carga</span>
                                 <p className={`text-xl font-black ${hasItems ? 'text-emerald-500' : 'text-blue-500'}`}>{stock} / {contract.quantity}</p>
                              </div>
                           </div>
                           <div className="w-full h-4 bg-black rounded-full overflow-hidden border border-blue-500/10 shadow-inner">
                              <div className={`h-full transition-all duration-1000 ${hasItems ? 'bg-emerald-500 shadow-[0_0_15px_rgba(16,185,129,0.5)]' : 'bg-blue-500'}`} style={{ width: `${Math.min(100, (stock / contract.quantity) * 100)}%` }} />
                           </div>
                        </div>

                        <button className={`w-full py-8 rounded-[2.5rem] font-black uppercase tracking-[0.4em] text-xs transition-all relative z-10 ${hasItems ? 'bg-blue-500 text-white shadow-2xl hover:scale-105 active:scale-95' : 'bg-zinc-800 text-zinc-600 cursor-not-allowed opacity-30'}`}>
                           {hasItems ? 'DESPACHAR CARGA INTERNACIONAL' : 'VOLUME MÍNIMO NÃO ATINGIDO'}
                        </button>
                     </div>
                   );
                })}
              </div>
            )}

            {/* Ranking de Soberanos */}
            {activeTab === 'ranking' && (
              <div className="max-w-4xl mx-auto space-y-12 pb-10">
                 <div className="bg-amber-400/5 border border-amber-400/20 p-16 rounded-[6rem] text-center space-y-8 relative overflow-hidden shadow-[0_0_100px_rgba(251,191,36,0.05)]">
                    <Trophy size={100} className="text-amber-400 mx-auto drop-shadow-[0_0_40px_rgba(251,191,36,0.3)] animate-pulse" />
                    <div>
                       <h3 className="text-6xl font-black italic tracking-tighter text-white uppercase leading-none">OS <span className="text-amber-400">SOBERANOS</span></h3>
                       <p className="text-[12px] font-black text-zinc-500 uppercase tracking-[0.5em] mt-4">A elite agroindustrial da rede TRIBO</p>
                    </div>
                 </div>

                 <div className="space-y-6">
                    {[
                      { name: 'Admin SOBERANO', credits: 999999999, rep: 9999, title: 'Rei do Agro', avatar: 'https://images.unsplash.com/photo-1535713875002-d1d0cf377fde?w=100' },
                      { name: currentUser.name, credits: gameState.credits, rep: currentUser.reputation, title: currentTitle.title, avatar: currentUser.avatar },
                    ].sort((a,b) => b.credits - a.credits).map((p, i) => (
                      <div key={i} className={`p-10 rounded-[4rem] border-2 flex items-center justify-between transition-all duration-500 ${p.name === currentUser.name ? 'bg-emerald-500 text-black border-emerald-500 shadow-2xl scale-[1.05]' : 'bg-zinc-900/40 border-white/5 text-white'}`}>
                         <div className="flex items-center gap-10">
                            <div className="font-black italic text-5xl w-14 opacity-40">#{i+1}</div>
                            <img src={p.avatar} className="w-24 h-24 rounded-[2.5rem] border-4 border-white/10 shadow-2xl object-cover" />
                            <div>
                               <p className="font-black text-3xl tracking-tighter">{p.name}</p>
                               <p className={`text-[11px] font-black uppercase tracking-widest mt-1 opacity-80`}>{p.title}</p>
                            </div>
                         </div>
                         <div className="text-right">
                            <p className="font-black text-3xl tracking-tighter">R$ {p.credits.toLocaleString()}</p>
                            <p className="text-[10px] font-black uppercase opacity-60 tracking-[0.2em] mt-1 flex items-center justify-end gap-2">⭐ {p.rep} Pontos de Prestígio</p>
                         </div>
                      </div>
                    ))}
                 </div>
              </div>
            )}

          </main>
        </>
      )}

      {/* Modais de Escolha */}
      {selectedPlot !== null && (
        <div className="fixed inset-0 z-[300] bg-black/98 backdrop-blur-3xl flex items-center justify-center p-8 animate-in fade-in duration-300">
           <div className="w-full max-w-4xl bg-[#0a0a0a] border border-white/10 rounded-[6rem] overflow-hidden shadow-2xl animate-in zoom-in-95 duration-500">
              <div className="p-16 border-b border-white/5 flex justify-between items-center bg-zinc-950/20">
                 <div>
                    <h3 className="text-5xl font-black italic tracking-tighter uppercase leading-none">BIBLIOTECA DE <span className="text-emerald-500">CULTURAS</span></h3>
                    <p className="text-[12px] font-black text-zinc-600 uppercase tracking-[0.5em] mt-3">Expanda sua produção agrícola</p>
                 </div>
                 <button onClick={() => setSelectedPlot(null)} className="p-8 bg-zinc-900 rounded-[2.5rem] text-zinc-500 hover:text-white transition-all"><X size={48}/></button>
              </div>
              <div className="p-16 grid grid-cols-1 md:grid-cols-2 gap-8 max-h-[60vh] overflow-y-auto scrollbar-hide">
                 {CROPS.map(c => (
                   <button 
                    key={c.id} 
                    disabled={gameState.level < c.minLevel || gameState.credits < c.cost}
                    onClick={() => handlePlant(selectedPlot, c.id)}
                    className={`p-10 rounded-[4rem] border-4 flex items-center justify-between transition-all ${gameState.level < c.minLevel ? 'opacity-20 bg-black cursor-not-allowed border-zinc-900' : 'bg-zinc-900/60 border-white/5 hover:border-emerald-500/40 hover:scale-[1.02] shadow-2xl'}`}
                   >
                     <div className="flex items-center gap-8 text-left">
                        <span className="text-7xl drop-shadow-2xl">{c.emoji}</span>
                        <div>
                           <p className="font-black text-2xl text-white tracking-tighter">{c.name}</p>
                           <p className="text-xl font-black text-emerald-500 tracking-tighter">R$ {c.cost.toLocaleString()}</p>
                        </div>
                     </div>
                     {gameState.level < c.minLevel && <Lock size={32} className="text-zinc-700"/>}
                   </button>
                 ))}
              </div>
           </div>
        </div>
      )}

    </div>
  );
};

export default AgroBrazil;

export enum IdentityType {
  REAL = 'REAL',
  PROFESSIONAL = 'PROFESSIONAL'
}

export enum UserPlan {
  FREE = 'FREE',
  PREMIUM = 'PREMIUM'
}

export enum UserStatus {
  ONLINE = 'ONLINE',
  BUSY = 'BUSY',
  AWAY = 'AWAY',
  INVISIBLE = 'INVISIBLE',
  OFFLINE = 'OFFLINE'
}

export interface User {
  id: string;
  name: string;
  username: string;
  email: string;
  age: number;
  birthDate: string;
  identityType: IdentityType;
  reputation: number;
  level: number;
  xp: number;
  verified: boolean;
  plan: UserPlan;
  bio: string;
  avatar: string;
  location: string;
  friends: string[];
  bookmarks: string[];
  joinedCommunities: string[];
  friendRequests: { fromId: string; timestamp: string }[];
  wishlist?: string[];
  privacy: {
    isPublic: boolean;
    showLocation: boolean;
    allowStrangersMsg: boolean;
    showOnlineStatus: boolean;
    incognitoMode?: boolean;
  };
  status: UserStatus;
  statusPhrase?: string;
  currentMusic?: string;
  currentMood?: string;
  ultima_atividade: number; 
  createdAt?: string;
  themePreference?: 'dark' | 'light' | 'nostalgia';
  animatedAvatar?: boolean;
}

export type MessageType = 'texto' | 'imagem' | 'audio' | 'video' | 'sticker' | 'emoji' | 'nudge';

export interface Message {
  id: string;
  conversa_id: string;
  remetente_id: string;
  tipo: MessageType;
  conteudo: string; 
  data_envio: number;
  lida: boolean;
  editada: boolean;
  metadata?: {
    duration?: number;
    fileName?: string;
    aspectRatio?: number;
  };
}

export type PlotStatus = 'locked' | 'empty' | 'planted' | 'growing' | 'ready' | 'partial_loss' | 'total_loss';

export interface AgroPlot {
  id: number;
  cropId: string | null;
  plantedAt: number | null;
  status: PlotStatus;
  quality: number; // 0.0 to 1.0
  riskTriggered: boolean;
}

export interface AgroPen {
  id: number;
  animalId: string | null;
  startedAt: number | null;
  status: 'locked' | 'empty' | 'active' | 'ready' | 'sick';
  hunger: number;
  health: number;
  genetics: number;
}

export interface MarketPrice {
  cropId: string;
  price: number;
  trend: 'up' | 'down' | 'stable';
  volatility: number;
  demand: number; // 0.1 to 2.0 multiplier
}

export interface ExportContract {
  id: string;
  targetItem: string;
  quantity: number;
  reward: number;
  premiumReward: number;
  expiresAt: number;
  bonusXp: number;
  destination: string;
}

export interface AgroEvent {
  id: string;
  title: string;
  description: string;
  effect: 'price_up' | 'price_down' | 'risk_up' | 'yield_up';
  targetCrop?: string;
  multiplier: number;
  expiresAt: number;
}

export interface AgroMachine {
  id: string;
  name: string;
  emoji: string;
  cost: number;
  minLevel: number;
  bonusType: 'growth_speed' | 'yield_boost' | 'risk_reduction' | 'export_bonus' | 'storage_rep';
  bonusValue: number;
  description: string;
}

export interface AgroGameState {
  credits: number;
  premiumCredits: number;
  level: number;
  xp: number;
  plots: AgroPlot[];
  pens: AgroPen[];
  inventory: Record<string, number>;
  marketPrices: MarketPrice[];
  exportContracts: ExportContract[];
  activeEvents: AgroEvent[];
  machines: string[]; // IDs das máquinas compradas
  lastCheck: number;
  feedStock: number;
}

export interface AgroCrop {
  id: string;
  name: string;
  emoji: string;
  growthTime: number; 
  cost: number;
  baseYield: number;
  xp: number;
  minLevel: number;
  riskFactor: number;
}

export interface AgroAnimal {
  id: string;
  name: string;
  emoji: string;
  productionTime: number;
  cost: number;
  baseYield: number;
  xp: number;
  products: string[];
  minLevel: number;
  feedNeeded: number;
}

export interface Community {
  id: string;
  name: string;
  description: string;
  category: string;
  members: string[]; 
  ownerId: string;
  icon: string;
  ranking: number;
  isPrivate: boolean;
  isPremium: boolean;
  createdAt: number;
}

export interface Product {
  id: string;
  name: string;
  price: number;
  location: string;
  image: string;
  category: string;
  sellerId: string;
  sellerName: string;
  status: 'active' | 'sold' | 'paused';
  description?: string;
