const AgroBrazil: React.FC<{ currentUser: User }> = ({ currentUser }) => {
  const [isLobby, setIsLobby] = useState(true);
  const [activeTab, setActiveTab] = useState<'fazenda' | 'industria' | 'mercado' | 'exportacao' | 'maquinas' | 'coops' | 'ranking'>('fazenda');
  const [rankingFilter, setRankingFilter] = useState<'nacional' | 'amigos' | 'semanal' | 'cooperativas'>('nacional');
  const [selectedPlot, setSelectedPlot] = useState<number | null>(null);
  const [isProcessing, setIsProcessing] = useState<string | null>(null);
  const [processingProgress, setProcessingProgress] = useState(0);

  const [gameState, setGameState] = useState<AgroGameState>(() => 
    UserDatabase.getAgroState(currentUser.id)
  );

  const currentTitle = useMemo(() => {
    return [...TITLES].reverse().find(t => gameState.level >= t.minLevel) || TITLES[0];
  }, [gameState.level]);

  const activeCoop = useMemo(() => {
    if (!gameState.coopId) return null;
    return UserDatabase.getCoops().find(c => c.id === gameState.coopId);
  }, [gameState.coopId]);

  // Gameloop: Tempo, Eventos, Inflação, Mercado
  useEffect(() => {
    const interval = setInterval(() => {
      const now = Date.now();
      setGameState(prev => {
        // 1. Atualizar Plantações
        const nextPlots = prev.plots.map(p => {
          if (!p.cropId || !p.plantedAt || p.status === 'locked' || p.status === 'empty' || p.status === 'ready' || p.status.includes('loss')) return p;
          const crop = CROPS.find(c => c.id === p.cropId);
          if (!crop) return p;

          const speedBuff = prev.machines.includes('trator_m7') ? 1.25 : 1.0;
          const riskReduction = prev.machines.includes('pulverizador_drone') ? 0.5 : 1.0;
          const elapsed = (now - p.plantedAt) / 1000;
          const progress = elapsed / (crop.growthTime / speedBuff);

          const activeRiskEvent = prev.activeEvents.find(e => e.targetCrop === crop.id && e.effect === 'risk_up');
          const finalRisk = (crop.riskFactor * riskReduction) * (activeRiskEvent ? activeRiskEvent.multiplier : 1.0);

          if (progress < 1.0 && Math.random() < finalRisk / 500) {
            const isTotal = Math.random() > 0.8;
            return { ...p, status: isTotal ? 'total_loss' : 'partial_loss', quality: isTotal ? 0 : 0.5 };
          }
          if (progress >= 1.0) return { ...p, status: 'ready' as PlotStatus };
          if (progress > 0.1) return { ...p, status: 'growing' as PlotStatus };
          return p;
        });

        // 2. Mercado Dinâmico
        const nextMarket = prev.marketPrices.map(mp => {
           let price = mp.price * 1.0005; 
           const demandMod = (Math.random() * 0.04) - 0.02;
           price *= (1 + demandMod);
           const ev = prev.activeEvents.find(e => e.targetCrop === mp.cropId);
           if (ev) {
             if (ev.effect === 'price_up') price *= 1.05;
             if (ev.effect === 'price_down') price *= 0.95;
           }
           const trend = price > mp.price ? 'up' : 'down';
           return { ...mp, price: Math.max(10, Math.floor(price)), trend: trend as any };
        });

        // 3. Eventos e Contratos
        const nextEvents = prev.activeEvents.filter(e => e.expiresAt > now);
        if (nextEvents.length < 2 && Math.random() > 0.995) {
          const template = GLOBAL_EVENTS[Math.floor(Math.random() * GLOBAL_EVENTS.length)];
          nextEvents.push({ ...template, id: Math.random().toString(36).substr(2,4), expiresAt: now + (1000 * 60 * 10) } as AgroEvent);
        }

        const newState = { ...prev, plots: nextPlots, marketPrices: nextMarket, activeEvents: nextEvents, lastCheck: now };
        UserDatabase.saveAgroState(currentUser.id, newState);
        return newState;
      });
    }, 1000);
    return () => clearInterval(interval);
  }, [currentUser.id]);

  const syncSocialValue = (xp: number) => {
    const user = UserDatabase.findById(currentUser.id);
    if (user) {
      user.reputation += Math.floor(xp / 10);
      user.xp += xp;
      if (user.xp >= user.level * 4000) { user.level++; user.xp = 0; }
      UserDatabase.updateUser(user);
    }
  };

  const handlePlant = (plotId: number, cropId: string) => {
    const crop = CROPS.find(c => c.id === cropId);
    if (!crop || gameState.credits < crop.cost) return;
    setGameState(prev => ({
      ...prev,
      credits: prev.credits - crop.cost,
      plots: prev.plots.map(p => p.id === plotId ? { ...p, cropId, plantedAt: Date.now(), status: 'planted', quality: 1.0 } : p)
    }));
    setSelectedPlot(null);
  };

  const handleHarvest = (plotId: number) => {
    const plot = gameState.plots.find(p => p.id === plotId);
    if (!plot || !plot.cropId) return;
    const crop = CROPS.find(c => c.id === plot.cropId);
    if (!crop) return;
    const yieldBuff = gameState.machines.includes('colheitadeira_titan') ? 1.25 : 1.0;
    const yieldAmount = Math.floor(crop.baseYield * plot.quality * yieldBuff);
    setGameState(prev => {
      const inv = { ...prev.inventory };
      inv[crop.id] = (inv[crop.id] || 0) + yieldAmount;
      syncSocialValue(crop.xp);
      return {
        ...prev,
        inventory: inv,
        xp: prev.xp + crop.xp,
        plots: prev.plots.map(p => p.id === plotId ? { ...p, cropId: null, plantedAt: null, status: 'empty', quality: 1.0 } : p)
      };
    });
  };

  const handleSell = (itemId: string, qty: number) => {
    const priceData = gameState.marketPrices.find(p => p.cropId === itemId);
    const stock = gameState.inventory[itemId] || 0;
    if (!priceData || stock < qty) return;
    const revenue = Math.floor(priceData.price * qty * 0.95);
    setGameState(prev => {
      const inv = { ...prev.inventory };
      inv[itemId] -= qty;
      return { ...prev, credits: prev.credits + revenue, weeklyRevenue: prev.weeklyRevenue + revenue, inventory: inv };
    });
  };

  const rankingList = useMemo(() => {
    if (rankingFilter === 'cooperativas') {
      return UserDatabase.getCoops().sort((a, b) => b.totalReputation - a.totalReputation);
    }

    const allUsers = UserDatabase.getUsers();
    let list = allUsers.map(u => ({
      ...u,
      agro: UserDatabase.getAgroState(u.id)
    }));

    if (rankingFilter === 'amigos') {
      list = list.filter(u => currentUser.friends.includes(u.id) || u.id === currentUser.id);
    }

    if (rankingFilter === 'semanal') {
      return list.sort((a, b) => b.agro.weeklyRevenue - a.agro.weeklyRevenue);
    }

    return list.sort((a, b) => b.agro.credits - a.agro.credits);
  }, [rankingFilter, currentUser.friends, currentUser.id]);

  const getRankTitle = (lvl: number) => {
     return [...TITLES].reverse().find(t => lvl >= t.minLevel)?.title || TITLES[0].title;
  };

  return (
    <div className="h-[calc(100vh-175px)] bg-[#010502] rounded-[3.5rem] border border-white/5 flex flex-col overflow-hidden shadow-2xl relative">

      <div className="absolute top-0 left-0 w-full h-full pointer-events-none opacity-5">
        <div className="absolute top-[-10%] left-[-10%] w-[60%] h-[60%] bg-emerald-500 blur-[150px] rounded-full"></div>
        <div className="absolute bottom-[-10%] right-[-10%] w-[60%] h-[60%] bg-amber-500 blur-[150px] rounded-full"></div>
      </div>

      <header className="p-8 bg-zinc-950/80 backdrop-blur-3xl border-b border-white/5 flex items-center justify-between relative z-20 shrink-0">
        <div className="flex items-center gap-6">
