              </div>
              <div className="p-16 grid grid-cols-1 md:grid-cols-2 gap-8 max-h-[60vh] overflow-y-auto scrollbar-hide">
                 {CROPS.map(c => (
                   <button key={c.id} disabled={gameState.level < c.minLevel || gameState.credits < c.cost} onClick={() => handlePlant(selectedPlot, c.id)} className={`p-10 rounded-[4rem] border-4 flex items-center justify-between transition-all ${gameState.level < c.minLevel ? 'opacity-20 bg-black cursor-not-allowed border-zinc-900' : 'bg-zinc-900/60 border-white/5 hover:border-emerald-500/40 hover:scale-[1.02] shadow-2xl'}`}>
                     <div className="flex items-center gap-8 text-left">
                        <span className="text-7xl drop-shadow-2xl">{c.emoji}</span>
                        <div>
                           <p className="font-black text-2xl text-white tracking-tighter">{c.name}</p>
                           <p className="text-xl font-black text-emerald-500 tracking-tighter">R$ {c.cost.toLocaleString()}</p>
                        </div>
                     </div>
                     {gameState.level < c.minLevel && <Lock size={32} className="text-zinc-700"/>}
                   </button>
                 ))}
              </div>
           </div>
        </div>
      )}
    </div>
  );
};

