  { id: 'laranja', name: 'Laranja Citros', emoji: '🍊', growthTime: 90, cost: 2000, baseYield: 6500, xp: 1500, minLevel: 12, riskFactor: 0.10 },
];

const INDUSTRY_RECIPES = [
  { id: 'racao', name: 'Fábrica de Ração', input: 'milho', inputQty: 200, output: 'racao', outputQty: 100, time: 10, xp: 50, emoji: '📦' },
  { id: 'queijo', name: 'Queijaria Artesanal', input: 'leite', inputQty: 100, output: 'queijo_especial', outputQty: 10, time: 30, xp: 450, emoji: '🧀' },
