const THEMATIC_EVENTS = [
  { id: 'festa_milho', title: 'Festa do Milho', description: 'O preço do Milho triplicou na Tribo!', effect: 'price_up', targetCrop: 'milho', multiplier: 3.0 },
  { id: 'expo_agro', title: 'ExpoAgro 2026', description: 'Bônus de 2x XP em todas as colheitas!', effect: 'xp_double', targetCrop: 'all', multiplier: 2.0 },
  { id: 'leilao_gado', title: 'Leilão de Elite', description: 'Produtos de pecuária com valor recorde.', effect: 'price_up', targetCrop: 'carne_premium', multiplier: 2.5 },
];

const TITLES = [
  { minLevel: 1, title: 'Pequeno Produtor', color: 'text-zinc-500' },
  { minLevel: 6, title: 'Agricultor Regional', color: 'text-emerald-500' },
  { minLevel: 16, title: 'Produtor Nacional', color: 'text-blue-500' },
  { minLevel: 31, title: 'Exportador Master', color: 'text-amber-500' },
  { minLevel: 51, title: 'Barão do Agro', color: 'text-rose-500 font-black' },
  { minLevel: 81, title: 'Rei do Agro Brasileiro', color: 'text-white font-black italic animate-pulse' },
];

const AgroBrazil: React.FC<{ currentUser: User }> = ({ currentUser }) => {
  const [isLobby, setIsLobby] = useState(true);
  const [activeTab, setActiveTab] = useState<'fazenda' | 'industria' | 'mercado' | 'missões' | 'caixa'>('fazenda');
  const [selectedPlot, setSelectedPlot] = useState<number | null>(null);
  const [isProcessing, setIsProcessing] = useState<string | null>(null);
  const [processingProgress, setProcessingProgress] = useState(0);
  const [surpriseBoxOpening, setSurpriseBoxOpening] = useState(false);
  const [boxResult, setBoxResult] = useState<string | null>(null);

  const [gameState, setGameState] = useState<AgroGameState>(() => 
    UserDatabase.getAgroState(currentUser.id)
  );

  // Sistema de Tempo Virtual (Dia/Noite)
  const isNight = useMemo(() => {
    const hours = new Date().getHours();
    return hours >= 20 || hours < 6;
  }, []);

  const currentTitle = useMemo(() => {
    return [...TITLES].reverse().find(t => gameState.level >= t.minLevel) || TITLES[0];
  }, [gameState.level]);

  // Gameloop: Tempo, Energia, Missões, Mercado
  useEffect(() => {
    const interval = setInterval(() => {
      const now = Date.now();
      setGameState(prev => {
        // 1. Regenerar Energia
        let nextEnergy = prev.energy;
        if (nextEnergy < prev.maxEnergy) {
          nextEnergy = Math.min(prev.maxEnergy, nextEnergy + 0.1); 
        }

        // 2. Atualizar Plantações
        const nextPlots = prev.plots.map(p => {
          if (!p.cropId || !p.plantedAt || p.status === 'locked' || p.status === 'empty' || p.status === 'ready' || p.status.includes('loss')) return p;
          const crop = CROPS.find(c => c.id === p.cropId);
          if (!crop) return p;

          // Bônus Noturno: 30% mais rápido se plantado à noite
          const speedBuff = p.isNightPlanted ? 1.3 : 1.0;
          const elapsed = (now - p.plantedAt) / 1000;
          const progress = elapsed / (crop.growthTime / speedBuff);

          if (progress >= 1.0) return { ...p, status: 'ready' as PlotStatus };
          if (progress > 0.1) return { ...p, status: 'growing' as PlotStatus };
          return p;
        });

        // 3. Mercado e Eventos
        const nextMarket = prev.marketPrices.map(mp => {
           let price = mp.price * 1.0002; 
           const ev = prev.activeEvents.find(e => e.targetCrop === mp.cropId && e.effect === 'price_up');
           if (ev) price *= 1.02;
           return { ...mp, price: Math.max(10, Math.floor(price)) };
        });

        // 4. Gerar Evento Aleatório
        const nextEvents = prev.activeEvents.filter(e => e.expiresAt > now);
        if (nextEvents.length < 1 && Math.random() > 0.998) {
          const template = THEMATIC_EVENTS[Math.floor(Math.random() * THEMATIC_EVENTS.length)];
          nextEvents.push({ ...template, id: Math.random().toString(36).substr(2,4), expiresAt: now + (1000 * 60 * 15) } as AgroEvent);
        }

        const newState = { ...prev, energy: nextEnergy, plots: nextPlots, marketPrices: nextMarket, activeEvents: nextEvents, lastCheck: now };
        UserDatabase.saveAgroState(currentUser.id, newState);
        return newState;
      });
    }, 1000);
    return () => clearInterval(interval);
  }, [currentUser.id]);

  const updateMissionProgress = (type: 'harvest' | 'process' | 'export', item: string, count: number) => {
    setGameState(prev => {
      const nextMissions = prev.missions.map(m => {
        if (m.isClaimed) return m;
        // Lógica simplificada de match de missão
        if (m.description.toLowerCase().includes(item.toLowerCase())) {
          return { ...m, currentCount: Math.min(m.targetCount, m.currentCount + count) };
        }
        return m;
      });
      return { ...prev, missions: nextMissions };
    });
  };

  const handlePlant = (plotId: number, cropId: string) => {
    const crop = CROPS.find(c => c.id === cropId);
    if (!crop || gameState.credits < crop.cost || gameState.energy < ENERGY_COSTS.PLANT) return;

    setGameState(prev => ({
      ...prev,
      credits: prev.credits - crop.cost,
      energy: prev.energy - ENERGY_COSTS.PLANT,
      plots: prev.plots.map(p => p.id === plotId ? { ...p, cropId, plantedAt: Date.now(), status: 'planted', quality: 1.0, isNightPlanted: isNight } : p)
    }));
    setSelectedPlot(null);
  };

  const handleHarvest = (plotId: number) => {
    const plot = gameState.plots.find(p => p.id === plotId);
    if (!plot || !plot.cropId || gameState.energy < ENERGY_COSTS.HARVEST) return;
    const crop = CROPS.find(c => c.id === plot.cropId);
    if (!crop) return;

    const xpMult = gameState.activeEvents.some(e => e.effect === 'xp_double') ? 2 : 1;
    const yieldAmount = Math.floor(crop.baseYield * plot.quality);

    setGameState(prev => {
      const inv = { ...prev.inventory };
      inv[crop.id] = (inv[crop.id] || 0) + yieldAmount;
      return {
        ...prev,
        energy: prev.energy - ENERGY_COSTS.HARVEST,
        inventory: inv,
        xp: prev.xp + (crop.xp * xpMult),
        plots: prev.plots.map(p => p.id === plotId ? { ...p, cropId: null, plantedAt: null, status: 'empty', quality: 1.0 } : p)
      };
    });
    updateMissionProgress('harvest', crop.name, yieldAmount);
    syncReputation(crop.xp / 10);
  };

  const handleSell = (itemId: string, qty: number) => {
    const priceData = gameState.marketPrices.find(p => p.cropId === itemId);
    const stock = gameState.inventory[itemId] || 0;
    if (!priceData || stock < qty) return;
    const revenue = Math.floor(priceData.price * qty * 0.95);
    setGameState(prev => {
      const inv = { ...prev.inventory };
      inv[itemId] -= qty;
      return { ...prev, credits: prev.credits + revenue, weeklyRevenue: prev.weeklyRevenue + revenue, inventory: inv };
    });
  };

  const syncReputation = (val: number) => {
    const user = UserDatabase.findById(currentUser.id);
    if (user) {
      user.reputation += Math.floor(val);
      if (user.xp >= user.level * 5000) { user.level++; user.xp = 0; }
      UserDatabase.updateUser(user);
    }
  };

  const openSurpriseBox = async () => {
    if (gameState.credits < 1000 || surpriseBoxOpening) return;
    setSurpriseBoxOpening(true);
    setBoxResult(null);

    await new Promise(r => setTimeout(r, 2000));

    const roll = Math.random();
    let reward = "";
    let energyBoost = 0;
    let creditsBoost = 0;
    let gemsBoost = 0;

    if (roll > 0.95) { reward = "Lendário: 50 AgroGems!"; gemsBoost = 50; }
    else if (roll > 0.8) { reward = "Épico: +100 Energia!"; energyBoost = 100; }
    else if (roll > 0.5) { reward = "Raro: R$ 5.000!"; creditsBoost = 5000; }
    else { reward = "Comum: +20 Energia"; energyBoost = 20; }

    setGameState(prev => ({
      ...prev,
      credits: prev.credits - 1000,
      energy: Math.min(prev.maxEnergy + 100, prev.energy + energyBoost),
      premiumCredits: prev.premiumCredits + gemsBoost,
      credits: prev.credits - 1000 + creditsBoost
    }));

    setBoxResult(reward);
    setSurpriseBoxOpening(false);
  };

  const claimMission = (mId: string) => {
    setGameState(prev => {
      const mission = prev.missions.find(m => m.id === mId);
      if (!mission || mission.currentCount < mission.targetCount || mission.isClaimed) return prev;
      return {
        ...prev,
        credits: prev.credits + mission.rewardCredits,
        premiumCredits: prev.premiumCredits + mission.rewardGems,
        missions: prev.missions.map(m => m.id === mId ? { ...m, isClaimed: true } : m)
      };
    });
  };

  return (
    <div className={`h-[calc(100vh-175px)] rounded-[3.5rem] border border-white/5 flex flex-col overflow-hidden shadow-2xl relative transition-colors duration-1000 ${isNight ? 'bg-[#01050a]' : 'bg-[#010a05]'}`}>

      {/* Background Decor */}
      <div className="absolute top-0 left-0 w-full h-full pointer-events-none opacity-5">
        <div className={`absolute top-[-10%] left-[-10%] w-[60%] h-[60%] blur-[150px] rounded-full ${isNight ? 'bg-blue-500' : 'bg-emerald-500'}`}></div>
        <div className={`absolute bottom-[-10%] right-[-10%] w-[60%] h-[60%] blur-[150px] rounded-full ${isNight ? 'bg-indigo-500' : 'bg-amber-500'}`}></div>
      </div>

      <header className="p-8 bg-black/60 backdrop-blur-3xl border-b border-white/5 flex items-center justify-between relative z-20 shrink-0">
        <div className="flex items-center gap-6">
          <button onClick={() => isLobby ? null : setIsLobby(true)} className="p-4 bg-zinc-900 text-zinc-500 rounded-2xl hover:text-white transition-all"><ChevronLeft size={24}/></button>
          <div className="flex items-center gap-4">
             <div className="relative">
                <div className={`w-14 h-14 rounded-2xl border flex items-center justify-center ${isNight ? 'bg-blue-500/10 border-blue-500/20 text-blue-400' : 'bg-emerald-500/10 border-emerald-500/20 text-emerald-500'}`}>
                   <Tractor size={32} />
                </div>
                <div className="absolute -top-1 -right-1 bg-black p-1 rounded-full">{isNight ? <Moon size={12} className="text-blue-400"/> : <Sun size={12} className="text-amber-400"/>}</div>
             </div>
             <div>
                <h2 className="text-xl font-black text-white italic tracking-tighter uppercase leading-none">AGRO <span className={isNight ? 'text-blue-500' : 'text-emerald-500'}>BRASIL</span></h2>
                <p className={`text-[9px] font-black uppercase tracking-widest mt-1.5 ${currentTitle.color}`}>{currentTitle.title}</p>
             </div>
          </div>
        </div>

        <div className="flex items-center gap-6">
           <div className="flex flex-col items-end gap-1">
              <div className="flex items-center gap-2">
                 <span className="text-[10px] font-black text-emerald-500 tracking-tighter">R$ {gameState.credits.toLocaleString()}</span>
                 <Wallet size={12} className="text-zinc-600"/>
