import React, { useState, useEffect, useMemo } from 'react';
import { 
  ChevronLeft, Plus, X, Tractor, Coins, Lock, TrendingUp, TrendingDown,
  Sprout, Factory, Package, Beef, Milk, Trophy, Loader2, Zap,
  ShoppingBag, Users, ShieldCheck, BarChart3, Star, ArrowUpRight,
  Droplets, Waves, Leaf, Box, Bug, ThermometerSun, AlertTriangle, Skull,
  ArrowRight, Flame, Wallet, History, Heart, Trash2, CheckCircle2,
  Globe, PlaneTakeoff, Ship, HardHat, Warehouse, Anchor, BadgeCheck, Landmark,
  Egg, Coffee, Banana, FlaskConical, Gavel, Mountain, Diamond, AlertCircle, 
  Truck, Settings2, ShieldAlert, Target, Users2, Building2, Crown, Medal,
  Moon, Sun, Gift, Sparkles, Battery, Timer, ShoppingCart,
  // Add Calendar import
  Calendar
} from 'lucide-react';
import { User, AgroCrop, AgroGameState, AgroPlot, PlotStatus, AgroAnimal, AgroPen, MarketPrice, ExportContract, AgroEvent, AgroMachine, AgroCoop, AgroMission } from '../types';
import { UserDatabase } from '../services/db';

const ENERGY_COSTS = {
  PLANT: 5,
  HARVEST: 3,
  PROCESS: 10,
  EXPORT: 15
};

const CROPS: AgroCrop[] = [
  { id: 'milho', name: 'Milho', emoji: '🌽', growthTime: 20, cost: 40, baseYield: 120, xp: 20, minLevel: 1, riskFactor: 0.04 },
  { id: 'soja', name: 'Soja', emoji: '🌱', growthTime: 60, cost: 300, baseYield: 800, xp: 150, minLevel: 2, riskFactor: 0.08 },
  { id: 'cana', name: 'Cana', emoji: '🎋', growthTime: 120, cost: 1200, baseYield: 4000, xp: 900, minLevel: 4, riskFactor: 0.12 },
  { id: 'cafe', name: 'Café Especial', emoji: '☕', growthTime: 180, cost: 5000, baseYield: 15000, xp: 4000, minLevel: 10, riskFactor: 0.15 },
  { id: 'laranja', name: 'Laranja Citros', emoji: '🍊', growthTime: 90, cost: 2000, baseYield: 6500, xp: 1500, minLevel: 12, riskFactor: 0.10 },
];

const INDUSTRY_RECIPES = [
  { id: 'racao', name: 'Fábrica de Ração', input: 'milho', inputQty: 200, output: 'racao', outputQty: 100, time: 10, xp: 50, emoji: '📦' },
  { id: 'queijo', name: 'Queijaria Artesanal', input: 'leite', inputQty: 100, output: 'queijo_especial', outputQty: 10, time: 30, xp: 450, emoji: '🧀' },
  { id: 'etanol', name: 'Destilaria de Etanol', input: 'cana', inputQty: 1000, output: 'etanol', outputQty: 80, time: 90, xp: 2500, emoji: '⛽' },
];

const THEMATIC_EVENTS = [
  { id: 'festa_milho', title: 'Festa do Milho', description: 'O preço do Milho triplicou na Tribo!', effect: 'price_up', targetCrop: 'milho', multiplier: 3.0 },
  { id: 'expo_agro', title: 'ExpoAgro 2026', description: 'Bônus de 2x XP em todas as colheitas!', effect: 'xp_double', targetCrop: 'all', multiplier: 2.0 },
  { id: 'leilao_gado', title: 'Leilão de Elite', description: 'Produtos de pecuária com valor recorde.', effect: 'price_up', targetCrop: 'carne_premium', multiplier: 2.5 },
];

const TITLES = [
  { minLevel: 1, title: 'Pequeno Produtor', color: 'text-zinc-500' },
  { minLevel: 6, title: 'Agricultor Regional', color: 'text-emerald-500' },
  { minLevel: 16, title: 'Produtor Nacional', color: 'text-blue-500' },
  { minLevel: 31, title: 'Exportador Master', color: 'text-amber-500' },
  { minLevel: 51, title: 'Barão do Agro', color: 'text-rose-500 font-black' },
  { minLevel: 81, title: 'Rei do Agro Brasileiro', color: 'text-white font-black italic animate-pulse' },
];

const AgroBrazil: React.FC<{ currentUser: User }> = ({ currentUser }) => {
  const [isLobby, setIsLobby] = useState(true);
  const [activeTab, setActiveTab] = useState<'fazenda' | 'industria' | 'mercado' | 'missões' | 'caixa'>('fazenda');
  const [selectedPlot, setSelectedPlot] = useState<number | null>(null);
  const [isProcessing, setIsProcessing] = useState<string | null>(null);
  const [processingProgress, setProcessingProgress] = useState(0);
  const [surpriseBoxOpening, setSurpriseBoxOpening] = useState(false);
  const [boxResult, setBoxResult] = useState<string | null>(null);

  const [gameState, setGameState] = useState<AgroGameState>(() => 
    UserDatabase.getAgroState(currentUser.id)
  );

  // Sistema de Tempo Virtual (Dia/Noite)
  const isNight = useMemo(() => {
    const hours = new Date().getHours();
    return hours >= 20 || hours < 6;
  }, []);

  const currentTitle = useMemo(() => {
    return [...TITLES].reverse().find(t => gameState.level >= t.minLevel) || TITLES[0];
  }, [gameState.level]);

  // Gameloop: Tempo, Energia, Missões, Mercado
  useEffect(() => {
    const interval = setInterval(() => {
      const now = Date.now();
      setGameState(prev => {
        // 1. Regenerar Energia
        let nextEnergy = prev.energy;
        if (nextEnergy < prev.maxEnergy) {
          nextEnergy = Math.min(prev.maxEnergy, nextEnergy + 0.1); 
        }

        // 2. Atualizar Plantações
        const nextPlots = prev.plots.map(p => {
          if (!p.cropId || !p.plantedAt || p.status === 'locked' || p.status === 'empty' || p.status === 'ready' || p.status.includes('loss')) return p;
          const crop = CROPS.find(c => c.id === p.cropId);
          if (!crop) return p;

          // Bônus Noturno: 30% mais rápido se plantado à noite
          const speedBuff = p.isNightPlanted ? 1.3 : 1.0;
          const elapsed = (now - p.plantedAt) / 1000;
          const progress = elapsed / (crop.growthTime / speedBuff);

          if (progress >= 1.0) return { ...p, status: 'ready' as PlotStatus };
          if (progress > 0.1) return { ...p, status: 'growing' as PlotStatus };
          return p;
        });

        // 3. Mercado e Eventos
        const nextMarket = prev.marketPrices.map(mp => {
           let price = mp.price * 1.0002; 
           const ev = prev.activeEvents.find(e => e.targetCrop === mp.cropId && e.effect === 'price_up');
           if (ev) price *= 1.02;
           return { ...mp, price: Math.max(10, Math.floor(price)) };
        });

        // 4. Gerar Evento Aleatório
        const nextEvents = prev.activeEvents.filter(e => e.expiresAt > now);
        if (nextEvents.length < 1 && Math.random() > 0.998) {
          const template = THEMATIC_EVENTS[Math.floor(Math.random() * THEMATIC_EVENTS.length)];
          nextEvents.push({ ...template, id: Math.random().toString(36).substr(2,4), expiresAt: now + (1000 * 60 * 15) } as AgroEvent);
        }

        const newState = { ...prev, energy: nextEnergy, plots: nextPlots, marketPrices: nextMarket, activeEvents: nextEvents, lastCheck: now };
        UserDatabase.saveAgroState(currentUser.id, newState);
        return newState;
      });
    }, 1000);
    return () => clearInterval(interval);
  }, [currentUser.id]);

  const updateMissionProgress = (type: 'harvest' | 'process' | 'export', item: string, count: number) => {
    setGameState(prev => {
      const nextMissions = prev.missions.map(m => {
        if (m.isClaimed) return m;
        // Lógica simplificada de match de missão
        if (m.description.toLowerCase().includes(item.toLowerCase())) {
          return { ...m, currentCount: Math.min(m.targetCount, m.currentCount + count) };
        }
        return m;
      });
      return { ...prev, missions: nextMissions };
    });
  };

  const handlePlant = (plotId: number, cropId: string) => {
    const crop = CROPS.find(c => c.id === cropId);
    if (!crop || gameState.credits < crop.cost || gameState.energy < ENERGY_COSTS.PLANT) return;

    setGameState(prev => ({
      ...prev,
      credits: prev.credits - crop.cost,
      energy: prev.energy - ENERGY_COSTS.PLANT,
      plots: prev.plots.map(p => p.id === plotId ? { ...p, cropId, plantedAt: Date.now(), status: 'planted', quality: 1.0, isNightPlanted: isNight } : p)
    }));
    setSelectedPlot(null);
  };

  const handleHarvest = (plotId: number) => {
    const plot = gameState.plots.find(p => p.id === plotId);
    if (!plot || !plot.cropId || gameState.energy < ENERGY_COSTS.HARVEST) return;
    const crop = CROPS.find(c => c.id === plot.cropId);
    if (!crop) return;

    const xpMult = gameState.activeEvents.some(e => e.effect === 'xp_double') ? 2 : 1;
    const yieldAmount = Math.floor(crop.baseYield * plot.quality);

    setGameState(prev => {
      const inv = { ...prev.inventory };
      inv[crop.id] = (inv[crop.id] || 0) + yieldAmount;
      return {
        ...prev,
        energy: prev.energy - ENERGY_COSTS.HARVEST,
        inventory: inv,
        xp: prev.xp + (crop.xp * xpMult),
        plots: prev.plots.map(p => p.id === plotId ? { ...p, cropId: null, plantedAt: null, status: 'empty', quality: 1.0 } : p)
      };
    });
    updateMissionProgress('harvest', crop.name, yieldAmount);
    syncReputation(crop.xp / 10);
  };

  const handleSell = (itemId: string, qty: number) => {
    const priceData = gameState.marketPrices.find(p => p.cropId === itemId);
    const stock = gameState.inventory[itemId] || 0;
    if (!priceData || stock < qty) return;
    const revenue = Math.floor(priceData.price * qty * 0.95);
    setGameState(prev => {
      const inv = { ...prev.inventory };
      inv[itemId] -= qty;
      return { ...prev, credits: prev.credits + revenue, weeklyRevenue: prev.weeklyRevenue + revenue, inventory: inv };
    });
  };

  const syncReputation = (val: number) => {
    const user = UserDatabase.findById(currentUser.id);
    if (user) {
      user.reputation += Math.floor(val);
      if (user.xp >= user.level * 5000) { user.level++; user.xp = 0; }
      UserDatabase.updateUser(user);
    }
  };

  const openSurpriseBox = async () => {
    if (gameState.credits < 1000 || surpriseBoxOpening) return;
    setSurpriseBoxOpening(true);
    setBoxResult(null);

    await new Promise(r => setTimeout(r, 2000));

    const roll = Math.random();
    let reward = "";
    let energyBoost = 0;
    let creditsBoost = 0;
    let gemsBoost = 0;

    if (roll > 0.95) { reward = "Lendário: 50 AgroGems!"; gemsBoost = 50; }
    else if (roll > 0.8) { reward = "Épico: +100 Energia!"; energyBoost = 100; }
    else if (roll > 0.5) { reward = "Raro: R$ 5.000!"; creditsBoost = 5000; }
    else { reward = "Comum: +20 Energia"; energyBoost = 20; }

    setGameState(prev => ({
      ...prev,
      // Fix duplicate property by combining logic
      credits: prev.credits - 1000 + creditsBoost,
      energy: Math.min(prev.maxEnergy + 100, prev.energy + energyBoost),
      premiumCredits: prev.premiumCredits + gemsBoost,
    }));

    setBoxResult(reward);
    setSurpriseBoxOpening(false);
  };

  const claimMission = (mId: string) => {
    setGameState(prev => {
      const mission = prev.missions.find(m => m.id === mId);
      if (!mission || mission.currentCount < mission.targetCount || mission.isClaimed) return prev;
      return {
        ...prev,
        credits: prev.credits + mission.rewardCredits,
        premiumCredits: prev.premiumCredits + mission.rewardGems,
        missions: prev.missions.map(m => m.id === mId ? { ...m, isClaimed: true } : m)
      };
    });
  };

  return (
    <div className={`h-[calc(100vh-175px)] rounded-[3.5rem] border border-white/5 flex flex-col overflow-hidden shadow-2xl relative transition-colors duration-1000 ${isNight ? 'bg-[#01050a]' : 'bg-[#010a05]'}`}>

      {/* Background Decor */}
      <div className="absolute top-0 left-0 w-full h-full pointer-events-none opacity-5">
        <div className={`absolute top-[-10%] left-[-10%] w-[60%] h-[60%] blur-[150px] rounded-full ${isNight ? 'bg-blue-500' : 'bg-emerald-500'}`}></div>
        <div className={`absolute bottom-[-10%] right-[-10%] w-[60%] h-[60%] blur-[150px] rounded-full ${isNight ? 'bg-indigo-500' : 'bg-amber-500'}`}></div>
      </div>

      <header className="p-8 bg-black/60 backdrop-blur-3xl border-b border-white/5 flex items-center justify-between relative z-20 shrink-0">
        <div className="flex items-center gap-6">
          <button onClick={() => isLobby ? null : setIsLobby(true)} className="p-4 bg-zinc-900 text-zinc-500 rounded-2xl hover:text-white transition-all"><ChevronLeft size={24}/></button>
          <div className="flex items-center gap-4">
             <div className="relative">
                <div className={`w-14 h-14 rounded-2xl border flex items-center justify-center ${isNight ? 'bg-blue-500/10 border-blue-500/20 text-blue-400' : 'bg-emerald-500/10 border-emerald-500/20 text-emerald-500'}`}>
                   <Tractor size={32} />
                </div>
                <div className="absolute -top-1 -right-1 bg-black p-1 rounded-full">{isNight ? <Moon size={12} className="text-blue-400"/> : <Sun size={12} className="text-amber-400"/>}</div>
             </div>
             <div>
                <h2 className="text-xl font-black text-white italic tracking-tighter uppercase leading-none">AGRO <span className={isNight ? 'text-blue-500' : 'text-emerald-500'}>BRASIL</span></h2>
                <p className={`text-[9px] font-black uppercase tracking-widest mt-1.5 ${currentTitle.color}`}>{currentTitle.title}</p>
             </div>
          </div>
        </div>

        <div className="flex items-center gap-6">
           <div className="flex flex-col items-end gap-1">
              <div className="flex items-center gap-2">
                 <span className="text-[10px] font-black text-emerald-500 tracking-tighter">R$ {gameState.credits.toLocaleString()}</span>
                 <Wallet size={12} className="text-zinc-600"/>
              </div>
              <div className="flex items-center gap-2">
                 <Battery size={12} className={gameState.energy < 20 ? 'text-rose-500 animate-pulse' : 'text-blue-400'} />
                 <div className="w-24 h-1.5 bg-black rounded-full overflow-hidden border border-white/5">
                    <div className="h-full bg-blue-500 transition-all duration-500" style={{ width: `${(gameState.energy / gameState.maxEnergy) * 100}%` }} />
                 </div>
              </div>
           </div>
           <div className="px-5 py-3 bg-zinc-900 rounded-2xl border border-white/5 text-center min-w-[80px]">
              <span className="text-[9px] font-black text-white uppercase tracking-widest block mb-1">NV. {gameState.level}</span>
              <div className="w-full h-1 bg-black rounded-full overflow-hidden">
                <div className="h-full bg-emerald-500" style={{ width: `${(gameState.xp % 5000) / 50}%` }} />
              </div>
           </div>
        </div>
      </header>

      {isLobby ? (
        <div className="flex-1 flex flex-col items-center justify-center p-12 text-center space-y-16 relative z-10 overflow-y-auto scrollbar-hide">
           <div className="relative group">
              <div className="absolute inset-0 bg-emerald-500 blur-[120px] opacity-10 animate-pulse"></div>
              <img src="https://images.unsplash.com/photo-1523348837708-15d4a09cfac2?w=800&h=400&fit=crop" className="w-full max-w-2xl h-80 object-cover rounded-[5rem] border-4 border-emerald-500/20 shadow-2xl relative z-10" />
              <div className="absolute -bottom-6 -right-6 bg-amber-500 text-black p-8 rounded-[3.5rem] shadow-2xl z-20 rotate-12 transition-all">
                 <Sparkles size={48} fill="currentColor" />
              </div>
           </div>

           <div className="space-y-6">
              <h1 className="text-7xl md:text-9xl font-black italic text-white tracking-tighter leading-none">VIVA O<br/><span className={isNight ? 'text-blue-500' : 'text-emerald-500'}>CAMPO</span></h1>
              <p className="text-zinc-500 font-bold uppercase tracking-[0.5em] text-[11px] max-w-lg mx-auto leading-relaxed">Produza, especule e conquiste a soberania rural na maior rede do Brasil.</p>
           </div>

           <button onClick={() => setIsLobby(false)} className="w-full max-w-md bg-emerald-500 hover:bg-emerald-400 text-black font-black py-10 rounded-[3.5rem] uppercase tracking-[0.3em] text-sm shadow-2xl shadow-emerald-500/20 active:scale-95 transition-all flex items-center justify-center gap-6">
              Iniciar Safra <ArrowRight size={24} />
           </button>
        </div>
      ) : (
        <>
          <nav className="flex bg-black/40 p-2 border-b border-white/5 overflow-x-auto scrollbar-hide relative z-20 shrink-0">
            {[
              { id: 'fazenda', icon: Sprout, label: 'Fazenda' },
              { id: 'industria', icon: Factory, label: 'Indústria' },
              { id: 'mercado', icon: ShoppingBag, label: 'Mercado' },
              { id: 'missões', icon: Target, label: 'Missões' },
              { id: 'caixa', icon: Gift, label: 'Surpresa' }
            ].map(t => (
              <button 
                key={t.id} 
                onClick={() => setActiveTab(t.id as any)} 
                className={`flex-1 min-w-[100px] py-5 rounded-[2rem] text-[9px] font-black uppercase tracking-widest flex items-center justify-center gap-2 transition-all ${activeTab === t.id ? 'bg-emerald-500 text-black shadow-xl' : 'text-zinc-600 hover:text-zinc-400'}`}
              >
                <t.icon size={18}/> {t.label}
              </button>
            ))}
          </nav>

          {gameState.activeEvents.length > 0 && (
            <div className="bg-rose-500/10 border-b border-rose-500/20 p-4 flex items-center gap-4 overflow-x-auto scrollbar-hide shrink-0 z-10">
               {gameState.activeEvents.map(ev => (
                 <div key={ev.id} className="flex-none bg-rose-500 text-white px-6 py-2 rounded-full text-[9px] font-black uppercase flex items-center gap-3 shadow-lg">
                    <AlertCircle size={14} />
                    <span>{ev.title}: {ev.description}</span>
                    <div className="w-px h-3 bg-white/20"></div>
                    <span className="opacity-70">{Math.floor((ev.expiresAt - Date.now()) / 60000)}m restantes</span>
                 </div>
               ))}
            </div>
          )}

          <main className="flex-1 overflow-y-auto p-10 scrollbar-hide relative z-10">

            {activeTab === 'fazenda' && (
              <div className="grid grid-cols-4 gap-6 perspective-[2000px] py-10">
                {gameState.plots.map((plot) => {
                  const crop = plot.cropId ? CROPS.find(c => c.id === plot.cropId) : null;
                  const isReady = plot.status === 'ready';
                  return (
                    <div 
                      key={plot.id}
                      onClick={() => !crop ? setSelectedPlot(plot.id) : isReady && handleHarvest(plot.id)}
                      className={`
                        aspect-square rounded-[3rem] border-2 flex items-center justify-center relative cursor-pointer transition-all duration-700 transform hover:-translate-y-4 shadow-xl
                        ${plot.status === 'locked' ? 'opacity-20 bg-black border-zinc-900 cursor-not-allowed' : 'bg-zinc-900/40 border-white/5 hover:border-emerald-500/40'}
                        ${isReady ? 'border-emerald-500 bg-emerald-500/10' : ''}
                      `}
                      style={{ transform: 'rotateX(45deg) rotateZ(-15deg)' }}
                    >
                      {plot.status === 'locked' ? <Lock className="text-zinc-800"/> : (
                        <div className="relative z-10 flex flex-col items-center gap-3">
                           {crop ? (
                              <>
                                 <span className={`text-6xl drop-shadow-2xl transition-transform duration-700 ${isReady ? 'scale-125' : ''}`}>{crop.emoji}</span>
                                 {plot.isNightPlanted && <Moon size={16} className="absolute -top-4 -right-4 text-blue-400 drop-shadow-xl" />}
                                 {isReady && <div className="absolute -top-10 bg-emerald-500 text-black px-4 py-1.5 rounded-full text-[8px] font-black uppercase tracking-widest animate-bounce">Pronto!</div>}
                              </>
                           ) : <Plus className="text-zinc-800 group-hover:text-emerald-500" size={32} />}
                        </div>
                      )}
                    </div>
                  );
                })}
              </div>
            )}

            {activeTab === 'missões' && (
               <div className="max-w-3xl mx-auto space-y-8 pb-10">
                  <div className="bg-zinc-900/60 p-10 rounded-[4rem] border border-white/5 text-center">
                     <h3 className="text-4xl font-black italic tracking-tighter text-white uppercase">CENTRAL DE <span className="text-emerald-500">METAS</span></h3>
                     <p className="text-[10px] font-black text-zinc-500 uppercase tracking-[0.4em] mt-4">Cumpra missões e ganhe AgroGems reais</p>
                  </div>

                  {gameState.missions.map(m => {
                    const progress = (m.currentCount / m.targetCount) * 100;
                    const canClaim = m.currentCount >= m.targetCount && !m.isClaimed;
                    return (
                      <div key={m.id} className={`p-8 rounded-[3.5rem] border-2 flex flex-col gap-6 transition-all ${m.isClaimed ? 'bg-zinc-950/40 border-white/5 opacity-50' : 'bg-zinc-900 border-white/10 hover:border-emerald-500/20'}`}>
                         <div className="flex justify-between items-start">
                            <div className="flex gap-6 items-center">
                               <div className={`w-16 h-16 rounded-[1.5rem] flex items-center justify-center text-black ${m.type === 'daily' ? 'bg-emerald-500' : 'bg-blue-500'}`}>
                                  {m.type === 'daily' ? <Sun size={24}/> : <Calendar size={24}/>}
                               </div>
                               <div>
                                  <h4 className="text-xl font-black text-white uppercase tracking-tight">{m.title}</h4>
                                  <p className="text-xs text-zinc-500 font-bold">{m.description}</p>
                               </div>
                            </div>
                            <div className="text-right">
                               <span className="text-sm font-black text-emerald-500">+R$ {m.rewardCredits}</span>
                               {m.rewardGems > 0 && <p className="text-[9px] font-black text-amber-400">+{m.rewardGems} AgroGems</p>}
                            </div>
                         </div>

                         <div className="space-y-2">
                            <div className="flex justify-between text-[10px] font-black uppercase text-zinc-600">
                               <span>Progresso</span>
                               <span>{m.currentCount} / {m.targetCount}</span>
                            </div>
                            <div className="w-full h-3 bg-black rounded-full overflow-hidden border border-white/5">
                               <div className="h-full bg-emerald-500" style={{ width: `${progress}%` }} />
                            </div>
                         </div>

                         {canClaim && (
                           <button onClick={() => claimMission(m.id)} className="w-full py-5 bg-emerald-500 text-black font-black uppercase tracking-widest text-xs rounded-[1.8rem] shadow-xl hover:bg-emerald-400 active:scale-95 transition-all">Coletar Recompensa</button>
                         )}
                         {m.isClaimed && (
                           <div className="flex justify-center text-[10px] font-black text-zinc-700 uppercase gap-2"><CheckCircle2 size={14}/> Missão Concluída</div>
                         )}
                      </div>
                    );
                  })}
               </div>
            )}

            {activeTab === 'caixa' && (
              <div className="flex flex-col items-center justify-center py-20 text-center space-y-12">
                 <div className={`relative group ${surpriseBoxOpening ? 'animate-bounce' : ''}`}>
                    <div className="absolute inset-0 bg-amber-500 blur-[100px] opacity-20 animate-pulse"></div>
                    <div className="w-64 h-64 bg-zinc-900 border-4 border-amber-500/30 rounded-[4rem] flex items-center justify-center text-9xl shadow-2xl relative z-10 transition-transform group-hover:scale-110">
                       <Gift size={120} className="text-amber-500" />
                    </div>
                 </div>

                 <div className="space-y-4">
                    <h3 className="text-4xl font-black italic tracking-tighter text-white uppercase">CAIXA <span className="text-amber-500">SURPRESA</span></h3>
                    <p className="text-zinc-500 font-bold uppercase text-[10px] tracking-[0.5em] max-w-sm">Tente a sorte por R$ 1.000. Ganhe energia, créditos ou gemas raras!</p>
                 </div>

                 {boxResult ? (
                   <div className="p-8 bg-amber-500 text-black rounded-[3rem] font-black text-xl animate-in zoom-in duration-500 shadow-2xl">
                      {boxResult}
                      <button onClick={() => setBoxResult(null)} className="block mx-auto mt-4 text-[9px] uppercase tracking-widest underline">Abrir Outra</button>
                   </div>
                 ) : (
                   <button 
                    onClick={openSurpriseBox}
                    disabled={gameState.credits < 1000 || surpriseBoxOpening}
                    className="px-16 py-8 bg-amber-500 text-black font-black uppercase tracking-[0.3em] text-sm rounded-[3rem] shadow-2xl hover:bg-amber-400 active:scale-95 transition-all disabled:opacity-20"
                   >
                     {surpriseBoxOpening ? 'Abrindo...' : 'Abrir Caixa'}
                   </button>
                 )}
              </div>
            )}

            {activeTab === 'mercado' && (
               <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8 pb-10">
                  {gameState.marketPrices.map(price => {
                    const stock = gameState.inventory[price.cropId] || 0;
                    return (
                      <div key={price.cropId} className="bg-zinc-900/60 border border-white/5 p-10 rounded-[4rem] flex flex-col gap-8 shadow-2xl">
                        <div className="flex justify-between items-center">
                          <div className="w-16 h-16 bg-zinc-950 rounded-[2rem] flex items-center justify-center text-4xl shadow-xl">{price.cropId === 'milho' ? '🌽' : '📦'}</div>
                        </div>
                        <div>
                          <h4 className="text-[12px] font-black uppercase text-zinc-600 tracking-[0.4em] mb-1">{price.cropId.replace('_', ' ')}</h4>
                          <p className="text-4xl font-black text-white tracking-tighter leading-none">R$ {price.price}</p>
                        </div>
                        <div className="flex justify-between p-6 bg-black/40 rounded-[2.5rem] border border-white/5">
                           <span className="text-[11px] font-black text-zinc-500 uppercase">Estoque</span>
                           <span className="text-2xl font-black text-emerald-500">{stock}</span>
                        </div>
                        <button onClick={() => handleSell(price.cropId, stock)} disabled={stock === 0} className="w-full py-5 bg-zinc-800 hover:bg-emerald-500 hover:text-black rounded-[1.8rem] text-[10px] font-black uppercase transition-all disabled:opacity-20">Liquidar Estoque</button>
                      </div>
                    );
                  })}
               </div>
            )}
          </main>
        </>
      )}

      {/* Modal de Sementes */}
      {selectedPlot !== null && (
        <div className="fixed inset-0 z-[300] bg-black/98 backdrop-blur-3xl flex items-center justify-center p-8 animate-in fade-in duration-300">
           <div className="w-full max-w-4xl bg-[#0a0a0a] border border-white/10 rounded-[6rem] overflow-hidden shadow-2xl animate-in zoom-in-95 duration-500">
              <div className="p-16 border-b border-white/5 flex justify-between items-center bg-zinc-950/20">
                 <div>
                    <h3 className="text-5xl font-black italic tracking-tighter uppercase leading-none">Sementes <span className="text-emerald-500">Premium</span></h3>
                    <p className="text-[12px] font-black text-zinc-600 uppercase tracking-[0.5em] mt-3">Cultivo estratégico - Custos {ENERGY_COSTS.PLANT}⚡</p>
                 </div>
                 <button onClick={() => setSelectedPlot(null)} className="p-8 bg-zinc-900 rounded-[2.5rem] text-zinc-500 hover:text-white transition-all"><X size={48}/></button>
              </div>
              <div className="p-16 grid grid-cols-1 md:grid-cols-2 gap-8 max-h-[60vh] overflow-y-auto scrollbar-hide">
                 {CROPS.map(c => (
                   <button 
                    key={c.id} 
                    disabled={gameState.level < c.minLevel || gameState.credits < c.cost || gameState.energy < ENERGY_COSTS.PLANT}
                    onClick={() => handlePlant(selectedPlot, c.id)}
                    className={`p-10 rounded-[4rem] border-4 flex items-center justify-between transition-all ${gameState.level < c.minLevel ? 'opacity-20 bg-black cursor-not-allowed border-zinc-900' : 'bg-zinc-900/60 border-white/5 hover:border-emerald-500/40 hover:scale-[1.02] shadow-2xl'}`}
                   >
                     <div className="flex items-center gap-8 text-left">
                        <span className="text-7xl drop-shadow-2xl">{c.emoji}</span>
                        <div>
                           <p className="font-black text-2xl text-white tracking-tighter">{c.name}</p>
                           <p className="text-xl font-black text-emerald-500 tracking-tighter">R$ {c.cost.toLocaleString()}</p>
                        </div>
                     </div>
                     {gameState.level < c.minLevel && <Lock size={32} className="text-zinc-700"/>}
                   </button>
                 ))}
              </div>
           </div>
        </div>
      )}
    </div>
  );
};

export default AgroBrazil;

export enum IdentityType {
  REAL = 'REAL',
  PROFESSIONAL = 'PROFESSIONAL'
}

export enum UserPlan {
  FREE = 'FREE',
  PREMIUM = 'PREMIUM'
}

export enum UserStatus {
  ONLINE = 'ONLINE',
  BUSY = 'BUSY',
  AWAY = 'AWAY',
  INVISIBLE = 'INVISIBLE',
  OFFLINE = 'OFFLINE'
}

export interface User {
  id: string;
  name: string;
  username: string;
  email: string;
  age: number;
  birthDate: string;
  identityType: IdentityType;
  reputation: number;
  level: number;
  xp: number;
  verified: boolean;
  plan: UserPlan;
  bio: string;
  avatar: string;
  location: string;
  friends: string[];
  bookmarks: string[];
  joinedCommunities: string[];
  friendRequests: { fromId: string; timestamp: string }[];
  wishlist?: string[];
  privacy: {
    isPublic: boolean;
    showLocation: boolean;
    allowStrangersMsg: boolean;
    showOnlineStatus: boolean;
    incognitoMode?: boolean;
  };
  status: UserStatus;
  statusPhrase?: string;
  currentMusic?: string;
  currentMood?: string;
  ultima_atividade: number; 
  createdAt?: string;
  themePreference?: 'dark' | 'light' | 'nostalgia';
  animatedAvatar?: boolean;
}

export type PlotStatus = 'locked' | 'empty' | 'planted' | 'growing' | 'ready' | 'partial_loss' | 'total_loss';

export interface AgroPlot {
  id: number;
  cropId: string | null;
  plantedAt: number | null;
  status: PlotStatus;
  quality: number; 
  isNightPlanted?: boolean;
}

export interface AgroPen {
  id: number;
  animalId: string | null;
  startedAt: number | null;
  status: 'locked' | 'empty' | 'active' | 'ready' | 'sick';
  health: number;
}

export interface MarketPrice {
  cropId: string;
  price: number;
  trend: 'up' | 'down' | 'stable';
  basePrice: number;
}

export interface ExportContract {
  id: string;
  targetItem: string;
  quantity: number;
  reward: number;
  premiumReward: number;
  expiresAt: number;
  bonusXp: number;
  destination: string;
}

export interface AgroEvent {
  id: string;
  title: string;
  description: string;
  effect: 'price_up' | 'price_down' | 'risk_up' | 'yield_up' | 'xp_double';
  targetCrop: string;
  multiplier: number;
  expiresAt: number;
}

export interface AgroMission {
  id: string;
  title: string;
  description: string;
  targetCount: number;
  currentCount: number;
  rewardCredits: number;
  rewardGems: number;
  type: 'daily' | 'weekly';
  isClaimed: boolean;
}

export interface AgroCoop {
  id: string;
  name: string;
  members: string[];
  totalCredits: number;
  totalReputation: number;
  goal: {
    title: string;
    item: string;
    target: number;
    current: number;
    deadline: number;
  } | null;
}

export interface AgroGameState {
  credits: number; 
  premiumCredits: number; 
  xp: number;
  level: number;
  energy: number;
  maxEnergy: number;
  plots: AgroPlot[];
  pens: AgroPen[];
  inventory: Record<string, number>;
  marketPrices: MarketPrice[];
  exportContracts: ExportContract[];
  activeEvents: AgroEvent[];
  missions: AgroMission[];
  machines: string[];
  coopId: string | null;
  lastCheck: number;
  feedStock: number;
  weeklyRevenue: number;
}

export interface AgroCrop {
  id: string;
  name: string;
  emoji: string;
  growthTime: number; 
  cost: number;
  baseYield: number;
  xp: number;
  minLevel: number;
  riskFactor: number;
}

export interface AgroAnimal {
  id: string;
  name: string;
  emoji: string;
  productionTime: number;
  cost: number;
  baseYield: number;
  xp: number;
  products: string[];
  minLevel: number;
}

export interface AgroMachine {
  id: string;
  name: string;
  emoji: string;
  cost: number;
  minLevel: number;
  bonusType: 'growth_speed' | 'yield_boost' | 'risk_reduction' | 'status_boost';
  bonusValue: number;
  description: string;
}

export interface Message {
  id: string;
  conversa_id: string;
