import { User, IdentityType, UserPlan, Notification, Post, Story, UserStatus, Message, Conversation, Product, Community, AgroGameState, MarketPrice, PlotStatus, AgroCoop, AgroMission } from '../types';

const USERS_KEY = 'tribo_users_v4';
const AGRO_KEY_PREFIX = 'tribo_agro_v4_';
const COOPS_KEY = 'tribo_coops_v4';
const POSTS_KEY = 'tribo_posts_v4';
const STORIES_KEY = 'tribo_stories_v4';
const NOTIFICATIONS_KEY_PREFIX = 'tribo_notifs_v4_';
const CONVERSATIONS_KEY = 'tribo_convs_v4';
const MESSAGES_KEY = 'tribo_msgs_v4';
const PRODUCTS_KEY = 'tribo_products_v4';
const COMMUNITIES_KEY = 'tribo_communities_v4';

export class UserDatabase {
  static getUsers(): User[] {
    const data = localStorage.getItem(USERS_KEY);
    let users: User[] = data ? JSON.parse(data) : [];

    if (!users.find(u => u.username === 'admin')) {
      const adminUser: User = {
        id: 'admin-001',
        name: 'Admin SOBERANO',
        username: 'admin',
        email: 'admin@tribo.com',
        age: 99,
        birthDate: '1900-01-01',
        identityType: IdentityType.PROFESSIONAL,
        reputation: 9999,
        level: 99,
        xp: 0,
        verified: true,
        plan: UserPlan.PREMIUM,
        bio: 'O arquiteto da rede TRIBO.',
        avatar: 'https://images.unsplash.com/photo-1535713875002-d1d0cf377fde?w=400&h=400&fit=crop',
        location: 'Matriz Tribo',
        friends: [],
        bookmarks: [],
        joinedCommunities: [],
        friendRequests: [],
        wishlist: [],
        privacy: { isPublic: true, showLocation: true, allowStrangersMsg: true, showOnlineStatus: true, incognitoMode: false },
        status: UserStatus.ONLINE,
        ultima_atividade: Date.now(),
        createdAt: new Date().toISOString(),
        themePreference: 'dark',
        animatedAvatar: true
      };
      users.push(adminUser);
      localStorage.setItem(USERS_KEY, JSON.stringify(users));
    }
    return users;
  }

  static findById(id: string): User | undefined {
    return this.getUsers().find(u => u.id === id);
  }

  static updateUser(user: User) {
    const users = this.getUsers();
    const index = users.findIndex(u => u.id === user.id);
    if (index !== -1) {
      users[index] = { ...user, ultima_atividade: Date.now() };
      localStorage.setItem(USERS_KEY, JSON.stringify(users));
    }
  }

  static authenticate(emailOrUsername: string, password?: string): User | null {
    const users = this.getUsers();
    return users.find(u => u.email === emailOrUsername || u.username === emailOrUsername) || null;
  }

  static saveUser(userData: Partial<User>): User {
    const users = this.getUsers();
    const newUser: User = {
      id: Math.random().toString(36).substr(2, 9),
      name: userData.name || 'Membro da Tribo',
      username: userData.username || 'user',
      email: userData.email || '',
      age: userData.age || 18,
      birthDate: userData.birthDate || new Date().toISOString(),
      identityType: userData.identityType || IdentityType.REAL,
      reputation: 10,
      level: 1,
      xp: 0,
      verified: false,
      plan: UserPlan.FREE,
      bio: userData.bio || '',
      avatar: userData.avatar || `https://picsum.photos/seed/${userData.username}/200`,
      location: userData.location || '',
      friends: [],
      bookmarks: [],
      joinedCommunities: [],
      friendRequests: [],
      wishlist: [],
      privacy: { isPublic: true, showLocation: true, allowStrangersMsg: true, showOnlineStatus: true, incognitoMode: false },
      status: UserStatus.ONLINE,
      ultima_atividade: Date.now(),
      createdAt: new Date().toISOString(),
      themePreference: 'dark',
      ...userData
    };
    users.push(newUser);
    localStorage.setItem(USERS_KEY, JSON.stringify(users));
    return newUser;
  }

  static getAgroState(userId: string): AgroGameState {
    const key = AGRO_KEY_PREFIX + userId;
    const data = localStorage.getItem(key);
    if (data) return JSON.parse(data);

    const initialState: AgroGameState = {
      credits: 5000,
      premiumCredits: 50,
      xp: 0,
      level: 1,
      energy: 100,
      maxEnergy: 100,
      feedStock: 100,
      coopId: null,
      weeklyRevenue: 0,
      inventory: { 'milho': 100, 'racao': 50 },
      plots: Array.from({ length: 16 }, (_, i) => ({
        id: i, cropId: null, plantedAt: null, status: (i < 4 ? 'empty' : 'locked') as PlotStatus, quality: 1.0
      })),
      pens: Array.from({ length: 8 }, (_, i) => ({
        id: i, animalId: null, startedAt: null, status: (i < 2 ? 'empty' : 'locked'), health: 1.0
      })),
      marketPrices: [
        { cropId: 'milho', price: 50, basePrice: 50, trend: 'stable' },
        { cropId: 'soja', price: 120, basePrice: 120, trend: 'up' },
        { cropId: 'cana', price: 40, basePrice: 40, trend: 'stable' },
        { cropId: 'leite', price: 80, basePrice: 80, trend: 'stable' },
        { cropId: 'carne_premium', price: 450, basePrice: 450, trend: 'up' },
      ],
      exportContracts: [],
      activeEvents: [],
      missions: [
        { id: 'm1', title: 'Primeira Safra', description: 'Colha 100 Milho', targetCount: 100, currentCount: 0, rewardCredits: 500, rewardGems: 1, type: 'daily', isClaimed: false },
        { id: 'm2', title: 'Engorda de Elite', description: 'Produza 50 Ração', targetCount: 50, currentCount: 0, rewardCredits: 1000, rewardGems: 2, type: 'daily', isClaimed: false },
        { id: 'm3', title: 'Barão da Soja', description: 'Exportar 500 Soja', targetCount: 500, currentCount: 0, rewardCredits: 5000, rewardGems: 10, type: 'weekly', isClaimed: false }
      ],
      machines: [],
      lastCheck: Date.now()
    };
    localStorage.setItem(key, JSON.stringify(initialState));
    return initialState;
  }

  static saveAgroState(userId: string, state: AgroGameState) {
    localStorage.setItem(AGRO_KEY_PREFIX + userId, JSON.stringify(state));
  }

  static getCoops(): AgroCoop[] {
    const data = localStorage.getItem(COOPS_KEY);
    if (data) return JSON.parse(data);

    const initialCoop: AgroCoop = {
      id: 'coop-br-001',
      name: 'Cooperativa Nacional',
      members: ['admin-001'],
      totalCredits: 1000000,
      totalReputation: 5000,
      goal: { title: 'Exportação de Natal', item: 'soja', target: 50000, current: 12500, deadline: Date.now() + 604800000 }
    };
    localStorage.setItem(COOPS_KEY, JSON.stringify([initialCoop]));
    return [initialCoop];
  }

  static saveCoop(coop: AgroCoop) {
    const coops = this.getCoops();
    const idx = coops.findIndex(c => c.id === coop.id);
    if (idx !== -1) coops[idx] = coop;
    else coops.push(coop);
    localStorage.setItem(COOPS_KEY, JSON.stringify(coops));
  }

  static getNotifications(userId: string): Notification[] {
    return JSON.parse(localStorage.getItem(NOTIFICATIONS_KEY_PREFIX + userId) || '[]');
  }

  static addNotification(userId: string, notif: Omit<Notification, 'id' | 'read'>) {
    const notifs = this.getNotifications(userId);
    notifs.unshift({ ...notif, id: Math.random().toString(36).substr(2, 9), read: false });
    localStorage.setItem(NOTIFICATIONS_KEY_PREFIX + userId, JSON.stringify(notifs.slice(0, 20)));
  }

  static getStories(): Story[] {
    const stories: Story[] = JSON.parse(localStorage.getItem(STORIES_KEY) || '[]');
    const now = Date.now();
    return stories.filter(s => now - s.timestamp < 24 * 60 * 60 * 1000);
  }

  static saveStory(story: Story): void {
    const stories = this.getStories();
    stories.unshift(story);
    localStorage.setItem(STORIES_KEY, JSON.stringify(stories));
  }

  static getDiscoverableUsers(excludeId: string): User[] {
    return this.getUsers().filter(u => u.id !== excludeId);
  }

  static searchUsers(term: string, excludeId: string): User[] {
    const lower = term.toLowerCase();
    return this.getUsers().filter(u => u.id !== excludeId && (u.name.toLowerCase().includes(lower) || u.username.toLowerCase().includes(lower)));
  }

  static sendFriendRequest(fromId: string, toId: string): boolean {
    const target = this.findById(toId);
    if (!target) return false;
    if (target.friendRequests.some(r => r.fromId === fromId)) return false;
    target.friendRequests.push({ fromId, timestamp: new Date().toISOString() });
    this.updateUser(target);
    return true;
  }

  static hasSentRequest(fromId: string, toId: string): boolean {
    const target = this.findById(toId);
    return !!target?.friendRequests.some(r => r.fromId === fromId);
  }

  static acceptFriendRequest(userId: string, fromId: string): void {
    const user = this.findById(userId);
    const sender = this.findById(fromId);
    if (user && sender) {
      user.friendRequests = user.friendRequests.filter(r => r.fromId !== fromId);
      if (!user.friends.includes(fromId)) user.friends.push(fromId);
      if (!sender.friends.includes(userId)) sender.friends.push(userId);
      this.updateUser(user);
      this.updateUser(sender);
    }
  }

  static removeFriend(userId: string, targetId: string): void {
    const user = this.findById(userId);
    const sender = this.findById(targetId);
    if (user && sender) {
      user.friends = user.friends.filter(id => id !== targetId);
      sender.friends = sender.friends.filter(id => id !== userId);
      this.updateUser(user);
      this.updateUser(sender);
    }
  }

  static getFeed(userId: string, mode: 'global' | 'tribo'): Post[] {
    const posts: Post[] = JSON.parse(localStorage.getItem(POSTS_KEY) || '[]');
    if (mode === 'tribo') {
      const user = this.findById(userId);
      return user ? posts.filter(p => user.friends.includes(p.authorId) || p.authorId === userId) : posts;
    }
    return posts;
  }

  static savePost(post: Post): void {
    const posts: Post[] = JSON.parse(localStorage.getItem(POSTS_KEY) || '[]');
    posts.unshift(post);
    localStorage.setItem(POSTS_KEY, JSON.stringify(posts));
  }

  static reactToPost(postId: string, userId: string): void {
    const posts: Post[] = JSON.parse(localStorage.getItem(POSTS_KEY) || '[]');
    const idx = posts.findIndex(p => p.id === postId);
    if (idx !== -1) {
      if (!posts[idx].likedBy) posts[idx].likedBy = [];
      const lIdx = posts[idx].likedBy.indexOf(userId);
      if (lIdx === -1) posts[idx].likedBy.push(userId);
      else posts[idx].likedBy.splice(lIdx, 1);
      localStorage.setItem(POSTS_KEY, JSON.stringify(posts));
    }
  }

  static async uploadFile(file: File): Promise<string> {
    return new Promise((resolve) => {
      const reader = new FileReader();
      reader.onloadend = () => resolve(reader.result as string);
      reader.readAsDataURL(file);
    });
  }

  static getConversations(userId: string): Conversation[] {
    const all: Conversation[] = JSON.parse(localStorage.getItem(CONVERSATIONS_KEY) || '[]');
    return all.filter(c => c.participantes.some(p => p.user_id === userId));
  }

  static getMessagesPaginated(convId: string, limit: number): { messages: Message[], hasMore: boolean } {
    const all: Message[] = JSON.parse(localStorage.getItem(MESSAGES_KEY) || '[]');
    const filtered = all.filter(m => m.conversa_id === convId);
    return { messages: filtered.slice(-limit), hasMore: filtered.length > limit };
  }

  static markMessagesAsRead(convId: string, userId: string): void {
    const all: Message[] = JSON.parse(localStorage.getItem(MESSAGES_KEY) || '[]');
    all.forEach(m => { if (m.conversa_id === convId && m.remetente_id !== userId) m.lida = true; });
    localStorage.setItem(MESSAGES_KEY, JSON.stringify(all));
  }

  static sendMessage(msg: Message): void {
    const all: Message[] = JSON.parse(localStorage.getItem(MESSAGES_KEY) || '[]');
    all.push(msg);
    localStorage.setItem(MESSAGES_KEY, JSON.stringify(all));
  }

  static getProducts(): Product[] { return JSON.parse(localStorage.getItem(PRODUCTS_KEY) || '[]'); }
  static saveProduct(p: Product) { 
    const products = this.getProducts(); 
    products.unshift(p); 
    localStorage.setItem(PRODUCTS_KEY, JSON.stringify(products)); 
  }

  static toggleWishlist(uId: string, pId: string) {
    const user = this.findById(uId);
    if (user) {
      if (!user.wishlist) user.wishlist = [];
      const idx = user.wishlist.indexOf(pId);
      if (idx === -1) user.wishlist.push(pId);
      else user.wishlist.splice(idx, 1);
      this.updateUser(user);
    }
  }

  static incrementProductViews(id: string) {
    const products = this.getProducts();
    const idx = products.findIndex(p => p.id === id);
    if (idx !== -1) {
      products[idx].views = (products[idx].views || 0) + 1;
      localStorage.setItem(PRODUCTS_KEY, JSON.stringify(products));
    }
  }

  static getCommunities(): Community[] { return JSON.parse(localStorage.getItem(COMMUNITIES_KEY) || '[]'); }
  static saveCommunity(c: Community) { 
    const comms = this.getCommunities(); 
    comms.unshift(c); 
    localStorage.setItem(COMMUNITIES_KEY, JSON.stringify(comms)); 
  }

  static toggleJoinCommunity(userId: string, communityId: string) {
    const user = this.findById(userId);
    const communities = this.getCommunities();
    const commIndex = communities.findIndex(c => c.id === communityId);
    if (user && commIndex !== -1) {
      const community = communities[commIndex];
      const memberIdx = community.members.indexOf(userId);
      if (!user.joinedCommunities) user.joinedCommunities = [];
      if (memberIdx === -1) {
        community.members.push(userId);
        if (!user.joinedCommunities.includes(communityId)) user.joinedCommunities.push(communityId);
      } else {
        community.members.splice(memberIdx, 1);
        user.joinedCommunities = user.joinedCommunities.filter(id => id !== communityId);
      }
      localStorage.setItem(COMMUNITIES_KEY, JSON.stringify(communities));
      this.updateUser(user);
    }
  }
}

import React, { useState, useEffect, useMemo } from 'react';
import { 
  ChevronLeft, Plus, X, Tractor, Lock, TrendingUp, TrendingDown,
  Sprout, Factory, ShoppingBag, Trophy, Loader2, Zap, Star, 
  ArrowRight, Flame, Wallet, History, CheckCircle2,
  Globe, Ship, Anchor, Diamond, AlertCircle, 
  Settings2, Target, Users2, Building2, Moon, Sun, Gift, Sparkles, Battery, Timer,
  Medal, Crown, ArrowUpRight
} from 'lucide-react';
import { User, AgroCrop, AgroGameState, AgroPlot, PlotStatus, AgroEvent, AgroCoop, AgroMission, UserStatus } from '../types';
import { UserDatabase } from '../services/db';

const ENERGY_COSTS = { PLANT: 5, HARVEST: 3, PROCESS: 10, EXPORT: 15 };

const CROPS: AgroCrop[] = [
  { id: 'milho', name: 'Milho', emoji: '🌽', growthTime: 20, cost: 40, baseYield: 120, xp: 20, minLevel: 1, riskFactor: 0.04 },
  { id: 'soja', name: 'Soja', emoji: '🌱', growthTime: 60, cost: 300, baseYield: 800, xp: 150, minLevel: 2, riskFactor: 0.08 },
  { id: 'cana', name: 'Cana', emoji: '🎋', growthTime: 120, cost: 1200, baseYield: 4000, xp: 900, minLevel: 4, riskFactor: 0.12 },
  { id: 'cafe', name: 'Café Especial', emoji: '☕', growthTime: 180, cost: 5000, baseYield: 15000, xp: 4000, minLevel: 10, riskFactor: 0.15 },
];

const THEMATIC_EVENTS = [
  { id: 'festa_milho', title: 'Festa do Milho', description: 'O preço do Milho triplicou na Tribo!', effect: 'price_up', targetCrop: 'milho', multiplier: 3.0 },
  { id: 'expo_agro', title: 'ExpoAgro 2026', description: 'Bônus de 2x XP em todas as colheitas!', effect: 'xp_double', targetCrop: 'all', multiplier: 2.0 },
  { id: 'leilao_gado', title: 'Leilão de Elite', description: 'Produtos de pecuária com valor recorde.', effect: 'price_up', targetCrop: 'carne_premium', multiplier: 2.5 },
];

const TITLES = [
  { minLevel: 1, title: 'Pequeno Produtor', color: 'text-zinc-500' },
  { minLevel: 10, title: 'Agricultor Regional', color: 'text-emerald-500' },
  { minLevel: 25, title: 'Produtor Nacional', color: 'text-blue-500' },
  { minLevel: 50, title: 'Exportador Master', color: 'text-amber-500' },
  { minLevel: 75, title: 'Barão do Agro', color: 'text-rose-500 font-black' },
  { minLevel: 100, title: 'Rei do Agro Brasileiro', color: 'text-white font-black italic animate-pulse' },
];

const AgroBrazil: React.FC<{ currentUser: User }> = ({ currentUser }) => {
  const [isLobby, setIsLobby] = useState(true);
  const [activeTab, setActiveTab] = useState<'fazenda' | 'mercado' | 'missões' | 'ranking' | 'coop' | 'caixa'>('fazenda');
  const [rankingFilter, setRankingFilter] = useState<'nacional' | 'amigos' | 'semanal' | 'cooperativas'>('nacional');
  const [selectedPlot, setSelectedPlot] = useState<number | null>(null);
  const [isProcessing, setIsProcessing] = useState<string | null>(null);
  const [surpriseBoxOpening, setSurpriseBoxOpening] = useState(false);
  const [boxResult, setBoxResult] = useState<string | null>(null);

  const [gameState, setGameState] = useState<AgroGameState>(() => 
    UserDatabase.getAgroState(currentUser.id)
  );

  const isNight = useMemo(() => {
    const hours = new Date().getHours();
    return hours >= 20 || hours < 6;
  }, []);

  const currentTitle = useMemo(() => {
    return [...TITLES].reverse().find(t => gameState.level >= t.minLevel) || TITLES[0];
  }, [gameState.level]);

  const activeCoop = useMemo(() => {
    if (!gameState.coopId) return null;
    return UserDatabase.getCoops().find(c => c.id === gameState.coopId);
  }, [gameState.coopId]);

  // Rankings Logic
  const rankings = useMemo(() => {
    const allUsers = UserDatabase.getUsers();
    const list = allUsers.map(u => ({
      id: u.id,
      name: u.name,
      avatar: u.avatar,
      level: u.level,
      agro: UserDatabase.getAgroState(u.id)
    }));

    if (rankingFilter === 'cooperativas') {
      return UserDatabase.getCoops().sort((a, b) => b.totalReputation - a.totalReputation);
    }
    if (rankingFilter === 'amigos') {
      return list.filter(u => currentUser.friends.includes(u.id) || u.id === currentUser.id).sort((a, b) => b.agro.credits - a.agro.credits);
    }
    if (rankingFilter === 'semanal') {
      return list.sort((a, b) => b.agro.weeklyRevenue - a.agro.weeklyRevenue);
    }
    return list.sort((a, b) => b.agro.credits - a.agro.credits);
  }, [rankingFilter, currentUser.id, currentUser.friends]);

  // Gameloop: Energia, Safra, Mercado
  useEffect(() => {
    const interval = setInterval(() => {
      const now = Date.now();
      setGameState(prev => {
        let nextEnergy = Math.min(prev.maxEnergy, prev.energy + 0.1); 

        const nextPlots = prev.plots.map(p => {
          if (!p.cropId || !p.plantedAt || p.status === 'locked' || p.status === 'empty' || p.status === 'ready') return p;
          const crop = CROPS.find(c => c.id === p.cropId);
          if (!crop) return p;

          const speedBuff = p.isNightPlanted ? 1.3 : 1.0;
          const elapsed = (now - p.plantedAt) / 1000;
          const progress = elapsed / (crop.growthTime / speedBuff);

          if (progress >= 1.0) return { ...p, status: 'ready' as PlotStatus };
          if (progress > 0.1) return { ...p, status: 'growing' as PlotStatus };
          return p;
        });

        const nextMarket = prev.marketPrices.map(mp => {
           let price = mp.price * (1 + (Math.random() * 0.01 - 0.005)); 
           const ev = prev.activeEvents.find(e => e.targetCrop === mp.cropId && e.effect === 'price_up');
           if (ev) price *= 1.05;
           return { ...mp, price: Math.max(10, Math.floor(price)), trend: price > mp.price ? 'up' : 'down' as any };
        });

        const nextEvents = prev.activeEvents.filter(e => e.expiresAt > now);
        if (nextEvents.length < 1 && Math.random() > 0.998) {
          const template = THEMATIC_EVENTS[Math.floor(Math.random() * THEMATIC_EVENTS.length)];
          nextEvents.push({ ...template, id: Math.random().toString(36).substr(2,4), expiresAt: now + 900000 } as AgroEvent);
        }

        const newState = { ...prev, energy: nextEnergy, plots: nextPlots, marketPrices: nextMarket, activeEvents: nextEvents, lastCheck: now };
        UserDatabase.saveAgroState(currentUser.id, newState);
        return newState;
      });
    }, 1000);
    return () => clearInterval(interval);
  }, [currentUser.id]);

  const updateMission = (action: string, count: number) => {
    setGameState(prev => {
      const nextMissions = prev.missions.map(m => {
        if (m.isClaimed) return m;
        if (m.description.toLowerCase().includes(action.toLowerCase())) {
          return { ...m, currentCount: Math.min(m.targetCount, m.currentCount + count) };
        }
        return m;
      });
      return { ...prev, missions: nextMissions };
    });
  };

  const handlePlant = (plotId: number, cropId: string) => {
    const crop = CROPS.find(c => c.id === cropId);
    if (!crop || gameState.credits < crop.cost || gameState.energy < ENERGY_COSTS.PLANT) return;
    setGameState(prev => ({
      ...prev,
      credits: prev.credits - crop.cost,
      energy: prev.energy - ENERGY_COSTS.PLANT,
      plots: prev.plots.map(p => p.id === plotId ? { ...p, cropId, plantedAt: Date.now(), status: 'planted', quality: 1.0, isNightPlanted: isNight } : p)
    }));
    setSelectedPlot(null);
  };

  const handleHarvest = (plotId: number) => {
    const plot = gameState.plots.find(p => p.id === plotId);
    if (!plot || !plot.cropId || gameState.energy < ENERGY_COSTS.HARVEST) return;
    const crop = CROPS.find(c => c.id === plot.cropId);
    if (!crop) return;
    const xpMult = gameState.activeEvents.some(e => e.effect === 'xp_double') ? 2 : 1;
    const yieldAmt = Math.floor(crop.baseYield * plot.quality);

    setGameState(prev => {
      const inv = { ...prev.inventory };
      inv[crop.id] = (inv[crop.id] || 0) + yieldAmt;
      return {
        ...prev,
        energy: prev.energy - ENERGY_COSTS.HARVEST,
        inventory: inv,
        xp: prev.xp + (crop.xp * xpMult),
        plots: prev.plots.map(p => p.id === plotId ? { ...p, cropId: null, plantedAt: null, status: 'empty' } : p)
      };
    });
    updateMission(crop.name, yieldAmt);
  };

  const openSurpriseBox = async () => {
    if (gameState.credits < 1000 || surpriseBoxOpening) return;
    setSurpriseBoxOpening(true);
    setBoxResult(null);
    await new Promise(r => setTimeout(r, 2000));
    const roll = Math.random();
    let reward = "Bagaço de Cana (Nada)";
    let credits = -1000;
    let energy = 0;
    let gems = 0;

    if (roll > 0.95) { reward = "💎 50 AgroGems!"; gems = 50; }
    else if (roll > 0.8) { reward = "⚡ 100 Energia!"; energy = 100; }
    else if (roll > 0.4) { reward = "💰 R$ 2.500!"; credits += 2500; }
    else { reward = "📦 Sementes Comuns"; energy = 10; }

    setGameState(prev => ({
      ...prev,
      credits: prev.credits + credits,
      energy: Math.min(prev.maxEnergy + 100, prev.energy + energy),
      premiumCredits: prev.premiumCredits + gems
    }));
    setBoxResult(reward);
    setSurpriseBoxOpening(false);
  };

  return (
    <div className={`h-[calc(100vh-175px)] rounded-[3.5rem] border border-white/5 flex flex-col overflow-hidden shadow-2xl relative transition-all duration-1000 ${isNight ? 'bg-[#01050a]' : 'bg-[#010a05]'}`}>

