    oscillator.type = 'sine';
    oscillator.frequency.setValueAtTime(550, audioCtx.currentTime);
    oscillator.frequency.exponentialRampToValueAtTime(800, audioCtx.currentTime + 0.1);
    gainNode.gain.setValueAtTime(0.1, audioCtx.currentTime);
    gainNode.gain.exponentialRampToValueAtTime(0.01, audioCtx.currentTime + 0.1);
    oscillator.connect(gainNode);
    gainNode.connect(audioCtx.destination);
    oscillator.start();
    oscillator.stop(audioCtx.currentTime + 0.1);
  } catch (e) {}
};

// --- STORY VIEWER COMPONENT ---
const StoryViewer: React.FC<{ stories: Story[]; initialIndex: number; onClose: () => void }> = ({ stories, initialIndex, onClose }) => {
  const [currentIndex, setCurrentIndex] = useState(initialIndex);
  const [progress, setProgress] = useState(0);
  const story = stories[currentIndex];

  useEffect(() => {
    setProgress(0);
    const duration = 5000; // 5 segundos por story
    const interval = 50; 
    const step = (interval / duration) * 100;

    const timer = setInterval(() => {
      setProgress(prev => {
        if (prev >= 100) {
          if (currentIndex < stories.length - 1) {
            setCurrentIndex(prevIdx => prevIdx + 1);
            return 0;
          } else {
            onClose();
            return 100;
          }
        }
        return prev + step;
      });
    }, interval);

    return () => clearInterval(timer);
  }, [currentIndex, stories.length, onClose]);

  return (
    <div className="fixed inset-0 z-[300] bg-black flex flex-col animate-in fade-in duration-300">
      <div className={`flex-grow flex flex-col bg-gradient-to-br ${story.color} relative overflow-hidden`}>
        {/* Progress Indicators */}
        <div className="absolute top-safe pt-4 left-4 right-4 flex gap-1.5 z-50">
          {stories.map((_, i) => (
            <div key={i} className="h-1 flex-grow bg-white/20 rounded-full overflow-hidden">
              <div 
                className="h-full bg-white transition-all duration-75" 
                style={{ width: i < currentIndex ? '100%' : i === currentIndex ? `${progress}%` : '0%' }}
              />
            </div>
          ))}
        </div>

        {/* Header */}
        <div className="absolute top-safe pt-10 left-6 right-6 flex justify-between items-center z-50">
          <div className="flex items-center gap-3">
            <img src={story.userAvatar} className="w-10 h-10 rounded-xl border-2 border-white/20 object-cover" alt="" />
            <div>
              <p className="font-black text-sm text-white tracking-tight">{story.userName}</p>
              <p className="text-[8px] font-black uppercase text-white/60 tracking-widest">Postado agora</p>
            </div>
          </div>
          <button onClick={onClose} className="p-2 text-white/60 hover:text-white transition-colors"><X size={28}/></button>
        </div>

        {/* Content */}
        <div className="flex-grow flex items-center justify-center p-12 text-center">
          <h2 className="text-4xl md:text-5xl font-black text-white italic tracking-tighter drop-shadow-2xl animate-in zoom-in duration-500">
            {story.content}
          </h2>
        </div>

        {/* Navigation Overlays */}
        <div className="absolute inset-0 flex">
          <div className="w-1/3 h-full cursor-pointer" onClick={() => currentIndex > 0 && setCurrentIndex(currentIndex - 1)} />
          <div className="w-2/3 h-full cursor-pointer" onClick={() => currentIndex < stories.length - 1 ? setCurrentIndex(currentIndex + 1) : onClose()} />
        </div>
      </div>
    </div>
  );
};

