const StoryCreator: React.FC<{ currentUser: User; onClose: () => void; onCreated: () => void }> = ({ currentUser, onClose, onCreated }) => {
  const [text, setText] = useState('');
  const [loading, setLoading] = useState(false);
  const colors = [
    'from-emerald-500 to-teal-600',
    'from-rose-500 to-orange-500',
    'from-purple-600 to-pink-500',
    'from-blue-600 to-indigo-700',
    'from-zinc-900 to-black'
  ];
  const [selectedColor, setSelectedColor] = useState(colors[0]);

  const handlePost = async () => {
    if (!text.trim()) return;
    setLoading(true);
    const newStory: Story = {
      id: Math.random().toString(36).substr(2, 9),
      userId: currentUser.id,
      userName: currentUser.name,
      userAvatar: currentUser.avatar,
      userIdentity: currentUser.identityType,
      content: text,
      color: selectedColor,
      timestamp: Date.now()
    };
    await new Promise(r => setTimeout(r, 800));
    UserDatabase.saveStory(newStory);
    setLoading(false);
    onCreated();
    onClose();
  };

  return (
    <div className="fixed inset-0 z-[300] bg-black flex flex-col animate-in slide-in-from-bottom duration-500">
      <div className={`flex-grow flex items-center justify-center p-12 bg-gradient-to-br ${selectedColor} transition-all duration-700`}>
        <textarea 
          autoFocus
          value={text}
          onChange={(e) => setText(e.target.value)}
          placeholder="O que está rolando agora?"
          className="w-full bg-transparent border-none text-white text-4xl font-black text-center outline-none placeholder:text-white/30 resize-none max-w-lg scrollbar-hide"
          maxLength={120}
        />
        <div className="absolute top-safe p-6 left-0 right-0 flex justify-between items-center">
          <button onClick={onClose} className="p-3 bg-black/20 backdrop-blur-xl rounded-2xl text-white"><ChevronLeft size={24}/></button>
          <div className="flex gap-2">
            {colors.map(c => (
              <button 
                key={c} 
                onClick={() => setSelectedColor(c)} 
                className={`w-8 h-8 rounded-full border-2 ${selectedColor === c ? 'border-white scale-125 shadow-lg' : 'border-white/20'} bg-gradient-to-br ${c} transition-all`}
              />
            ))}
          </div>
        </div>
      </div>
      <div className="p-10 bg-black border-t border-white/5 pb-safe">
        <button 
          onClick={handlePost}
