const USERS_KEY = 'tribo_users_v5';
const AGRO_STATE_KEY = 'tribo_agro_v5_';
const MARKET_KEY = 'tribo_market_v5';
const COOPS_KEY = 'tribo_coops_v5';

export class UserDatabase {
  // --- BASE AUTH & USERS ---
  static getUsers(): User[] {
    const data = localStorage.getItem(USERS_KEY);
    return data ? JSON.parse(data) : [];
  }

  static findById(id: string): User | undefined {
    return this.getUsers().find(u => u.id === id);
  }

  static updateUser(user: User) {
    const users = this.getUsers();
    const index = users.findIndex(u => u.id === user.id);
    if (index !== -1) {
      users[index] = { ...user, ultima_atividade: Date.now() };
      localStorage.setItem(USERS_KEY, JSON.stringify(users));
    }
  }

  static authenticate(emailOrUsername: string, password?: string): User | null {
    return this.getUsers().find(u => u.email === emailOrUsername || u.username === emailOrUsername) || null;
  }

  static saveUser(userData: Partial<User>): User {
    const users = this.getUsers();
    const newUser: User = {
      id: Math.random().toString(36).substr(2, 9),
      name: userData.name || 'Membro',
      username: userData.username || 'user',
      email: userData.email || '',
      age: 18,
      birthDate: new Date().toISOString(),
      identityType: IdentityType.REAL,
      reputation: 10,
      level: 1,
      xp: 0,
      verified: false,
      plan: UserPlan.FREE,
      bio: '',
      avatar: `https://picsum.photos/seed/${userData.username}/200`,
      location: 'Brasil',
      friends: [],
      bookmarks: [],
      joinedCommunities: [],
      friendRequests: [],
      wishlist: [],
      privacy: { isPublic: true, showLocation: true, allowStrangersMsg: true, showOnlineStatus: true, incognitoMode: false },
      status: UserStatus.ONLINE,
      ultima_atividade: Date.now(),
      createdAt: new Date().toISOString(),
      themePreference: 'dark'
    };
    users.push(newUser);
    localStorage.setItem(USERS_KEY, JSON.stringify(users));
    return newUser;
  }

  // --- SCALABLE AGRO ENGINE (BACKEND SIMULATION) ---

  static getMarketPrices(): MarketPrice[] {
    const data = localStorage.getItem(MARKET_KEY);
    if (data) return JSON.parse(data);

    const initialMarket: MarketPrice[] = [
      { id: 'milho', name: 'Milho', emoji: '🌽', currentPrice: 50, basePrice: 50, trend: 'stable', volatility: 0.05 },
      { id: 'soja', name: 'Soja', emoji: '🌱', currentPrice: 120, basePrice: 120, trend: 'up', volatility: 0.08 },
      { id: 'cana', name: 'Cana', emoji: '🎋', currentPrice: 40, basePrice: 40, trend: 'stable', volatility: 0.03 },
      { id: 'cafe', name: 'Café', emoji: '☕', currentPrice: 450, basePrice: 450, trend: 'up', volatility: 0.15 },
    ];
    localStorage.setItem(MARKET_KEY, JSON.stringify(initialMarket));
    return initialMarket;
  }

  static getAgroState(userId: string): AgroGameState {
    const key = AGRO_STATE_KEY + userId;
    const data = localStorage.getItem(key);
    if (data) return JSON.parse(data);

    const initialState: AgroGameState = {
      credits: 5000,
      gems: 50,
      inventory: { 'milho': 100 },
      machines: [],
      coopId: null,
      transactions: [],
      activeEvents: [],
      missions: [
        { id: 'd1', title: 'Produtor Iniciante', type: 'daily', target: 50, current: 0, reward: { credits: 200, gems: 1 }, claimed: false }
      ],
      farm: {
        id: 'farm_' + userId,
        ownerId: userId,
        name: 'Fazenda SOBERANA',
        energy: 100,
        maxEnergy: 100,
        level: 1,
        xp: 0,
        plots: Array.from({ length: 16 }, (_, i) => ({
          id: i, cropId: null, plantedAt: null, status: i < 4 ? 'empty' : 'locked', quality: 1.0
        }))
      }
    };
    localStorage.setItem(key, JSON.stringify(initialState));
    return initialState;
  }

  static saveAgroState(userId: string, state: AgroGameState) {
    localStorage.setItem(AGRO_STATE_KEY + userId, JSON.stringify(state));
  }

  static logTransaction(userId: string, tx: Omit<AgroTransaction, 'id' | 'timestamp' | 'hash'>) {
    const state = this.getAgroState(userId);
    const newTx: AgroTransaction = {
      ...tx,
      id: 'tx_' + Math.random().toString(36).substr(2, 9),
      timestamp: Date.now(),
      hash: btoa(userId + tx.amount + Date.now()) // Simulação de hash de segurança
    };
    state.transactions.unshift(newTx);
    state.transactions = state.transactions.slice(0, 50); // Mantém apenas os últimos 50 logs
    this.saveAgroState(userId, state);
  }

  static getCoops(): AgroCoop[] {
    const data = localStorage.getItem(COOPS_KEY);
    return data ? JSON.parse(data) : [];
  }

  static saveCoop(coop: AgroCoop) {
    const coops = this.getCoops();
    const idx = coops.findIndex(c => c.id === coop.id);
    if (idx !== -1) coops[idx] = coop; else coops.push(coop);
    localStorage.setItem(COOPS_KEY, JSON.stringify(coops));
  }

  // --- SOCIAL HELPERS ---
  static getNotifications(userId: string): Notification[] { return []; }
  static getStories(): Story[] { return []; }
  static saveStory(s: Story) {}
  static getDiscoverableUsers(id: string): User[] { return []; }
  static searchUsers(t: string, id: string): User[] { return []; }
  static sendFriendRequest(f: string, t: string) { return true; }
  static hasSentRequest(f: string, t: string) { return false; }
  static acceptFriendRequest(u: string, f: string) {}
  static removeFriend(u: string, t: string) {}
  static getFeed(u: string, m: string): Post[] { return []; }
  static savePost(p: Post) {}
  static reactToPost(p: string, u: string) {}
  static async uploadFile(f: File): Promise<string> { return ''; }
  static getConversations(u: string): Conversation[] { return []; }
  static getMessagesPaginated(c: string, l: number): { messages: Message[], hasMore: boolean } { return { messages: [], hasMore: false }; }
  static markMessagesAsRead(c: string, u: string) {}
  static sendMessage(m: Message) {}
  static getProducts(): Product[] { return []; }
  static saveProduct(p: Product) {}
  static toggleWishlist(u: string, p: string) {}
  static incrementProductViews(id: string) {}
  static getCommunities(): Community[] { return []; }
  static saveCommunity(c: Community) {}
  static toggleJoinCommunity(u: string, c: string) {}
}

import React, { useState, useEffect, useMemo } from 'react';
import { 
  ChevronLeft, Plus, X, Tractor, Lock, TrendingUp, TrendingDown,
  Sprout, Factory, ShoppingBag, Trophy, Loader2, Zap, Star, 
  ArrowRight, Flame, Wallet, History, CheckCircle2,
  Globe, Ship, Anchor, Diamond, AlertCircle, 
  Settings2, Target, Users2, Building2, Moon, Sun, Gift, Sparkles, Battery, Timer,
  Medal, Crown, ArrowUpRight, BarChart3, ShieldCheck, Activity, Search
} from 'lucide-react';
import { User, AgroCrop, AgroGameState, AgroPlot, PlotStatus, AgroEvent, AgroCoop, AgroMission, MarketPrice, AgroTransaction } from '../types';
import { UserDatabase } from '../services/db';

const ENERGY_COSTS = { PLANT: 5, HARVEST: 3, PROCESS: 10, EXPORT: 15 };

const CROPS: AgroCrop[] = [
  { id: 'milho', name: 'Milho', emoji: '🌽', growthTime: 30, cost: 40, baseYield: 120, xp: 20, minLevel: 1, riskFactor: 0.04 },
  { id: 'soja', name: 'Soja', emoji: '🌱', growthTime: 60, cost: 300, baseYield: 800, xp: 150, minLevel: 2, riskFactor: 0.08 },
  { id: 'cana', name: 'Cana', emoji: '🎋', growthTime: 120, cost: 1200, baseYield: 4000, xp: 900, minLevel: 4, riskFactor: 0.12 },
  { id: 'cafe', name: 'Café Especial', emoji: '☕', growthTime: 300, cost: 5000, baseYield: 15000, xp: 4000, minLevel: 10, riskFactor: 0.15 },
];

const TITLES = [
  { minLevel: 1, title: 'Pequeno Produtor', color: 'text-zinc-500' },
  { minLevel: 10, title: 'Agricultor Regional', color: 'text-emerald-500' },
  { minLevel: 25, title: 'Produtor Nacional', color: 'text-blue-500' },
  { minLevel: 50, title: 'Exportador Master', color: 'text-amber-500' },
  { minLevel: 75, title: 'Barão do Agro', color: 'text-rose-500 font-black' },
  { minLevel: 100, title: 'Rei do Agro Brasileiro', color: 'text-white font-black italic animate-pulse' },
];

const AgroBrazil: React.FC<{ currentUser: User }> = ({ currentUser }) => {
  const [isLobby, setIsLobby] = useState(true);
  const [activeTab, setActiveTab] = useState<'fazenda' | 'mercado' | 'logs' | 'ranking' | 'coop'>('fazenda');
  const [gameState, setGameState] = useState<AgroGameState>(() => UserDatabase.getAgroState(currentUser.id));
  const [marketPrices, setMarketPrices] = useState<MarketPrice[]>(() => UserDatabase.getMarketPrices());
  const [selectedPlot, setSelectedPlot] = useState<number | null>(null);

  const isNight = useMemo(() => {
    const h = new Date().getHours();
    return h >= 20 || h < 6;
  }, []);

  const currentTitle = useMemo(() => {
    return [...TITLES].reverse().find(t => gameState.farm.level >= t.minLevel) || TITLES[0];
  }, [gameState.farm.level]);

  // ENGINE: Gameloop de Sincronização
  useEffect(() => {
    const tick = setInterval(() => {
      const now = Date.now();

      // 1. Atualizar Plantações
      setGameState(prev => {
        const nextPlots = prev.farm.plots.map(p => {
          if (!p.cropId || p.status !== 'growing') return p;
          const crop = CROPS.find(c => c.id === p.cropId);
          if (!crop) return p;
          const elapsed = (now - (p.plantedAt || 0)) / 1000;
          if (elapsed >= crop.growthTime) return { ...p, status: 'ready' as PlotStatus };
          return p;
        });

        // 2. Regenerar Energia
        const nextEnergy = Math.min(prev.farm.maxEnergy, prev.farm.energy + 0.5);

        const newState = { 
          ...prev, 
          farm: { ...prev.farm, plots: nextPlots, energy: nextEnergy } 
        };
        UserDatabase.saveAgroState(currentUser.id, newState);
        return newState;
      });

      // 3. Simular Mercado (Simulação de Backend)
      setMarketPrices(prev => {
        const next = prev.map(p => {
          const change = (Math.random() * p.volatility * 2 - p.volatility) * p.basePrice;
          const newPrice = Math.max(p.basePrice * 0.5, p.currentPrice + change);
          return { ...p, currentPrice: Math.floor(newPrice), trend: newPrice > p.currentPrice ? 'up' : 'down' as any };
        });
        localStorage.setItem('tribo_market_v5', JSON.stringify(next));
        return next;
      });

    }, 2000);
    return () => clearInterval(tick);
  }, [currentUser.id]);

  const handlePlant = (plotId: number, cropId: string) => {
    const crop = CROPS.find(c => c.id === cropId);
    if (!crop || gameState.credits < crop.cost || gameState.farm.energy < ENERGY_COSTS.PLANT) return;

    setGameState(prev => ({
      ...prev,
      credits: prev.credits - crop.cost,
      farm: {
        ...prev.farm,
        energy: prev.farm.energy - ENERGY_COSTS.PLANT,
        plots: prev.farm.plots.map(p => p.id === plotId ? {
          ...p, cropId, plantedAt: Date.now(), status: 'growing', isNightPlanted: isNight
        } : p)
      }
    }));

    UserDatabase.logTransaction(currentUser.id, {
      userId: currentUser.id, type: 'buy', amount: crop.cost, currency: 'credits', itemId: crop.id, quantity: 1
    });
    setSelectedPlot(null);
  };

  const handleHarvest = (plotId: number) => {
    const plot = gameState.farm.plots.find(p => p.id === plotId);
    if (!plot || plot.status !== 'ready' || gameState.farm.energy < ENERGY_COSTS.HARVEST) return;
    const crop = CROPS.find(c => c.id === plot.cropId);
    if (!crop) return;

    const yieldAmt = Math.floor(crop.baseYield * plot.quality);

    setGameState(prev => {
      const inv = { ...prev.inventory };
      inv[crop.id] = (inv[crop.id] || 0) + yieldAmt;
      return {
        ...prev,
        inventory: inv,
        farm: {
          ...prev.farm,
          energy: prev.farm.energy - ENERGY_COSTS.HARVEST,
          plots: prev.farm.plots.map(p => p.id === plotId ? { ...p, cropId: null, plantedAt: null, status: 'empty' } : p)
        }
      };
    });

    UserDatabase.logTransaction(currentUser.id, {
      userId: currentUser.id, type: 'harvest', amount: 0, currency: 'credits', itemId: crop.id, quantity: yieldAmt
    });
  };

  const handleSell = (cropId: string) => {
    const stock = gameState.inventory[cropId] || 0;
    const price = marketPrices.find(p => p.id === cropId)?.currentPrice || 0;
    if (stock <= 0 || price <= 0) return;

    const totalRevenue = stock * price;
    setGameState(prev => {
      const inv = { ...prev.inventory };
      inv[cropId] = 0;
      return { ...prev, credits: prev.credits + totalRevenue, inventory: inv };
    });

    UserDatabase.logTransaction(currentUser.id, {
      userId: currentUser.id, type: 'sell', amount: totalRevenue, currency: 'credits', itemId: cropId, quantity: stock
    });
  };

  return (
    <div className={`h-[calc(100vh-175px)] rounded-[3.5rem] border border-white/5 flex flex-col overflow-hidden shadow-2xl relative transition-all duration-1000 ${isNight ? 'bg-[#01050a]' : 'bg-[#010a05]'}`}>

      {/* Header Estilo Terminal Financeiro */}
      <header className="p-8 bg-black/60 backdrop-blur-3xl border-b border-white/5 flex items-center justify-between relative z-20">
        <div className="flex items-center gap-6">
          <button onClick={() => isLobby ? null : setIsLobby(true)} className="p-4 bg-zinc-900 text-zinc-500 rounded-2xl hover:text-white transition-all"><ChevronLeft size={24}/></button>
          <div className="flex items-center gap-4">
             <div className="relative">
                <div className={`w-14 h-14 rounded-2xl border flex items-center justify-center ${isNight ? 'bg-blue-500/10 border-blue-500/20 text-blue-400' : 'bg-emerald-500/10 border-emerald-500/20 text-emerald-500'}`}>
                   <Tractor size={32} />
                </div>
                <div className="absolute -top-1 -right-1 bg-black p-1 rounded-full border border-white/10">{isNight ? <Moon size={12} className="text-blue-400"/> : <Sun size={12} className="text-amber-400"/>}</div>
             </div>
             <div>
                <h2 className="text-xl font-black text-white italic tracking-tighter uppercase leading-none">AGRO <span className={isNight ? 'text-blue-500' : 'text-emerald-500'}>BRASIL</span></h2>
                <p className={`text-[9px] font-black uppercase tracking-widest mt-1.5 ${currentTitle.color}`}>{currentTitle.title}</p>
             </div>
          </div>
        </div>

        <div className="flex items-center gap-6">
           <div className="hidden md:flex flex-col items-end gap-1.5">
              <div className="flex items-center gap-3">
                 <span className="text-[10px] font-black text-zinc-500 uppercase tracking-widest">Saldo Soberano</span>
                 <span className="text-xl font-black text-emerald-500 tracking-tighter">R$ {gameState.credits.toLocaleString()}</span>
              </div>
              <div className="flex items-center gap-2">
                 <Battery size={12} className={gameState.farm.energy < 20 ? 'text-rose-500 animate-pulse' : 'text-blue-400'} />
                 <div className="w-32 h-1.5 bg-black rounded-full overflow-hidden border border-white/5">
                    <div className="h-full bg-blue-500 transition-all duration-500" style={{ width: `${(gameState.farm.energy / gameState.farm.maxEnergy) * 100}%` }} />
                 </div>
              </div>
           </div>
           <div className="px-6 py-4 bg-zinc-900 rounded-3xl border border-white/5 shadow-xl text-center min-w-[100px]">
              <span className="text-[10px] font-black text-zinc-500 uppercase block mb-1">Nível Farm</span>
              <span className="text-2xl font-black text-white">{gameState.farm.level}</span>
           </div>
        </div>
      </header>

      {isLobby ? (
        <div className="flex-1 flex flex-col items-center justify-center p-12 text-center space-y-12 relative z-10 overflow-y-auto scrollbar-hide">
           <div className="relative group">
              <div className="absolute inset-0 bg-emerald-500 blur-[150px] opacity-10 animate-pulse"></div>
              <img src="https://images.unsplash.com/photo-1523348837708-15d4a09cfac2?w=1000&h=500&fit=crop" className="w-full max-w-4xl h-96 object-cover rounded-[5rem] border-4 border-emerald-500/20 shadow-2xl relative z-10 transition-transform duration-1000 group-hover:scale-105" />
              <div className="absolute -bottom-10 -right-10 bg-amber-500 text-black p-12 rounded-[4rem] shadow-2xl z-20 rotate-12 transition-all hover:rotate-0">
                 <Crown size={64} fill="currentColor" />
              </div>
           </div>

           <div className="space-y-6 max-w-3xl">
              <h1 className="text-7xl md:text-9xl font-black italic text-white tracking-tighter leading-none">ECONOMIA<br/><span className={isNight ? 'text-blue-500' : 'text-emerald-500'}>RECURSIVA</span></h1>
              <p className="text-zinc-500 font-bold uppercase tracking-[0.4em] text-[12px] leading-relaxed">Estrutura escalável. Transações auditadas. Cooperativas reais. A maior rede produtiva da TRIBO.</p>
           </div>

           <button onClick={() => setIsLobby(false)} className="w-full max-w-md bg-emerald-500 hover:bg-emerald-400 text-black font-black py-12 rounded-[4rem] uppercase tracking-[0.4em] text-sm shadow-2xl shadow-emerald-500/20 active:scale-95 transition-all flex items-center justify-center gap-6">
              Assumir Comando <ArrowRight size={28} />
           </button>
        </div>
      ) : (
        <>
          {/* Navegação de Módulos */}
          <nav className="flex bg-black/40 p-3 border-b border-white/5 overflow-x-auto scrollbar-hide relative z-20 shrink-0">
            {[
              { id: 'fazenda', icon: Sprout, label: 'Produção' },
              { id: 'mercado', icon: BarChart3, label: 'Bolsa' },
              { id: 'logs', icon: Activity, label: 'Auditoria' },
              { id: 'ranking', icon: Trophy, label: 'Ranking' },
              { id: 'coop', icon: Users2, label: 'Gestão' }
            ].map(t => (
              <button 
                key={t.id} 
                onClick={() => setActiveTab(t.id as any)} 
                className={`flex-1 min-w-[120px] py-5 rounded-[2.5rem] text-[10px] font-black uppercase tracking-widest flex items-center justify-center gap-3 transition-all ${activeTab === t.id ? 'bg-emerald-500 text-black shadow-xl scale-105' : 'text-zinc-600 hover:text-zinc-400'}`}
              >
                <t.icon size={18}/> {t.label}
              </button>
            ))}
          </nav>

          <main className="flex-1 overflow-y-auto p-10 scrollbar-hide relative z-10">

            {/* AUDITORIA DE TRANSAÇÕES (ANTI-FRAUDE) */}
            {activeTab === 'logs' && (
               <div className="max-w-4xl mx-auto space-y-8 pb-10">
                  <div className="bg-zinc-900/60 p-12 rounded-[4rem] border border-white/5 flex items-center justify-between">
                     <div>
                        <h3 className="text-4xl font-black italic text-white uppercase tracking-tighter">LOG DE <span className="text-emerald-500">OPERAÇÕES</span></h3>
                        <p className="text-[10px] font-black text-zinc-500 uppercase tracking-[0.4em] mt-2">Transações validadas via motor SOBERANO</p>
                     </div>
                     <ShieldCheck size={48} className="text-emerald-500 opacity-20" />
                  </div>

                  <div className="space-y-4">
                     {gameState.transactions.map(tx => (
                        <div key={tx.id} className="bg-zinc-900/40 p-6 rounded-[2.5rem] border border-white/5 flex items-center justify-between group hover:border-emerald-500/20 transition-all">
                           <div className="flex items-center gap-6">
                              <div className={`w-14 h-14 rounded-2xl flex items-center justify-center ${tx.type === 'sell' ? 'bg-emerald-500/10 text-emerald-500' : tx.type === 'buy' ? 'bg-rose-500/10 text-rose-500' : 'bg-blue-500/10 text-blue-500'}`}>
                                 {tx.type === 'sell' ? <TrendingUp size={24}/> : tx.type === 'buy' ? <TrendingDown size={24}/> : <Sprout size={24}/>}
                              </div>
                              <div>
                                 <p className="text-[10px] font-black uppercase text-zinc-600 tracking-widest">{tx.id} • {new Date(tx.timestamp).toLocaleTimeString()}</p>
                                 <p className="font-bold text-white text-lg">{tx.type.toUpperCase()}: {tx.quantity} {tx.itemId}</p>
                              </div>
                           </div>
                           <div className="text-right">
                              <p className={`text-xl font-black ${tx.type === 'sell' ? 'text-emerald-500' : 'text-rose-500'}`}>
                                 {tx.type === 'sell' ? '+' : '-'} R$ {tx.amount.toLocaleString()}
                              </p>
                              <p className="text-[8px] font-black text-zinc-800 uppercase tracking-tighter break-all max-w-[100px] truncate">{tx.hash}</p>
                           </div>
                        </div>
                     ))}
                  </div>
               </div>
            )}

            {/* BOLSA DE VALORES (MERCADO DINÂMICO) */}
            {activeTab === 'mercado' && (
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-2 gap-8 pb-10 max-w-6xl mx-auto">
                 {marketPrices.map(price => {
                    const stock = gameState.inventory[price.id] || 0;
                    return (
                      <div key={price.id} className="bg-zinc-900/60 border border-white/5 p-10 rounded-[4rem] flex flex-col gap-10 shadow-2xl relative overflow-hidden group">
                         <div className="absolute top-0 right-0 p-8 opacity-5"><BarChart3 size={150}/></div>
                         <div className="flex justify-between items-start relative z-10">
                            <div className="flex items-center gap-8">
                               <div className="w-20 h-20 bg-zinc-950 rounded-[2.5rem] flex items-center justify-center text-5xl shadow-xl">{price.emoji}</div>
                               <div>
                                  <h4 className="text-3xl font-black text-white tracking-tighter uppercase">{price.name}</h4>
                                  <div className={`flex items-center gap-2 mt-2 font-black uppercase text-[10px] ${price.trend === 'up' ? 'text-emerald-500' : 'text-rose-500'}`}>
                                     {price.trend === 'up' ? <TrendingUp size={14}/> : <TrendingDown size={14}/>} {price.trend === 'up' ? 'Alta' : 'Baixa'} No Pregão
                                  </div>
                               </div>
                            </div>
                            <div className="text-right">
                               <p className="text-4xl font-black text-white tracking-tighter leading-none">R$ {price.currentPrice}</p>
                               <p className="text-[9px] font-black text-zinc-600 uppercase tracking-widest mt-1">Cotação Atual</p>
                            </div>
                         </div>

                         <div className="grid grid-cols-2 gap-4 relative z-10">
                            <div className="bg-black/40 p-6 rounded-3xl border border-white/5 text-center">
                               <span className="text-[9px] font-black text-zinc-500 uppercase block mb-1">Seu Estoque</span>
                               <span className="text-2xl font-black text-emerald-500">{stock}</span>
                            </div>
                            <div className="bg-black/40 p-6 rounded-3xl border border-white/5 text-center">
                               <span className="text-[9px] font-black text-zinc-500 uppercase block mb-1">Venda Total</span>
                               <span className="text-2xl font-black text-white">R$ {(stock * price.currentPrice).toLocaleString()}</span>
                            </div>
                         </div>

                         <button 
                          onClick={() => handleSell(price.id)}
                          disabled={stock <= 0}
                          className={`w-full py-8 rounded-[2.5rem] font-black uppercase tracking-[0.3em] text-xs transition-all relative z-10 ${stock > 0 ? 'bg-emerald-500 text-black shadow-2xl hover:bg-emerald-400' : 'bg-zinc-800 text-zinc-600 cursor-not-allowed opacity-30'}`}
                         >
                            Liquidar no Mercado
                         </button>
                      </div>
                    );
                 })}
              </div>
            )}

            {/* LAVOURAS PERSPECTIVA 3D */}
            {activeTab === 'fazenda' && (
              <div className="grid grid-cols-4 gap-6 perspective-[2000px] py-10 max-w-5xl mx-auto">
                {gameState.farm.plots.map((plot) => {
                  const crop = plot.cropId ? CROPS.find(c => c.id === plot.cropId) : null;
                  const isReady = plot.status === 'ready';
                  const isGrowing = plot.status === 'growing';
                  return (
                    <div 
                      key={plot.id} 
                      onClick={() => !crop ? setSelectedPlot(plot.id) : isReady && handleHarvest(plot.id)} 
                      className={`aspect-square rounded-[3rem] border-2 flex items-center justify-center relative cursor-pointer transition-all duration-700 transform hover:-translate-y-4 shadow-xl ${plot.status === 'locked' ? 'opacity-20 bg-black border-zinc-900 cursor-not-allowed' : 'bg-zinc-900/40 border-white/5 hover:border-emerald-500/40'} ${isReady ? 'border-emerald-500 bg-emerald-500/10' : ''}`} 
                      style={{ transform: 'rotateX(45deg) rotateZ(-15deg)' }}
                    >
                      {plot.status === 'locked' ? <Lock className="text-zinc-800"/> : (
                        <div className="relative z-10 flex flex-col items-center gap-3">
                           {crop ? (
                              <>
                                 <span className={`text-6xl drop-shadow-2xl transition-transform duration-700 ${isReady ? 'scale-125' : ''}`}>{crop.emoji}</span>
                                 {plot.isNightPlanted && <Moon size={16} className="absolute -top-4 -right-4 text-blue-400 drop-shadow-xl animate-pulse" />}
                                 {isGrowing && <div className="absolute inset-x-[-10px] bottom-[-20px] h-1.5 bg-black/40 rounded-full overflow-hidden"><div className="h-full bg-emerald-500 animate-pulse" style={{ width: '40%' }} /></div>}
                                 {isReady && <div className="absolute -top-12 bg-emerald-500 text-black px-6 py-2 rounded-full text-[9px] font-black uppercase tracking-widest shadow-2xl animate-bounce">Pronto!</div>}
                              </>
                           ) : <Plus className="text-zinc-800 group-hover:text-emerald-500" size={32} />}
                        </div>
                      )}
                    </div>
                  );
                })}
              </div>
            )}
          </main>
        </>
      )}

      {/* Modal de Sementes Auditadas */}
      {selectedPlot !== null && (
        <div className="fixed inset-0 z-[300] bg-black/98 backdrop-blur-3xl flex items-center justify-center p-8 animate-in fade-in duration-300">
           <div className="w-full max-w-4xl bg-[#0a0a0a] border border-white/10 rounded-[6rem] overflow-hidden shadow-2xl animate-in zoom-in-95 duration-500">
              <div className="p-16 border-b border-white/5 flex justify-between items-center bg-zinc-950/20">
                 <div>
                    <h3 className="text-5xl font-black italic tracking-tighter uppercase leading-none">BIBLIOTECA DE <span className="text-emerald-500">ATIVOS</span></h3>
                    <p className="text-[12px] font-black text-zinc-600 uppercase tracking-[0.5em] mt-3">Investimento rural auditado</p>
                 </div>
                 <button onClick={() => setSelectedPlot(null)} className="p-8 bg-zinc-900 rounded-[3rem] text-zinc-500 hover:text-white transition-all"><X size={48}/></button>
              </div>
              <div className="p-16 grid grid-cols-1 md:grid-cols-2 gap-8 max-h-[60vh] overflow-y-auto scrollbar-hide">
                 {CROPS.map(c => (
                   <button 
                    key={c.id} 
                    disabled={gameState.farm.level < c.minLevel || gameState.credits < c.cost || gameState.farm.energy < ENERGY_COSTS.PLANT} 
                    onClick={() => handlePlant(selectedPlot, c.id)} 
                    className={`p-10 rounded-[4rem] border-4 flex items-center justify-between transition-all ${gameState.farm.level < c.minLevel ? 'opacity-20 bg-black cursor-not-allowed border-zinc-900' : 'bg-zinc-900/60 border-white/5 hover:border-emerald-500/40 hover:scale-[1.02] shadow-2xl'}`}
                   >
                     <div className="flex items-center gap-8 text-left">
                        <span className="text-7xl drop-shadow-2xl">{c.emoji}</span>
                        <div><p className="font-black text-2xl text-white tracking-tighter">{c.name}</p><p className="text-xl font-black text-emerald-500 tracking-tighter">R$ {c.cost.toLocaleString()}</p></div>
                     </div>
                     {gameState.farm.level < c.minLevel && <Lock size={32} className="text-zinc-700"/>}
                   </button>
                 ))}
              </div>
           </div>
        </div>
      )}
    </div>
  );
};

