  const handlePublish = async () => {
    if (!newPostText.trim()) return;
    setIsPublishing(true);
    // Fixed: Removed 'type', 'likes', and 'lovedBy' as they are not properties of Post interface
    const newPost: Post = {
      id: Math.random().toString(36).substr(2, 9),
      authorId: currentUser.id, 
      authorName: currentUser.name, 
      authorAvatar: currentUser.avatar, 
      authorIdentity: currentUser.identityType,
      content: newPostText, 
      timestamp: 'Agora', 
      likedBy: [], 
      comments: []
    };
    UserDatabase.savePost(newPost);
    setNewPostText('');
    setIsPublishing(false);
    refresh();
  };

  return (
    <div className="max-w-xl mx-auto space-y-8 pb-10">
      {/* SEÇÃO DE STORIES CARROSSEL */}
      <section className="bg-zinc-900/60 border border-white/5 rounded-[4rem] p-6 shadow-2xl relative overflow-hidden backdrop-blur-xl">
        <div className="absolute top-0 right-0 p-6 opacity-5 pointer-events-none">
          <Flame size={120} className="text-emerald-500 rotate-12" />
        </div>
        <div className="flex items-center justify-between mb-6 px-4">
          <div>
            <h3 className="text-sm font-black italic tracking-tighter text-white uppercase">FOGO <span className="text-emerald-500">24H</span></h3>
            <p className="text-[8px] font-black text-zinc-600 uppercase tracking-widest">Momentos efêmeros da rede</p>
          </div>
          <Zap size={20} className="text-emerald-500 animate-pulse" fill="currentColor" />
        </div>
        <StoriesBar currentUser={currentUser} onRefresh={refresh} />
      </section>

      {/* TABS DE FEED */}
      <div className="flex bg-zinc-900/80 p-1.5 rounded-[2.5rem] border border-white/10 backdrop-blur-3xl sticky top-20 z-40">
        <button onClick={() => setFeedMode('global')} className={`flex-1 py-4 rounded-[2rem] text-[10px] font-black uppercase tracking-widest flex items-center justify-center gap-2 transition-all ${feedMode === 'global' ? 'bg-zinc-800 text-emerald-400 shadow-xl' : 'text-zinc-600'}`}><Globe size={14}/> Global</button>
        <button onClick={() => setFeedMode('tribo')} className={`flex-1 py-4 rounded-[2rem] text-[10px] font-black uppercase tracking-widest flex items-center justify-center gap-2 transition-all ${feedMode === 'tribo' ? 'bg-emerald-500 text-black shadow-lg shadow-emerald-500/20' : 'text-zinc-600'}`}><UsersIcon size={14}/> Minha Tribo</button>
      </div>

      {feedMode === 'tribo' && <TribeSuggestions currentUser={currentUser} onRefresh={refresh} />}

      {/* CRIAR POST */}
      <div className="bg-zinc-900/50 border border-white/10 rounded-[3.5rem] p-7 shadow-2xl backdrop-blur-xl">
        <div className="flex gap-4">
          <img src={currentUser.avatar} className="w-12 h-12 rounded-2xl object-cover shrink-0" alt="" />
          <div className="flex-grow">
            <textarea value={newPostText} onChange={(e) => setNewPostText(e.target.value)} placeholder="Mande seu recado para a Tribo..." className="w-full bg-transparent outline-none resize-none text-lg font-medium py-1 text-white placeholder:text-zinc-800" rows={2} />
            <div className="flex justify-end pt-4 border-t border-white/5 mt-4">
              <button onClick={handlePublish} disabled={!newPostText.trim() || isPublishing} className="bg-emerald-500 text-black font-black px-10 py-4 rounded-3xl text-[10px] uppercase tracking-widest flex items-center gap-2 shadow-xl shadow-emerald-500/10 active:scale-95 transition-all">
                {isPublishing ? <Loader2 size={16} className="animate-spin" /> : <Send size={16} fill="currentColor" />} Publicar
              </button>
            </div>
          </div>
        </div>
      </div>

      {/* LISTA DE POSTS */}
      <div className="space-y-4">
        {posts.length > 0 ? (
          posts.map(p => <FeedPost key={p.id} post={p} currentUser={currentUser} onRefresh={refresh} />)
        ) : (
          <div className="py-24 text-center bg-zinc-900/10 rounded-[4rem] border-2 border-dashed border-white/5">
            <UsersIcon size={40} className="mx-auto mb-6 text-zinc-800 opacity-20" />
            <p className="text-zinc-700 font-black uppercase text-xs tracking-widest">A Tribo está em silêncio...</p>
          </div>
        )}
      </div>
    </div>
  );
};

