  { id: 'cafe', name: 'Café Especial', emoji: '☕', growthTime: 300, cost: 5000, baseYield: 15000, xp: 4000, minLevel: 10, riskFactor: 0.15 },
  { id: 'soja_premium', name: 'Soja Genética', emoji: '🧬', growthTime: 450, cost: 15000, baseYield: 60000, xp: 12000, minLevel: 20, riskFactor: 0.02, isPremium: true },
];

const MACHINES = [
  { id: 'trator_m1', name: 'Trator SOBERANO T-100', desc: 'Reduz custo de plantio em 2⚡', price: 50000, icon: Tractor, bonus: 'plant_save' },
  { id: 'drone_insp', name: 'Drone de Inspeção A.I.', desc: 'Reduz risco de perda em 50%', price: 120000, icon: Rocket, bonus: 'risk_red' },
  { id: 'irrig_auto', name: 'Pivô de Irrigação 2026', desc: 'Produção 10% mais rápida sempre', price: 250000, icon: Droplets, bonus: 'speed_passive' },
];

const BOOSTS = [
  { id: 'bio_ultra', name: 'Bio-Estimulante', desc: 'Reduz tempo de colheita atual em 50%', price: 2500, gems: 5, icon: Flame },
  { id: 'fertil_gems', name: 'Fertilizante de Gems', desc: 'Dobra o XP da colheita', price: 5000, gems: 10, icon: Zap },
];

const TITLES = [
  { minLevel: 1, title: 'Pequeno Produtor', color: 'text-zinc-500' },
  { minLevel: 10, title: 'Agricultor Regional', color: 'text-emerald-500' },
  { minLevel: 25, title: 'Produtor Nacional', color: 'text-blue-500' },
  { minLevel: 50, title: 'Exportador Master', color: 'text-amber-500' },
  { minLevel: 75, title: 'Barão do Agro', color: 'text-rose-500 font-black' },
  { minLevel: 100, title: 'Rei do Agro Brasileiro', color: 'text-white font-black italic animate-pulse' },
];

const AgroBrazil: React.FC<{ currentUser: User }> = ({ currentUser }) => {
  const [isLobby, setIsLobby] = useState(true);
  const [activeTab, setActiveTab] = useState<'fazenda' | 'mercado' | 'loja' | 'ranking' | 'vip'>('fazenda');
  const [shopSubTab, setShopSubTab] = useState<'maquinas' | 'boosts' | 'estilo'>('maquinas');
  const [gameState, setGameState] = useState<AgroGameState>(() => UserDatabase.getAgroState(currentUser.id));
  const [marketPrices, setMarketPrices] = useState<MarketPrice[]>(() => UserDatabase.getMarketPrices());
  const [selectedPlot, setSelectedPlot] = useState<number | null>(null);

  const isNight = useMemo(() => {
    const h = new Date().getHours();
    return h >= 20 || h < 6;
  }, []);

  const currentTitle = useMemo(() => {
    return [...TITLES].reverse().find(t => gameState.farm.level >= t.minLevel) || TITLES[0];
  }, [gameState.farm.level]);

  // ENGINE: Sincronização e Regeneração
  useEffect(() => {
    const tick = setInterval(() => {
      const now = Date.now();

      setGameState(prev => {
        // 1. Plots & Boosts
        const nextPlots = prev.farm.plots.map(p => {
          if (!p.cropId || p.status !== 'growing') return p;
          const crop = CROPS.find(c => c.id === p.cropId);
          if (!crop) return p;

          let growthTime = crop.growthTime;
          // Máquina: Irrigação Automática
          if (prev.machines.includes('irrig_auto')) growthTime *= 0.9;

          const elapsed = (now - (p.plantedAt || 0)) / 1000;
          if (elapsed >= growthTime) return { ...p, status: 'ready' as PlotStatus };
          return p;
        });

        // 2. Energia
        const nextEnergy = Math.min(prev.farm.maxEnergy, prev.farm.energy + 0.5);

        const newState = { 
          ...prev, 
          farm: { ...prev.farm, plots: nextPlots, energy: nextEnergy } 
        };
        UserDatabase.saveAgroState(currentUser.id, newState);
        return newState;
      });
    }, 2000);
    return () => clearInterval(tick);
  }, [currentUser.id]);

  const handlePlant = (plotId: number, cropId: string) => {
    const crop = CROPS.find(c => c.id === cropId);
    let costEnergy = ENERGY_COSTS.PLANT;
    // Máquina: Trator T-100
    if (gameState.machines.includes('trator_m1')) costEnergy -= 2;

    if (!crop || gameState.credits < crop.cost || gameState.farm.energy < costEnergy) return;

    setGameState(prev => ({
      ...prev,
      credits: prev.credits - crop.cost,
      farm: {
        ...prev.farm,
        energy: prev.farm.energy - costEnergy,
        plots: prev.farm.plots.map(p => p.id === plotId ? {
          ...p, cropId, plantedAt: Date.now(), status: 'growing', isNightPlanted: isNight
        } : p)
      }
    }));

    UserDatabase.logTransaction(currentUser.id, {
      userId: currentUser.id, type: 'buy', amount: crop.cost, currency: 'credits', itemId: crop.id, quantity: 1
    });
    setSelectedPlot(null);
  };

  const handleHarvest = (plotId: number) => {
    const plot = gameState.farm.plots.find(p => p.id === plotId);
    if (!plot || plot.status !== 'ready' || gameState.farm.energy < ENERGY_COSTS.HARVEST) return;
    const crop = CROPS.find(c => c.id === plot.cropId);
    if (!crop) return;

    const yieldAmt = Math.floor(crop.baseYield * plot.quality);

    setGameState(prev => {
      const inv = { ...prev.inventory };
      inv[crop.id] = (inv[crop.id] || 0) + yieldAmt;
      return {
        ...prev,
        inventory: inv,
        farm: {
          ...prev.farm,
          energy: prev.farm.energy - ENERGY_COSTS.HARVEST,
          plots: prev.farm.plots.map(p => p.id === plotId ? { ...p, cropId: null, plantedAt: null, status: 'empty' } : p)
        }
      };
    });

    UserDatabase.logTransaction(currentUser.id, {
      userId: currentUser.id, type: 'harvest', amount: 0, currency: 'credits', itemId: crop.id, quantity: yieldAmt
    });
  };

  const buyMachine = (id: string, price: number) => {
    if (gameState.credits < price || gameState.machines.includes(id)) return;
    setGameState(prev => ({
      ...prev,
      credits: prev.credits - price,
      machines: [...prev.machines, id]
    }));
    UserDatabase.logTransaction(currentUser.id, {
      userId: currentUser.id, type: 'buy', amount: price, currency: 'credits', itemId: id, quantity: 1
    });
  };

  const applyBoost = (plotId: number) => {
    const boostId = 'bio_ultra';
    if (!gameState.boosts[boostId] || gameState.boosts[boostId] <= 0) return;

    setGameState(prev => {
      const nextBoosts = { ...prev.boosts };
      nextBoosts[boostId]--;

      const nextPlots = prev.farm.plots.map(p => {
        if (p.id === plotId && p.status === 'growing') {
          // Mecânica: Reduz o tempo restante pela metade
          const now = Date.now();
          const plantedAt = p.plantedAt || now;
          const currentElapsed = (now - plantedAt) / 1000;
          const newPlantedAt = now - (currentElapsed * 2000); // Hack para simular avanço
          return { ...p, plantedAt: newPlantedAt };
        }
        return p;
      });

      return {
        ...prev,
        boosts: nextBoosts,
        farm: { ...prev.farm, plots: nextPlots }
      };
    });
  };

  return (
