const ENERGY_COSTS = { PLANT: 5, HARVEST: 3, PROCESS: 10, EXPORT: 15 };

const CROPS: AgroCrop[] = [
  { id: 'milho', name: 'Milho Comum', emoji: '🌽', growthTime: 30, cost: 40, baseYield: 120, xp: 20, minLevel: 1, riskFactor: 0.04 },
  { id: 'soja', name: 'Soja Industrial', emoji: '🌱', growthTime: 60, cost: 300, baseYield: 800, xp: 150, minLevel: 2, riskFactor: 0.08 },
  { id: 'cana', name: 'Cana de Açúcar', emoji: '🎋', growthTime: 120, cost: 1200, baseYield: 4000, xp: 900, minLevel: 4, riskFactor: 0.12 },
  { id: 'cafe', name: 'Café Especial', emoji: '☕', growthTime: 300, cost: 5000, baseYield: 15000, xp: 4000, minLevel: 10, riskFactor: 0.15 },
  { id: 'soja_premium', name: 'Soja Genética', emoji: '🧬', growthTime: 450, cost: 15000, baseYield: 60000, xp: 12000, minLevel: 20, riskFactor: 0.02, isPremium: true },
];

const MACHINES = [
  { id: 'trator_m1', name: 'Trator SOBERANO T-100', desc: 'Reduz custo de plantio em 2⚡', price: 50000, icon: Tractor, bonus: 'plant_save' },
  { id: 'drone_insp', name: 'Drone de Inspeção A.I.', desc: 'Reduz risco de perda em 50%', price: 120000, icon: Rocket, bonus: 'risk_red' },
  { id: 'colhe_quant', name: 'Colheitadeira Quântica', desc: 'Colhe 5 plots simultaneamente', price: 500000, icon: Cpu, bonus: 'multi_harvest' },
  { id: 'sat_monit', name: 'Satélite SOBERANO-1', desc: 'Qualidade da colheita +200%', price: 1500000, icon: Globe, bonus: 'quality_god' },
];

const AgroBrazil: React.FC<{ currentUser: User }> = ({ currentUser }) => {
  const [isLobby, setIsLobby] = useState(true);
  const [activeTab, setActiveTab] = useState<'fazenda' | 'mercado' | 'infra' | 'loja' | 'logs'>('fazenda');
  const [gameState, setGameState] = useState<AgroGameState>(() => UserDatabase.getAgroState(currentUser.id));
  const [marketPrices, setMarketPrices] = useState<MarketPrice[]>(() => UserDatabase.getMarketPrices());
  const [selectedPlot, setSelectedPlot] = useState<number | null>(null);

  const isNight = useMemo(() => {
    const h = new Date().getHours();
    return h >= 20 || h < 6;
  }, []);

  // Gameloop: Simulação de Rede e Produção
  useEffect(() => {
    const tick = setInterval(() => {
      const now = Date.now();

      setGameState(prev => {
        // 1. Plots
        const nextPlots = prev.farm.plots.map(p => {
          if (!p.cropId || p.status !== 'growing') return p;
          const crop = CROPS.find(c => c.id === p.cropId);
          if (!crop) return p;
          const elapsed = (now - (p.plantedAt || 0)) / 1000;
          if (elapsed >= crop.growthTime) return { ...p, status: 'ready' as PlotStatus };
          return p;
        });

        // 2. Energia & Cluster Load
        const nextEnergy = Math.min(prev.farm.maxEnergy, prev.farm.energy + 0.5);
        const nextLoad = Math.min(100, Math.max(10, prev.economy.serverLoad + (Math.random() * 2 - 1)));

        const newState = { 
          ...prev, 
          economy: { ...prev.economy, serverLoad: nextLoad },
          farm: { ...prev.farm, plots: nextPlots, energy: nextEnergy } 
        };
        UserDatabase.saveAgroState(currentUser.id, newState);
        return newState;
      });

      // 3. Mercado Anti-inflacionário
      setMarketPrices(prev => {
        return prev.map(p => {
          // Preço cai se volume global é alto, sobe se for baixo
          const volumeFactor = p.globalVolume > 1000000 ? -0.01 : 0.01;
          const change = (Math.random() * p.volatility + volumeFactor) * p.basePrice;
          const nextPrice = Math.max(p.basePrice * 0.4, p.currentPrice + change);
          return { ...p, currentPrice: Math.floor(nextPrice), trend: nextPrice > p.currentPrice ? 'up' : 'down' as any };
        });
      });

    }, 3000);
    return () => clearInterval(tick);
  }, [currentUser.id]);

  const handlePlant = (plotId: number, cropId: string) => {
    const crop = CROPS.find(c => c.id === cropId);
    if (!crop || gameState.credits < crop.cost || gameState.farm.energy < ENERGY_COSTS.PLANT) return;

    setGameState(prev => ({
      ...prev,
      credits: prev.credits - crop.cost,
      farm: {
        ...prev.farm,
        energy: prev.farm.energy - ENERGY_COSTS.PLANT,
        plots: prev.farm.plots.map(p => p.id === plotId ? {
          ...p, cropId, plantedAt: Date.now(), status: 'growing', isNightPlanted: isNight
        } : p)
      }
    }));

    UserDatabase.logTransaction(currentUser.id, {
      userId: currentUser.id, type: 'buy', amount: crop.cost, currency: 'credits', itemId: crop.id, quantity: 1
    });
    setSelectedPlot(null);
  };

  const handleHarvest = (plotId: number) => {
    const plot = gameState.farm.plots.find(p => p.id === plotId);
    if (!plot || plot.status !== 'ready' || gameState.farm.energy < ENERGY_COSTS.HARVEST) return;
    const crop = CROPS.find(c => c.id === plot.cropId);
    if (!crop) return;

    // Bônus Satélite
    const qualityMultiplier = gameState.machines.includes('sat_monit') ? 3.0 : 1.0;
    const yieldAmt = Math.floor(crop.baseYield * plot.quality * qualityMultiplier);

    setGameState(prev => {
      const inv = { ...prev.inventory };
      inv[crop.id] = (inv[crop.id] || 0) + yieldAmt;
      return {
        ...prev,
        inventory: inv,
        farm: {
          ...prev.farm,
          energy: prev.farm.energy - ENERGY_COSTS.HARVEST,
          plots: prev.farm.plots.map(p => p.id === plotId ? { ...p, cropId: null, plantedAt: null, status: 'empty' } : p)
        }
      };
    });

    UserDatabase.logTransaction(currentUser.id, {
      userId: currentUser.id, type: 'harvest', amount: 0, currency: 'credits', itemId: crop.id, quantity: yieldAmt
    });
  };

  const handleSell = (cropId: string) => {
    const stock = gameState.inventory[cropId] || 0;
    const price = marketPrices.find(p => p.id === cropId)?.currentPrice || 0;
    if (stock <= 0 || price <= 0) return;

    // Taxa de Soberania (Anti-inflação)
    const taxRate = gameState.economy.inflationIndex > 1.05 ? 0.15 : 0.05;
    const totalRevenue = Math.floor(stock * price * (1 - taxRate));

    setGameState(prev => {
      const inv = { ...prev.inventory };
      inv[cropId] = 0;
      return { ...prev, credits: prev.credits + totalRevenue, inventory: inv };
    });

    UserDatabase.logTransaction(currentUser.id, {
      userId: currentUser.id, type: 'sell', amount: totalRevenue, currency: 'credits', itemId: cropId, quantity: stock
    });
  };

  return (
    <div className={`h-[calc(100vh-175px)] rounded-[3.5rem] border border-white/5 flex flex-col overflow-hidden shadow-2xl relative transition-all duration-1000 ${isNight ? 'bg-[#01050a]' : 'bg-[#010a05]'}`}>

      {/* Header Estilo Terminal Financeiro */}
      <header className="px-8 py-6 bg-black/80 backdrop-blur-3xl border-b border-white/5 flex items-center justify-between relative z-20">
        <div className="flex items-center gap-6">
          <button onClick={() => isLobby ? null : setIsLobby(true)} className="p-4 bg-zinc-900 text-zinc-500 rounded-2xl hover:text-white transition-all"><ChevronLeft size={24}/></button>
          <div className="flex items-center gap-4">
             <div className={`w-14 h-14 rounded-2xl border flex items-center justify-center ${isNight ? 'bg-blue-500/10 text-blue-400' : 'bg-emerald-500/10 text-emerald-500'}`}>
                <Cpu size={32} />
             </div>
             <div>
                <h2 className="text-xl font-black text-white italic tracking-tighter uppercase leading-none">SOBERANA <span className={isNight ? 'text-blue-500' : 'text-emerald-500'}>CLOUD</span></h2>
                <div className="flex items-center gap-2 mt-1">
                   <span className="w-2 h-2 bg-emerald-500 rounded-full animate-pulse"></span>
                   <p className="text-[8px] font-black uppercase text-zinc-500 tracking-widest">Cluster {gameState.economy.activeCluster} Online</p>
                </div>
             </div>
          </div>
        </div>

        <div className="flex items-center gap-8">
           <div className="hidden lg:flex gap-6 border-r border-white/10 pr-8">
              <div className="text-right">
                 <p className="text-[9px] font-black text-zinc-600 uppercase mb-1">Carga Global</p>
                 <div className="flex items-center gap-2">
                    <div className="w-20 h-1.5 bg-zinc-900 rounded-full overflow-hidden">
                       <div className="h-full bg-blue-500" style={{ width: `${gameState.economy.serverLoad}%` }}></div>
                    </div>
                    <span className="text-[10px] font-black text-white">{Math.floor(gameState.economy.serverLoad)}%</span>
                 </div>
              </div>
              <div className="text-right">
                 <p className="text-[9px] font-black text-zinc-600 uppercase mb-1">Indice Inflação</p>
                 <p className={`text-[10px] font-black ${gameState.economy.inflationIndex > 1.05 ? 'text-rose-500' : 'text-emerald-500'}`}>
                   {(gameState.economy.inflationIndex * 100 - 100).toFixed(2)}%
                 </p>
              </div>
           </div>
           <div className="flex items-center gap-4">
              <div className="text-right">
                 <p className="text-[9px] font-black text-zinc-600 uppercase">Patrimônio</p>
                 <p className="text-2xl font-black text-emerald-500 tracking-tighter">C$ {gameState.credits.toLocaleString()}</p>
              </div>
              <div className="w-12 h-12 bg-zinc-900 rounded-xl flex items-center justify-center text-amber-400 border border-white/5">
                 <Diamond size={24} fill="currentColor" />
              </div>
           </div>
        </div>
      </header>

      {isLobby ? (
        <div className="flex-1 flex flex-col items-center justify-center p-12 text-center space-y-12 relative z-10 overflow-y-auto scrollbar-hide">
           <div className="relative">
              <div className="absolute inset-0 bg-emerald-500 blur-[200px] opacity-10 animate-pulse"></div>
              <div className="w-[500px] h-[500px] bg-zinc-950/40 border border-white/5 rounded-full flex flex-col items-center justify-center p-20 relative z-10 shadow-3xl">
                 <Globe size={200} className="text-emerald-500 opacity-20 animate-spin-slow mb-12" />
                 <h1 className="text-6xl font-black italic text-white tracking-tighter leading-none uppercase">ECONOMIA<br/><span className="text-emerald-500">MUNDIAL</span></h1>
                 <p className="mt-6 text-zinc-500 font-bold text-xs uppercase tracking-[0.4em]">1.4M usuários simultâneos no cluster</p>
              </div>
           </div>

           <button onClick={() => setIsLobby(false)} className="w-full max-w-md bg-white text-black font-black py-10 rounded-[3rem] uppercase tracking-[0.5em] text-sm shadow-2xl active:scale-95 transition-all flex items-center justify-center gap-6 group">
              Sincronizar Terminal <ArrowRight size={24} className="group-hover:translate-x-2 transition-transform" />
           </button>
        </div>
      ) : (
        <>
          <nav className="flex bg-black/40 p-3 border-b border-white/5 overflow-x-auto scrollbar-hide relative z-20 shrink-0">
            {[
              { id: 'fazenda', icon: Sprout, label: 'Centro de Comando' },
              { id: 'mercado', icon: BarChart, label: 'Pregão' },
              { id: 'loja', icon: ShoppingBag, label: 'Inovação' },
              { id: 'infra', icon: Server, label: 'Cluster Status' },
              { id: 'logs', icon: Activity, label: 'Auditoria' }
            ].map(t => (
              <button 
                key={t.id} 
                onClick={() => setActiveTab(t.id as any)} 
                className={`flex-1 min-w-[150px] py-5 rounded-[2.5rem] text-[10px] font-black uppercase tracking-widest flex items-center justify-center gap-3 transition-all ${activeTab === t.id ? 'bg-emerald-500 text-black shadow-xl' : 'text-zinc-600 hover:text-zinc-400'}`}
              >
                <t.icon size={18}/> {t.label}
              </button>
            ))}
          </nav>

          <main className="flex-1 overflow-y-auto p-10 scrollbar-hide relative z-10">

            {/* INFRAESTRUTURA (CLUSTER LOAD) */}
            {activeTab === 'infra' && (
              <div className="max-w-4xl mx-auto space-y-12 pb-20">
                 <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
                    {[
                      { name: 'SA-EAST-1 (S.Paulo)', load: gameState.economy.serverLoad, region: 'Ativo' },
                      { name: 'US-EAST-2 (Virginia)', load: 12, region: 'Standby' },
