                 <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                    {marketPrices.map(price => {
                      const stock = gameState.inventory[price.id] || 0;
                      return (
                        <div key={price.id} className="bg-zinc-900/60 p-10 rounded-[4rem] border border-white/5 shadow-2xl group hover:border-emerald-500/20 transition-all">
