                      const crop = plot.cropId ? CROPS.find(c => c.id === plot.cropId) : null;
                      const isReady = plot.status === 'ready';
                      return (
                        <div 
                          key={plot.id} 
                          onClick={() => !crop ? setSelectedPlot(plot.id) : isReady && handleHarvest(plot.id)} 
                          className={`aspect-square rounded-[3.5rem] border-2 flex items-center justify-center relative cursor-pointer transition-all duration-700 transform hover:-translate-y-6 shadow-2xl ${plot.status === 'locked' ? 'opacity-20 bg-black border-zinc-900 cursor-not-allowed' : 'bg-zinc-900/60 border-white/5 hover:border-emerald-500/40'} ${isReady ? 'border-emerald-500 bg-emerald-500/10' : ''}`} 
                          style={{ transform: 'rotateX(35deg) rotateZ(-10deg)' }}
