                                  </>
                               ) : <Plus className="text-zinc-800 opacity-20" size={32} />}
                            </div>
                          )}
                        </div>
                      );
                    })}
                 </div>
              </div>
            )}

            {/* INOVAÇÃO (LOJA DE MÁQUINAS) */}
            {activeTab === 'loja' && (
              <div className="max-w-6xl mx-auto grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-8 pb-20">
                {MACHINES.map(m => {
                  const owned = gameState.machines.includes(m.id);
                  return (
                    <div key={m.id} className={`bg-zinc-900/60 p-10 rounded-[4rem] border-2 transition-all flex flex-col justify-between ${owned ? 'border-emerald-500/20' : 'border-white/5 hover:border-emerald-500/40'}`}>
