                        </div>
                        <h4 className="text-xl font-black text-white tracking-tighter mb-2">{m.name}</h4>
                        <p className="text-zinc-500 text-xs font-bold leading-relaxed">{m.desc}</p>
                      </div>
                      <div className="mt-8">
                         <p className="text-2xl font-black text-white mb-6">C$ {m.price.toLocaleString()}</p>
                         <button 
                          disabled={owned || gameState.credits < m.price}
                          className={`w-full py-5 rounded-[2rem] font-black uppercase text-[9px] tracking-widest transition-all ${owned ? 'bg-zinc-800 text-emerald-500' : 'bg-emerald-500 text-black hover:scale-105 active:scale-95 shadow-xl'}`}
                         >
                           {owned ? 'Ativo no Cluster' : 'Instalar'}
                         </button>
                      </div>
                    </div>
                  );
                })}
              </div>
            )}

          </main>
        </>
      )}

      {/* MODAL DE SEMENTES */}
      {selectedPlot !== null && (
        <div className="fixed inset-0 z-[300] bg-black/98 backdrop-blur-3xl flex items-center justify-center p-8 animate-in fade-in duration-300">
           <div className="w-full max-w-4xl bg-[#0a0a0a] border border-white/10 rounded-[6rem] overflow-hidden shadow-3xl animate-in zoom-in-95">
              <div className="p-16 border-b border-white/5 flex justify-between items-center bg-zinc-950/20">
                 <div>
                    <h3 className="text-5xl font-black italic tracking-tighter uppercase leading-none">ATIVOS <span className="text-emerald-500">BIOLÓGICOS</span></h3>
                    <p className="text-[12px] font-black text-zinc-600 uppercase tracking-[0.5em] mt-3">Investimento rural auditado v2.5</p>
                 </div>
                 <button onClick={() => setSelectedPlot(null)} className="p-8 bg-zinc-900 rounded-[3rem] text-zinc-500 hover:text-white transition-all"><X size={48}/></button>
              </div>
              <div className="p-16 grid grid-cols-1 md:grid-cols-2 gap-8 max-h-[60vh] overflow-y-auto scrollbar-hide">
                 {CROPS.map(c => (
                   <button 
                    key={c.id} 
                    disabled={gameState.farm.level < c.minLevel || gameState.credits < c.cost} 
                    onClick={() => handlePlant(selectedPlot, c.id)} 
                    className={`p-10 rounded-[4rem] border-4 flex items-center justify-between transition-all ${gameState.farm.level < c.minLevel ? 'opacity-20 bg-black cursor-not-allowed' : 'bg-zinc-900/60 border-white/5 hover:border-emerald-500/40 shadow-2xl'}`}
                   >
                     <div className="flex items-center gap-8 text-left">
                        <span className="text-7xl drop-shadow-3xl">{c.emoji}</span>
                        <div>
                           <p className="font-black text-2xl text-white tracking-tighter">{c.name}</p>
                           <p className="text-xl font-black text-emerald-500 tracking-tighter">C$ {c.cost.toLocaleString()}</p>
                        </div>
                     </div>
                     {gameState.farm.level < c.minLevel && <Lock size={32} className="text-zinc-800"/>}
                   </button>
                 ))}
              </div>
           </div>
        </div>
      )}
    </div>
  );
};

