  { id: 'cana', name: 'Cana de Açúcar', emoji: '🎋', growthTime: 120, cost: 1200, baseYield: 4000, xp: 900, minLevel: 4, riskFactor: 0.12 },
  { id: 'cafe', name: 'Café Especial', emoji: '☕', growthTime: 300, cost: 5000, baseYield: 15000, xp: 4000, minLevel: 10, riskFactor: 0.15 },
  { id: 'soja_premium', name: 'Soja Genética', emoji: '🧬', growthTime: 450, cost: 25000, baseYield: 85000, xp: 15000, minLevel: 25, riskFactor: 0.02, isPremium: true },
];

const MACHINES = [
  { id: 'trator_m1', name: 'Trator SOBERANO T-100', desc: 'Reduz custo de plantio em 2⚡', price: 50000, icon: Tractor, bonus: 'plant_save' },
  { id: 'drone_insp', name: 'Drone de Inspeção A.I.', desc: 'Garante colheita 100% perfeita', price: 150000, icon: Rocket, bonus: 'perfect_yield' },
