];

const BOOSTS = [
  { id: 'bio_stim', name: 'Bio-estimulante', desc: 'Crescimento +50% no plot atual', price: 500, gems: 5, icon: Flame },
  { id: 'xp_fert', name: 'Fertilizante de Gems', desc: 'Dobra o XP da colheita', price: 1200, gems: 15, icon: Zap },
];

const UniversoView: React.FC<{ currentUser: User }> = ({ currentUser }) => {
  const [isLobby, setIsLobby] = useState(true);
  const [activeTab, setActiveTab] = useState<'comando' | 'mercado' | 'infra' | 'inovacao' | 'eventos'>('comando');
  const [gameState, setGameState] = useState<AgroGameState>(() => UserDatabase.getAgroState(currentUser.id));
  const [marketPrices, setMarketPrices] = useState<MarketPrice[]>(() => UserDatabase.getMarketPrices());
  const [selectedPlot, setSelectedPlot] = useState<number | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);

  const isNight = useMemo(() => {
    const h = new Date().getHours();
    return h >= 20 || h < 6;
  }, []);

  // Gameloop: Simulação de Rede e Crescimento em Tempo Real
  useEffect(() => {
    const tick = setInterval(() => {
      const now = Date.now();

      setGameState(prev => {
        // 1. Atualizar Crescimento dos Plots
        const nextPlots = prev.farm.plots.map(p => {
          if (!p.cropId || p.status !== 'growing') return p;
          const crop = CROPS.find(c => c.id === p.cropId);
          if (!crop) return p;

          let growthTime = crop.growthTime;
          if (p.isBoosted) growthTime *= 0.5; // Boost de Bio-estimulante

          const elapsed = (now - (p.plantedAt || 0)) / 1000;
          if (elapsed >= growthTime) return { ...p, status: 'ready' as PlotStatus };
          return p;
        });

        // 2. Simular Carga do Cluster e Regeneração de Energia
        const nextEnergy = Math.min(prev.farm.maxEnergy, prev.farm.energy + 0.8);
        const nextLoad = Math.min(100, Math.max(5, prev.economy.serverLoad + (Math.random() * 4 - 2)));

        const newState = { 
          ...prev, 
          economy: { ...prev.economy, serverLoad: nextLoad },
          farm: { ...prev.farm, plots: nextPlots, energy: nextEnergy } 
        };
        UserDatabase.saveAgroState(currentUser.id, newState);
        return newState;
      });

      // 3. Atualizar Pregão (Algoritmo Anti-Inflação)
      setMarketPrices(prev => prev.map(p => {
        const volumeFactor = p.globalVolume > 1500000 ? -0.015 : 0.012;
        const change = (Math.random() * p.volatility + volumeFactor) * p.basePrice;
        const nextPrice = Math.max(p.basePrice * 0.3, p.currentPrice + change);
        return { ...p, currentPrice: Math.floor(nextPrice), trend: nextPrice > p.currentPrice ? 'up' : 'down' as any };
      }));

    }, 2500);
    return () => clearInterval(tick);
  }, [currentUser.id]);

  const handlePlant = (plotId: number, cropId: string) => {
    const crop = CROPS.find(c => c.id === cropId);
    if (!crop || gameState.credits < crop.cost || gameState.farm.energy < ENERGY_COSTS.PLANT) return;

    setGameState(prev => ({
      ...prev,
      credits: prev.credits - crop.cost,
      farm: {
        ...prev.farm,
        energy: prev.farm.energy - ENERGY_COSTS.PLANT,
        plots: prev.farm.plots.map(p => p.id === plotId ? {
          ...p, cropId, plantedAt: Date.now(), status: 'growing', isNightPlanted: isNight, isBoosted: false
        } : p)
      }
    }));

    UserDatabase.logTransaction(currentUser.id, {
      userId: currentUser.id, type: 'buy', amount: crop.cost, currency: 'credits', itemId: crop.id, quantity: 1
    });
    setSelectedPlot(null);
  };

  const applyBoost = (plotId: number) => {
    if (gameState.boosts['bio_stim'] <= 0) return;
    setGameState(prev => ({
      ...prev,
      boosts: { ...prev.boosts, 'bio_stim': prev.boosts['bio_stim'] - 1 },
      farm: {
        ...prev.farm,
        plots: prev.farm.plots.map(p => p.id === plotId ? { ...p, isBoosted: true } : p)
      }
    }));
  };

  const handleHarvest = (plotId: number) => {
    const plot = gameState.farm.plots.find(p => p.id === plotId);
    if (!plot || plot.status !== 'ready' || gameState.farm.energy < ENERGY_COSTS.HARVEST) return;
    const crop = CROPS.find(c => c.id === plot.cropId);
    if (!crop) return;

    const machineBonus = gameState.machines.includes('sat_monit') ? 4.0 : 1.0;
    const yieldAmt = Math.floor(crop.baseYield * plot.quality * machineBonus);

    setGameState(prev => {
      const inv = { ...prev.inventory };
      inv[crop.id] = (inv[crop.id] || 0) + yieldAmt;
      return {
        ...prev,
        inventory: inv,
        farm: {
          ...prev.farm,
          energy: prev.farm.energy - ENERGY_COSTS.HARVEST,
          plots: prev.farm.plots.map(p => p.id === plotId ? { ...p, cropId: null, plantedAt: null, status: 'empty' } : p)
        }
      };
    });

    UserDatabase.logTransaction(currentUser.id, {
      userId: currentUser.id, type: 'harvest', amount: 0, currency: 'credits', itemId: crop.id, quantity: yieldAmt
    });
  };

  return (
    <div className={`h-[calc(100vh-175px)] rounded-[3.5rem] border border-white/5 flex flex-col overflow-hidden shadow-2xl relative transition-all duration-1000 ${isNight ? 'bg-[#01080d]' : 'bg-[#010d05]'}`}>

      {/* HUD: Centro de Comando Quântico */}
      <header className="px-10 py-8 bg-black/80 backdrop-blur-3xl border-b border-white/5 flex items-center justify-between relative z-20">
        <div className="flex items-center gap-8">
          <button onClick={() => isLobby ? null : setIsLobby(true)} className="p-4 bg-zinc-900 text-zinc-500 rounded-2xl hover:text-white transition-all"><ChevronLeft size={24}/></button>
          <div className="flex items-center gap-6">
             <div className={`w-16 h-16 rounded-3xl border flex items-center justify-center ${isNight ? 'bg-blue-500/10 text-blue-400 border-blue-500/20 shadow-[0_0_30px_rgba(59,130,246,0.2)]' : 'bg-emerald-500/10 text-emerald-500 border-emerald-500/20 shadow-[0_0_30px_rgba(16,185,129,0.2)]'}`}>
                <CloudLightning size={36} className="animate-pulse" />
             </div>
             <div>
                <h2 className="text-2xl font-black text-white italic tracking-tighter uppercase leading-none">AGRO <span className={isNight ? 'text-blue-500' : 'text-emerald-500'}>SOBERANA</span></h2>
                <div className="flex items-center gap-3 mt-2">
                   <div className="flex items-center gap-2 bg-emerald-500/10 px-3 py-1 rounded-full border border-emerald-500/20">
                      <div className="w-2 h-2 bg-emerald-500 rounded-full animate-ping"></div>
                      <span className="text-[8px] font-black uppercase text-emerald-500 tracking-widest">{gameState.economy.activeCluster}</span>
                   </div>
                   <p className="text-[8px] font-black uppercase text-zinc-600 tracking-widest">v3.0 Secure Node</p>
                </div>
             </div>
          </div>
        </div>

        <div className="flex items-center gap-10">
           <div className="hidden xl:flex gap-10 border-r border-white/10 pr-10">
              <div className="text-right">
                 <p className="text-[9px] font-black text-zinc-600 uppercase mb-1.5 flex items-center gap-2 justify-end"><Server size={10}/> Carga Cluster</p>
                 <div className="flex items-center gap-3">
                    <div className="w-32 h-2 bg-zinc-950 rounded-full overflow-hidden border border-white/5">
                       <div className="h-full bg-blue-500 transition-all duration-1000" style={{ width: `${gameState.economy.serverLoad}%` }}></div>
                    </div>
                    <span className="text-[10px] font-black text-white">{Math.floor(gameState.economy.serverLoad)}%</span>
                 </div>
              </div>
              <div className="text-right">
                 <p className="text-[9px] font-black text-zinc-600 uppercase mb-1.5 flex items-center gap-2 justify-end"><Activity size={10}/> Inflação Global</p>
