                   +{(gameState.economy.inflationIndex * 100 - 100).toFixed(2)}%
                 </p>
              </div>
           </div>
           <div className="flex items-center gap-6">
              <div className="text-right">
                 <p className="text-[9px] font-black text-zinc-600 uppercase">Patrimônio Líquido</p>
                 <p className="text-3xl font-black text-emerald-500 tracking-tighter">C$ {gameState.credits.toLocaleString()}</p>
              </div>
              <div className="w-14 h-14 bg-amber-400 text-black rounded-2xl flex items-center justify-center shadow-xl shadow-amber-400/20 border-4 border-black group cursor-pointer hover:scale-110 transition-transform">
                 <Diamond size={28} fill="currentColor" />
                 <div className="absolute -top-3 -right-3 bg-white text-black text-[9px] font-black px-2 py-0.5 rounded-full">{gameState.gems}</div>
              </div>
        </div>
      </header>

      {isLobby ? (
        <div className="flex-1 flex flex-col items-center justify-center p-12 text-center space-y-16 relative z-10 overflow-y-auto scrollbar-hide">
           <div className="relative group">
              <div className="absolute inset-0 bg-emerald-500 blur-[250px] opacity-10 group-hover:opacity-20 transition-opacity"></div>
              <div className="w-[600px] h-[600px] bg-zinc-950/40 border border-white/5 rounded-full flex flex-col items-center justify-center p-20 relative z-10 shadow-3xl overflow-hidden backdrop-blur-3xl">
                 <Globe size={300} className="text-emerald-500 opacity-10 animate-spin-slow mb-12 absolute" />
                 <Cpu size={120} className="text-emerald-500 mb-10 relative z-10" />
                 <h1 className="text-7xl font-black italic text-white tracking-tighter leading-none uppercase relative z-10">FORJA<br/><span className="text-emerald-500">DIGITAL</span></h1>
                 <p className="mt-8 text-zinc-500 font-bold text-sm uppercase tracking-[0.5em] relative z-10">Acesso Soberano ao Mercado de 2026</p>
              </div>
           </div>

           <button onClick={() => setIsLobby(false)} className="w-full max-w-lg bg-white text-black font-black py-12 rounded-[4rem] uppercase tracking-[0.6em] text-sm shadow-2xl active:scale-95 transition-all flex items-center justify-center gap-8 group">
              Entrar na Rede <MousePointer2 size={32} className="group-hover:translate-x-4 transition-transform" />
           </button>
        </div>
      ) : (
        <>
          <nav className="flex bg-black/40 p-4 border-b border-white/5 overflow-x-auto scrollbar-hide relative z-20 shrink-0">
            {[
              { id: 'comando', icon: Terminal, label: 'Command Center' },
              { id: 'mercado', icon: BarChart3, label: 'Exchange' },
              { id: 'inovacao', icon: ShoppingBag, label: 'Inovação' },
              { id: 'eventos', icon: BadgeCheck, label: 'VIP Contracts' },
              { id: 'infra', icon: Database, label: 'Infra Monitoring' }
            ].map(t => (
              <button 
                key={t.id} 
                onClick={() => setActiveTab(t.id as any)} 
                className={`flex-1 min-w-[180px] py-6 rounded-[3rem] text-[10px] font-black uppercase tracking-widest flex items-center justify-center gap-4 transition-all ${activeTab === t.id ? 'bg-emerald-500 text-black shadow-2xl scale-105' : 'text-zinc-600 hover:text-zinc-400'}`}
              >
                <t.icon size={20}/> {t.label}
