              <div className="max-w-6xl mx-auto space-y-12 pb-24">
                 <div className="grid grid-cols-4 gap-8 perspective-[4000px]">
                    {gameState.farm.plots.map((plot) => {
                      const crop = plot.cropId ? CROPS.find(c => c.id === plot.cropId) : null;
