                                  <>
                                     <span className={`text-8xl drop-shadow-3xl transition-transform duration-1000 ${isReady ? 'scale-125' : 'scale-100'}`}>{crop.emoji}</span>
                                     {plot.status === 'growing' && (
                                       <div className="absolute inset-x-[-20px] bottom-[-40px] h-2.5 bg-black/80 rounded-full overflow-hidden border border-white/10 p-0.5">
                                          <div className={`h-full rounded-full transition-all duration-1000 ${plot.isBoosted ? 'bg-amber-400' : 'bg-emerald-500'} animate-pulse`} style={{ width: '40%' }} />
                                       </div>
                                     )}
                                     {plot.status === 'growing' && (
                                       <button 
                                         onClick={(e) => { e.stopPropagation(); applyBoost(plot.id); }}
                                         className="absolute -top-6 -right-6 p-4 bg-amber-400 text-black rounded-2xl shadow-2xl hover:scale-110 active:scale-95 transition-all group"
                                       >
                                         <Flame size={20} fill="currentColor" className="group-hover:animate-bounce" />
                                       </button>
                                     )}
                                     {isReady && <div className="absolute -top-20 bg-emerald-500 text-black px-8 py-3 rounded-3xl text-xs font-black uppercase tracking-widest shadow-3xl animate-bounce border-4 border-black">Colher Ativo</div>}
                                  </>
                               ) : <Plus className="text-zinc-800 opacity-10 group-hover:opacity-40" size={48} />}
