                             <button 
                              disabled={owned || gameState.credits < m.price}
                              className={`w-full py-6 rounded-[2.5rem] font-black uppercase text-xs tracking-widest transition-all ${owned ? 'bg-zinc-900 text-emerald-500' : 'bg-emerald-500 text-black hover:bg-emerald-400 shadow-xl'}`}
                             >
                               {owned ? 'Ativo na Rede' : 'Instalar Unidade'}
                             </button>
                          </div>
                        </div>
                      );
                    })}
                 </div>

                 <div className="bg-zinc-950/40 p-16 rounded-[5rem] border border-white/5">
                    <h3 className="text-3xl font-black italic text-white uppercase tracking-tighter mb-12 flex items-center gap-6"><Zap className="text-amber-400" fill="currentColor"/> ACELERADORES DE CICLO</h3>
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
                       {BOOSTS.map(b => (
                         <div key={b.id} className="bg-black/40 p-10 rounded-[4rem] border border-white/5 flex items-center justify-between group hover:border-amber-400/30 transition-all">
                            <div className="flex items-center gap-8">
                               <div className="w-20 h-20 bg-amber-400/10 rounded-3xl flex items-center justify-center text-amber-400 group-hover:scale-110 transition-transform">
                                  <b.icon size={40} fill="currentColor" />
                               </div>
                               <div>
                                  <h4 className="text-2xl font-black text-white tracking-tighter">{b.name}</h4>
                                  <p className="text-[10px] font-black text-zinc-600 uppercase tracking-widest mt-1">{b.desc}</p>
                               </div>
                            </div>
                            <div className="flex flex-col items-end gap-3">
                               <button className="bg-zinc-900 px-8 py-4 rounded-[2rem] border border-white/5 text-sm font-black text-emerald-500 hover:text-white transition-colors">C$ {b.price}</button>
                               <button className="bg-amber-400 px-8 py-3 rounded-full text-black font-black text-[9px] uppercase tracking-widest flex items-center gap-2 active:scale-95">
                                  <Diamond size={12} fill="currentColor"/> {b.gems} Gems
                               </button>
                            </div>
                         </div>
                       ))}
                    </div>
                 </div>
              </div>
            )}

            {/* EXCHANGE (BOLSA DE VALORES) */}
            {activeTab === 'mercado' && (
              <div className="max-w-7xl mx-auto grid grid-cols-1 md:grid-cols-2 gap-10 pb-24">
                 {marketPrices.map(price => {
                    const stock = gameState.inventory[price.id] || 0;
                    return (
                      <div key={price.id} className="bg-zinc-950/60 p-12 rounded-[5.5rem] border-4 border-white/5 shadow-3xl group hover:border-emerald-500/20 transition-all">
                         <div className="flex justify-between items-start mb-12">
                            <div className="flex items-center gap-8">
                               <div className="w-24 h-24 bg-zinc-900 rounded-[3.5rem] flex items-center justify-center text-7xl shadow-2xl group-hover:rotate-12 transition-transform">{price.emoji}</div>
                               <div>
                                  <h4 className="text-3xl font-black text-white tracking-tighter uppercase">{price.name}</h4>
                                  <div className={`flex items-center gap-3 mt-2 font-black uppercase text-[11px] ${price.trend === 'up' ? 'text-emerald-500' : 'text-rose-500'}`}>
                                     {price.trend === 'up' ? <TrendingUp size={16}/> : <TrendingDown size={16}/>} {price.trend === 'up' ? 'Valorização' : 'Bear Market'}
                                  </div>
                               </div>
                            </div>
                            <div className="text-right">
                               <p className="text-5xl font-black text-white tracking-tighter leading-none">C$ {price.currentPrice}</p>
                               <p className="text-[10px] font-black text-zinc-600 uppercase tracking-widest mt-3">Preço por Unidade</p>
                            </div>
                         </div>

                         <div className="grid grid-cols-2 gap-8 mb-12">
                            <div className="bg-black/40 p-8 rounded-[3rem] border border-white/5">
                               <p className="text-[10px] font-black text-zinc-700 uppercase mb-2">Volume Global</p>
                               <p className="text-2xl font-black text-zinc-400">{(price.globalVolume / 1000).toFixed(1)}K Units</p>
                            </div>
                            <div className="bg-black/40 p-8 rounded-[3rem] border border-white/5 text-right">
                               <p className="text-[10px] font-black text-zinc-700 uppercase mb-2">Seu Estoque</p>
                               <p className="text-2xl font-black text-emerald-500">{stock.toLocaleString()}</p>
                            </div>
                         </div>

                         <button 
                          disabled={stock <= 0}
                          className={`w-full py-8 rounded-[3.5rem] font-black uppercase tracking-[0.3em] text-xs transition-all ${stock > 0 ? 'bg-emerald-500 text-black hover:bg-emerald-400 shadow-2xl shadow-emerald-500/10' : 'bg-zinc-900 text-zinc-700 opacity-20'}`}
                         >
                            Liquidar Ativos (Mercado)
                         </button>
                      </div>
                    );
                 })}
              </div>
            )}

          </main>
        </>
      )}

      {/* MODAL: BIBLIOTECA GENÉTICA */}
      {selectedPlot !== null && (
        <div className="fixed inset-0 z-[300] bg-black/98 backdrop-blur-3xl flex items-center justify-center p-8 animate-in fade-in duration-500">
           <div className="w-full max-w-5xl bg-[#050505] border border-white/10 rounded-[6rem] overflow-hidden shadow-3xl animate-in zoom-in-95">
              <div className="p-20 border-b border-white/5 flex justify-between items-center bg-zinc-950/20">
                 <div>
                    <h3 className="text-6xl font-black italic tracking-tighter uppercase leading-none">BIBLIOTECA <span className="text-emerald-500">GENÉTICA</span></h3>
                    <p className="text-[14px] font-black text-zinc-600 uppercase tracking-[0.6em] mt-4">Ativos Biológicos v3.0 Certificados</p>
                 </div>
                 <button onClick={() => setSelectedPlot(null)} className="p-10 bg-zinc-900 rounded-[3rem] text-zinc-500 hover:text-white transition-all hover:rotate-90"><X size={56}/></button>
              </div>
              <div className="p-20 grid grid-cols-1 md:grid-cols-2 gap-10 max-h-[65vh] overflow-y-auto scrollbar-hide">
                 {CROPS.map(c => (
                   <button 
                    key={c.id} 
                    disabled={gameState.farm.level < c.minLevel || gameState.credits < c.cost} 
                    onClick={() => handlePlant(selectedPlot, c.id)} 
                    className={`p-12 rounded-[5rem] border-4 flex items-center justify-between transition-all group ${gameState.farm.level < c.minLevel ? 'opacity-20 bg-black border-zinc-900 cursor-not-allowed' : 'bg-zinc-900/60 border-white/5 hover:border-emerald-500/40 hover:-translate-y-2'}`}
                   >
                     <div className="flex items-center gap-10 text-left">
                        <span className="text-8xl drop-shadow-3xl group-hover:scale-110 transition-transform duration-700">{c.emoji}</span>
                        <div>
                           <div className="flex items-center gap-3">
                              <p className="font-black text-3xl text-white tracking-tighter uppercase">{c.name}</p>
                              {c.isPremium && <Diamond size={16} className="text-amber-400" fill="currentColor"/>}
                           </div>
                           <p className="text-2xl font-black text-emerald-500 tracking-tighter mt-1">C$ {c.cost.toLocaleString()}</p>
                        </div>
                     </div>
                     {gameState.farm.level < c.minLevel ? <Lock size={40} className="text-zinc-800"/> : <ArrowRight size={40} className="text-zinc-800 group-hover:text-emerald-500" />}
                   </button>
                 ))}
              </div>
           </div>
        </div>
      )}
    </div>
  );
};

// Simple Terminal mock for icon
const Terminal = (props: any) => (
  <svg {...props} width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
    <polyline points="4 17 10 11 4 5"></polyline>
    <line x1="12" y1="19" x2="20" y2="19"></line>
  </svg>
);

export default UniversoView;
